c-1 5-5 9-11 9h-2L532 67 19 159h-2c-5 0-9-4-11-9l-5-22c-1-6 2-12 8-13z&#34;/&gt;&lt;/svg&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.93em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mclose nulldelimiter&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;v&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

 &lt;h1&gt;第一步：安装Opencv&lt;/h1&gt;
&lt;p&gt;&lt;strong&gt;安装Opencv参考链接：&lt;/strong&gt;&lt;a href=&#34;https://blog.csdn.net/weixin_53877178/article/details/127938403&#34;&gt;安装OpenCV&lt;/a&gt;&lt;/p&gt;
&lt;h1&gt;获取yolov5s.pt权值文件&lt;/h1&gt;
&lt;p&gt;使用的是轻量的&lt;code&gt;yolov5s&lt;/code&gt;模型,在本地训练后，通过命令发送发到树莓派上:&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;首先查看树莓派地址：&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;    ifconfig  # 查看地址
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;/images/13.webp&#34; alt=&#34;&#34;&gt;&lt;br&gt;
连接的wify，可以看到所属的地址端口。&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;将本地导出的&lt;code&gt;best.onnx&lt;/code&gt;权值文件发送到树莓派上：&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;    scp best.onnx &amp;lt;用户名&amp;gt;@&amp;lt;树莓派地址&amp;gt;:&amp;lt;保存文件地址&amp;gt;  
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;推理代码&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;iostream&amp;gt;
#include &amp;lt;opencv2/opencv.hpp&amp;gt;
#include &amp;lt;opencv2/dnn.hpp&amp;gt;
#include &amp;lt;chrono&amp;gt;  // 添加时间测量头文件

using namespace cv;
using namespace cv::dnn;

std::vector&amp;lt;std::string&amp;gt; classes = &amp;#123;
	&amp;quot;defective_insulator&amp;quot;,&amp;quot;broken_defect&amp;quot;,&amp;quot;good_insulator&amp;quot;,&amp;quot;flashover_defect&amp;quot;
&amp;#125;;

int main() &amp;#123;
	// 1. 输入图片路径
    std::string img_path = &amp;quot;images/insulator.jpg&amp;quot;; // 输入图片路径
    Mat frame = imread(img_path);
    if(frame.empty()) &amp;#123;
        std::cerr &amp;lt;&amp;lt; &amp;quot;Error: Could not read the image.&amp;quot; &amp;lt;&amp;lt; std::endl;
        return -1;
    &amp;#125;
	// 2. 加载模型
    Net net =  cv::dnn::readNetFromONNX(&amp;quot;weights/ZJ/best.onnx&amp;quot;);
	net.setPreferableBackend(cv::dnn::DNN_BACKEND_OPENCV);
	net.setPreferableTarget(cv::dnn::DNN_TARGET_OPENCL);
	// 打印模型信息
    // std::cout &amp;lt;&amp;lt; &amp;quot;Network layers:&amp;quot; &amp;lt;&amp;lt; std::endl;
    // for (int i = 0; i &amp;lt; net.getLayerNames().size(); i++) &amp;#123;
    //     std::cout &amp;lt;&amp;lt; net.getLayerNames()[i] &amp;lt;&amp;lt; std::endl;
    // &amp;#125;

    if (net.empty()) &amp;#123;
        std::cerr &amp;lt;&amp;lt; &amp;quot;Error: Could not load the neural network.&amp;quot; &amp;lt;&amp;lt; std::endl;
        return -1;
    &amp;#125;


	// 3. 预处理参数设置
    const int input_width = 512;
    const int input_height = 512;
    float x_factor = frame.cols / (float)input_width;  // 修改为动态计算
    float y_factor = frame.rows / (float)input_height;


	// 预处理计时
	auto preprocess_start = std::chrono::high_resolution_clock::now();

	// 4. 图像预处理（增加letterbox处理）
    Mat resized;
    int new_width, new_height;
    if (frame.cols &amp;gt; frame.rows) &amp;#123;
        new_width = input_width;
        new_height = (int)(frame.rows * input_width / (float)frame.cols);
    &amp;#125; else &amp;#123;
        new_height = input_height;
        new_width = (int)(frame.cols * input_height / (float)frame.rows);
    &amp;#125;
    resize(frame, resized, Size(new_width, new_height));

    Mat blob = blobFromImage(resized, 1/255.0, Size(input_width, input_height), Scalar(0,0,0), true, false);
	// blob.convertTo(blob, CV_16F);  // 半精度计算
	// 预处理计时结束
	auto preprocess_end = std::chrono::high_resolution_clock::now();

	// 推理计时
	auto inference_start = std::chrono::high_resolution_clock::now();

    net.setInput(blob);

	// 5. 推理后处理
	cv::Mat preds =net.forward();

	// 推理计时结束
	auto inference_end = std::chrono::high_resolution_clock::now();

	// 后处理计时
    auto postprocess_start = std::chrono::high_resolution_clock::now();


	std::vector&amp;lt;int&amp;gt; class_ids;
	std::vector&amp;lt;float&amp;gt; confidences;
	std::vector&amp;lt;Rect&amp;gt; boxes;
	std::cout &amp;lt;&amp;lt; &amp;quot;rows: &amp;quot;&amp;lt;&amp;lt; preds.size[1]&amp;lt;&amp;lt; &amp;quot; data: &amp;quot; &amp;lt;&amp;lt; preds.size[2] &amp;lt;&amp;lt; std::endl;
	// cv::Mat det_output(preds.size[1], preds.size[2], CV_32F, preds.ptr&amp;lt;float&amp;gt;());
	cv::Mat det_output = preds.reshape(1, preds.size[1]); // 避免内存复制
	//In a typical YOLO output, the format is [x_center, y_center, width, height, object_confidence, class_score1, class_score2, ..., class_scoreN] for each bounding box. 
	for (int i = 0; i &amp;lt; det_output.rows; i++) &amp;#123;
		float confidence = det_output.at&amp;lt;float&amp;gt;(i, 4);
		cv::Mat class_scores = det_output.row(i).colRange(5, 5 + classes.size());


		Point class_id_point;
		double max_class_score;
		minMaxLoc(class_scores, NULL, &amp;amp;max_class_score, NULL, &amp;amp;class_id_point);
		int class_id = class_id_point.x; 

		float final_confidence = confidence * max_class_score;

		// std::cout &amp;lt;&amp;lt; &amp;quot;Final confidence: &amp;quot; &amp;lt;&amp;lt; final_confidence &amp;lt;&amp;lt; std::endl;

		if (final_confidence &amp;lt; 0.45) &amp;#123;
			continue;
		&amp;#125;

		float cx = det_output.at&amp;lt;float&amp;gt;(i, 0);
		float cy = det_output.at&amp;lt;float&amp;gt;(i, 1);
		float ow = det_output.at&amp;lt;float&amp;gt;(i, 2);
		float oh = det_output.at&amp;lt;float&amp;gt;(i, 3);
		int x = static_cast&amp;lt;int&amp;gt;((cx - 0.5 * ow) * x_factor);
		int y = static_cast&amp;lt;int&amp;gt;((cy - 0.5 * oh) * y_factor);
		int width = static_cast&amp;lt;int&amp;gt;(ow * x_factor);
		int height = static_cast&amp;lt;int&amp;gt;(oh * y_factor);

        boxes.push_back(Rect(x, y, width, height));
        confidences.push_back(final_confidence);
        class_ids.push_back(class_id);
	&amp;#125;


	std::vector&amp;lt;int&amp;gt; indices;
	dnn::NMSBoxes(boxes, confidences, 0.6, 0.3, indices); 

	// Draw the final bounding boxes
	for (size_t i = 0; i &amp;lt; indices.size(); ++i) &amp;#123;
		int idx = indices[i];
		Rect box = boxes[idx];
		cv::rectangle(frame, cv::Point(box.x, box.y), cv::Point(box.x + box.width, box.y + box.height), cv::Scalar(0, 0, 255), 2, 8);


	std::string label = classes[class_ids[idx]] + &amp;quot;: &amp;quot; + std::to_string(confidences[idx]);
	putText(frame, label.c_str(), Point(box.x, box.y - 10), FONT_HERSHEY_SIMPLEX, 0.9, Scalar(0, 255, 0), 2);
		&amp;#125;

	auto postprocess_end = std::chrono::high_resolution_clock::now();

	// 输出各阶段耗时（单位：ms）
	float preprocess_time = std::chrono::duration_cast&amp;lt;std::chrono::milliseconds&amp;gt;(preprocess_end - preprocess_start).count();
	float inference_time = std::chrono::duration_cast&amp;lt;std::chrono::milliseconds&amp;gt;(inference_end - inference_start).count();
	float postprocess_time = std::chrono::duration_cast&amp;lt;std::chrono::milliseconds&amp;gt;(postprocess_end - postprocess_start).count();

	// 计算总耗时（单位：ms）
	auto duration = std::chrono::duration_cast&amp;lt;std::chrono::milliseconds&amp;gt;(postprocess_end - preprocess_start).count();
	std::cout &amp;lt;&amp;lt; &amp;quot;预处理: &amp;quot; &amp;lt;&amp;lt; preprocess_time &amp;lt;&amp;lt; &amp;quot; ms&amp;quot; &amp;lt;&amp;lt; std::endl;
	std::cout &amp;lt;&amp;lt; &amp;quot;推理: &amp;quot; &amp;lt;&amp;lt; inference_time &amp;lt;&amp;lt; &amp;quot; ms&amp;quot; &amp;lt;&amp;lt; std::endl; 
	std::cout &amp;lt;&amp;lt; &amp;quot;后处理: &amp;quot; &amp;lt;&amp;lt; postprocess_time &amp;lt;&amp;lt; &amp;quot; ms&amp;quot; &amp;lt;&amp;lt; std::endl;
	std::cout &amp;lt;&amp;lt; &amp;quot;总耗时: &amp;quot; &amp;lt;&amp;lt; duration &amp;lt;&amp;lt; &amp;quot; ms&amp;quot; &amp;lt;&amp;lt; std::endl;

	float fps = 1000.0 / duration;  // 计算FPS
	std::cout &amp;lt;&amp;lt; &amp;quot;FPS: &amp;quot; &amp;lt;&amp;lt; fps &amp;lt;&amp;lt; std::endl;
	// 6. 显示结果（取消视频循环）
	imshow(&amp;quot;Object Detection&amp;quot;, frame);
	waitKey(0);  // 改为等待按键

    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;

 &lt;blockquote&gt;
&lt;p&gt;本文主要介绍如何使用LSTM预测电池的SOH(SOC)。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;项目地址：&lt;a href=&#34;https://github.com/zhang3399/Battery-SOH-prediction&#34;&gt;https://github.com/zhang3399/Battery-SOH-prediction&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;1-数据集介绍&#34;&gt;1. 数据集介绍&lt;/h2&gt;
&lt;p&gt;数据集来源于&lt;a href=&#34;https://ti.arc.nasa.gov/tech/dash/groups/pcoe/prognostic-data-repository/#battery&#34;&gt;https://ti.arc.nasa.gov/tech/dash/groups/pcoe/prognostic-data-repository/#battery&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;数据说明：&lt;/strong&gt;&lt;br&gt;
一组四个锂离子电池（#5、6、7和18）在室温下经历了3种不同的操作模式（充电、放电和阻抗）。以1.5A的恒流（CC）模式充电，直到电池电压达到4.2V，然后以恒压（CV）模式继续充电，直到充电电流降至20mA。以2A的恒定电流（CC）水平进行放电，直到电池5、6、7和18的电池电压分别降至2.7V、2.5V、2.2V和2.5V。通过电化学阻抗谱（EIS）从0.1Hz到5kHz的频率扫描进行阻抗测量。重复的充电和放电循环导致电池加速老化，而阻抗测量则提供了对随着老化过程而变化的内部电池参数的洞察。当电池达到寿命终止（EOL）标准时，实验停止，即额定容量下降30%（从2Ahr降至1.4Ahr）。该数据集可用于预测剩余电荷（对于给定的放电循环）和剩余使用寿命（RUL）。&lt;br&gt;
&lt;strong&gt;文件清单：&lt;/strong&gt;&lt;br&gt;
(项目目录下path.xlsx统计的充放电循环周期)&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;文件名&lt;/th&gt;
&lt;th&gt;电池编号&lt;/th&gt;
&lt;th&gt;循环次数&lt;/th&gt;
&lt;th&gt;数据规模&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;B0005.mat&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;5&lt;/td&gt;
&lt;td&gt;167&lt;/td&gt;
&lt;td&gt;15.2MB&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;B0006.mat&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;6&lt;/td&gt;
&lt;td&gt;167&lt;/td&gt;
&lt;td&gt;15.2MB&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;B0007.mat&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;7&lt;/td&gt;
&lt;td&gt;167&lt;/td&gt;
&lt;td&gt;15.3MB&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;B0018.mat&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;18&lt;/td&gt;
&lt;td&gt;132&lt;/td&gt;
&lt;td&gt;8.1MB&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;strong&gt;数据结构：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;cycle：包含充电、放电和阻抗操作的顶层结构阵列&lt;/li&gt;
&lt;li&gt;type：充电、放电或阻抗(charge, discharge or impedance)&lt;/li&gt;
&lt;li&gt;ambient_temperature：环境温度（摄氏度）&lt;/li&gt;
&lt;li&gt;time：周期开始的日期和时间，采用MATLAB日期向量格式&lt;/li&gt;
&lt;li&gt;data：包含测量值的数据结构
&lt;ul&gt;
&lt;li&gt;charge充电类型字段为：
&lt;ul&gt;
&lt;li&gt;Voltage_measured：蓄电池端子电压（伏特）&lt;/li&gt;
&lt;li&gt;Current_measured：电池输出电流（安培）&lt;/li&gt;
&lt;li&gt;Temperature_measured：电池温度（摄氏度）&lt;/li&gt;
&lt;li&gt;Current_charge：在充电器处测量的电流（安培）&lt;/li&gt;
&lt;li&gt;Voltage_charge：在充电器处测量的电压（伏特）&lt;/li&gt;
&lt;li&gt;Time：周期的时间矢量（秒）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;discharge放电类型字段为：
&lt;ul&gt;
&lt;li&gt;Voltage_measured：蓄电池端子电压（伏特）&lt;/li&gt;
&lt;li&gt;Current_measured：电池输出电流（安培）&lt;/li&gt;
&lt;li&gt;Temperature_measured：电池温度（摄氏度）&lt;/li&gt;
&lt;li&gt;Current_charge：负载下测量的电流（安培）&lt;/li&gt;
&lt;li&gt;Voltage_charge：负载下测量的电压（伏特）&lt;/li&gt;
&lt;li&gt;Time：周期的时间矢量（秒）&lt;/li&gt;
&lt;li&gt;Capacity：放电至2.7V的电池容量（Ahr）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;impedance阻抗类型字段为：
&lt;ul&gt;
&lt;li&gt;Sense_current：感测支路中的电流（安培）&lt;/li&gt;
&lt;li&gt;Battery_current：电池支路中的电流（安培）&lt;/li&gt;
&lt;li&gt;Current_ratio：上述电流的比率&lt;/li&gt;
&lt;li&gt;Battery_impedance：根据原始数据计算的电池阻抗（欧姆）&lt;/li&gt;
&lt;li&gt;Rectified_impedance：校准和平滑的电池阻抗（欧姆）&lt;/li&gt;
&lt;li&gt;Re：估计电解质电阻（欧姆）&lt;/li&gt;
&lt;li&gt;Rct：估计的电荷转移电阻（欧姆）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;2-数据预处理&#34;&gt;2. 数据预处理&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;提取数据：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;考虑阻抗测试数据并不是与充放电周期进行，因此，我们只考虑充放电周期数据,并将相邻的充放电周期数据合并作为一组数据。&lt;/p&gt;
&lt;p&gt;而且训练的输入特征并不是越多越好，通过pandas的corr()函数分析，发现一些特征与SOH相关性较低，因此我们选择一些关键特征，如充电时间、充电电流标准差、放电时间和放电容量，这些特征与SOH的相关性较高，分析结果采用热力图如下：&lt;br&gt;
&lt;img loading=&#34;lazy&#34; data-src=&#34;/images/%E7%89%B9%E5%BE%81%E7%9B%B8%E5%85%B3%E6%80%A7%E5%88%86%E6%9E%90.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;
def extract_operation_features(cycle):
    ## 提取单个操作的特征
    features = &amp;#123;&amp;#125;
    data = cycle[&#39;data&#39;]
    try:
        if cycle[&#39;type&#39;] == &#39;charge&#39;:
            # 提取充电特征
            features.update(&amp;#123;
                &#39;cc_time&#39;: np.argmax(data[&#39;Voltage_measured&#39;] &amp;gt;= 4.2) / len(data[&#39;Time&#39;]),  # 恒流阶段占比
                &#39;current_charge_std&#39;: np.std(data[&#39;Current_measured&#39;]),
                &#39;Voltage_measured&#39;: np.argmax(data[&#39;Voltage_measured&#39;] &amp;gt;= 4.2) / len(data[&#39;Time&#39;]),
            &amp;#125;)
        elif cycle[&#39;type&#39;] == &#39;discharge&#39;:
            # 提取放电特征
            features.update(&amp;#123;
                &#39;discharge_duration&#39;: data[&#39;Time&#39;][-1] - data[&#39;Time&#39;][0],
                &#39;capacity&#39;: data[&#39;Capacity&#39;]  # 取最终放电容量
            &amp;#125;)
    except KeyError as e:
        print(f&amp;quot;特征提取错误: &amp;#123;str(e)&amp;#125;&amp;quot;)
    return features
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;数据集划分方式：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;df&lt;/code&gt;是划分的数据集，是上一步提取包含5、6、7、18号电池的特征信息。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;div_batt&lt;/code&gt;是用于划分训练集和测试集电池ID列表，这里是[‘05’, ‘06’, ‘07’]。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;test_ratio&lt;/code&gt;控制划分比例&lt;/li&gt;
&lt;li&gt;&lt;code&gt;test_new_batt&lt;/code&gt;是用于将全新电池作为测试集电池ID，这里是’18’。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;函数处理返回两种验证集&lt;code&gt;pd.concat(val_dfs)&lt;/code&gt;, &lt;code&gt;final_test_df&lt;/code&gt;。&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;code&gt;pd.concat(val_dfs)&lt;/code&gt;按照将div_batt列表电池的后20%作为测试集。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;final_test_df&lt;/code&gt;将&lt;code&gt;test_new_batt&lt;/code&gt;号电池作为测试集。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;# 划分数据集为训练集和测试集
def create_hybrid_split(df, div_batt, div_name, test_ratio=0.2, test_new_batt=None): 
    # 划分数据集为训练集和测试集 
    # df: 数据集
    # div_batt: 电池ID列表&#39;
    # div_name: 按照该属性值划分
    # test_ratio: 测试集比例（充放电周期数据前一部分为训练集，后面为测试集，保证无交叉）
    # test_new_batt: 新的一组电池作为测试集（可选）
    final_test_batt = test_new_batt
    final_test_df = df[df[div_name] == final_test_batt]
    # 其他电池内部按时间划分
    train_dfs, val_dfs = [], []
    for batt_id in div_batt:
        batt_data = df[df[div_name] == batt_id]
        split_idx = int(len(batt_data) * (1 - test_ratio))

        train_part = batt_data.iloc[:split_idx]
        val_part = batt_data.iloc[split_idx:]

        train_dfs.append(train_part)
        val_dfs.append(val_part)
    return pd.concat(train_dfs), pd.concat(val_dfs), final_test_df
# 开始数据集的划分
all_data = []
for batt_id in [&#39;05&#39;, &#39;06&#39;, &#39;07&#39;, &#39;18&#39;]:  # 遍历电池数据B005.mat, B006.mat, B007.mat, B0018.mat
    print(f&amp;quot;Processing battery &amp;#123;batt_id&amp;#125;...&amp;quot;)
    cycles = load_battery_data(batt_id)  # 数据加载
    current_cycle_num = 0  # 独立维护每个电池的周期计数器
    last_charge_features = &amp;#123;&amp;#125;  # 存储最近一次充电特征
    initial_capacity = None
    for cycle in cycles:
        # 跳过阻抗测试
        if cycle[&#39;type&#39;] == &#39;impedance&#39;:
            continue
        # 提取基础特征
        features = extract_operation_features(cycle)

        if cycle[&#39;type&#39;] == &#39;charge&#39;:
            # 缓存充电特征，等待后续放电配对
            last_charge_features = features

        elif cycle[&#39;type&#39;] == &#39;discharge&#39; and last_charge_features != &amp;#123;&amp;#125;: #开始为放电则跳过，确保构建（充电-放电）周期
            if not last_charge_features:
                print(f&amp;quot;Warning: 放电周期 &amp;#123;current_cycle_num&amp;#125; 缺少充电数据&amp;quot;)
                continue
            # 合并特征
            full_features = &amp;#123;
                &#39;battery_id&#39;: batt_id,
                &#39;cycle&#39;: current_cycle_num,
                **last_charge_features,
                **features
            &amp;#125;
            # 初始化容量记录
            if initial_capacity is None:
                initial_capacity = full_features[&#39;capacity&#39;]
                print(f&amp;quot;电池 &amp;#123;batt_id&amp;#125; 初始容量: &amp;#123;initial_capacity:.2f&amp;#125;Ah&amp;quot;)
            # 计算健康指标
            full_features[&#39;soh&#39;] = full_features[&#39;capacity&#39;] / initial_capacity
            all_data.append(full_features)
            # 周期计数器递增
            current_cycle_num += 1
            last_charge_features = &amp;#123;&amp;#125;  # 重置缓存
# 转换为DataFrame
df = pd.DataFrame(all_data)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;数据集划分：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;这里可以设置&lt;code&gt;train_batt_ids&lt;/code&gt;，&lt;code&gt;test_batt_ids&lt;/code&gt;，来选择上面提到的测试集划分方式，要取消几处可选的注释。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;df = create_dataset()

# 定义特征列（根据最新特征工程调整）
feature_cols = [
    &#39;cc_time&#39;,
    &#39;current_charge_std&#39;,
    &#39;Voltage_measured&#39;,
    &#39;discharge_duration&#39;,
    &#39;capacity&#39;
]
# 读取config.yaml定义的目标列
target_col = config[&#39;data&#39;][&#39;target_col&#39;]
# 按电池ID划分数据集（严格隔离）
train_batt_ids = [&#39;05&#39;, &#39;06&#39;, &#39;07&#39;]  # 划分训练集、测试集数据
# test_batt_ids = &#39;18&#39;  # 测试完整新电池数据（可选）

train_df, test_df, final_test_df = create_hybrid_split(df,
                                                        div_batt=train_batt_ids,
                                                        div_name=&#39;battery_id&#39;,
                                                        test_ratio=config[&#39;data&#39;][&#39;test_ratio&#39;],
                                                        # test_new_batt=test_batt_ids   #（可选）
                                                        )

# test_df = final_test_df #（可选）
# 特征标准化（仅在训练数据上拟合）
scaler = StandardScaler()
train_df[feature_cols] = scaler.fit_transform(train_df[feature_cols])
test_df[feature_cols] = scaler.transform(test_df[feature_cols])
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;实验发现，将数据的前一部分用于训练，后一部分用于测试，预测精度高一些。如果采用一组新的电池如B0018号则效果会略微下降，这可能是数据量还是太少的原因，模型泛化能力不足。&lt;/p&gt;
&lt;h2 id=&#34;3-模型构建&#34;&gt;3. 模型构建&lt;/h2&gt;
&lt;p&gt;模型采用LSTM（Long Short-Term Memory）网络，用于预测电池的SOH。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class BatteryLSTM(nn.Module):
    def __init__(self, input_size, hidden_size, num_layers, dropout, output_size):
        super().__init__()
        self.lstm = nn.LSTM(
            input_size=input_size,
            hidden_size=hidden_size,
            num_layers=num_layers,
            dropout=dropout,
            batch_first=True
        )
        self.fc = nn.Sequential(
            nn.Linear(hidden_size, 32),
            nn.ReLU(),
            nn.Dropout(dropout),
            nn.Linear(32, output_size)
        )

    def forward(self, x):
        out, (h_n, c_n) = self.lstm(x)
        out = self.fc(out[:, -1, :])
        return out
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;4-模型训练&#34;&gt;4. 模型训练&lt;/h2&gt;
&lt;p&gt;模型训练包括模型参数设置、模型训练、模型评估等步骤。&lt;br&gt;
关于精度可以尝试调整模型参数，如隐藏层大小、层数、dropout率等，以获得更好的性能。&lt;br&gt;
序列长度seq_length不大的话，隐藏层不需要太大我习惯分别尝试为[32, 64, 128, 256]。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-yaml&#34;&gt;data:
  sequence_length: 10
  test_ratio: 0.2
  target_col: &amp;quot;soh&amp;quot;

model:
  input_size: 5
  hidden_size: 128
  num_layers: 2
  dropout: 0.3
  output_size: 1

training:
  epochs: 300
  batch_size: 8
  learning_rate: 0.001
  patience: 20
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;5-模型预测&#34;&gt;5. 模型预测&lt;/h2&gt;
&lt;p&gt;各项指标：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;======== 最终模型评估指标 ========
MSE: 0.0001
RMSE: 0.0090
MAE: 0.0070
R²: 0.9838
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;预测结果：&lt;br&gt;
&lt;img loading=&#34;lazy&#34; data-src=&#34;/images/soh_trend_comparison.webp&#34; alt=&#34;&#34;&gt;&lt;br&gt;
图片这样是因为预测的是5、6、7号电池的后20%个周期的SOH，因为偷懒未单独对每个电池进行处理，想好看一点可以在前面讲的，将18号电池单独作为测试集。&lt;/p&gt;

 &lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;Lambda&lt;/code&gt;表达式是 &lt;code&gt;C++11&lt;/code&gt; 引入的一种匿名函数，允许在需要函数对象的地方直接定义一个函数，无需显式定义函数名。&lt;code&gt;Lambda&lt;/code&gt; 表达式常用于实现回调函数、临时函数、算法函数等场景。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1&gt;基本语法&lt;/h1&gt;
&lt;p&gt;Lambda 表达式的完整语法结构如下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;[ captures ] ( params ) mutable -&amp;gt; return_type &amp;#123; body &amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;组成部分&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;[ captures ]&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;捕获列表，定义外部变量如何被 &lt;code&gt;Lambda&lt;/code&gt; 访问（值捕获、引用捕获等）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;( params )&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;参数列表，与普通函数参数列表一致&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;mutable&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;可选关键字，允许修改按值捕获的变量&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;-&amp;gt; return_type&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;可选返回类型，可省略（编译器自动推导）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;&amp;#123; body &amp;#125;&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;Lambda&lt;/code&gt; 函数体&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h1&gt;捕获列表（Capture List）&lt;/h1&gt;
&lt;h2 id=&#34;捕获方式&#34;&gt;捕获方式&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;捕获方式&lt;/th&gt;
&lt;th&gt;语法示例&lt;/th&gt;
&lt;th&gt;行为&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;​按值捕获&lt;/td&gt;
&lt;td&gt;[x]&lt;/td&gt;
&lt;td&gt;复制外部变量 &lt;code&gt;x&lt;/code&gt; 的值到 &lt;code&gt;Lambda&lt;/code&gt; 内部&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​按引用捕获&lt;/td&gt;
&lt;td&gt;[&amp;amp;x]&lt;/td&gt;
&lt;td&gt;直接引用外部变量 &lt;code&gt;x&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​隐式按值捕获全部&lt;/td&gt;
&lt;td&gt;[=]&lt;/td&gt;
&lt;td&gt;按值捕获所有外部变量（不推荐，易导致悬空引用或性能问题）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​隐式按引用捕获全部&lt;/td&gt;
&lt;td&gt;[&amp;amp;]&lt;/td&gt;
&lt;td&gt;按引用捕获所有外部变量（不推荐，需谨慎管理生命周期）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​混合捕获&lt;/td&gt;
&lt;td&gt;&lt;code&gt;[x, &amp;amp;y]&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;按值捕获 &lt;code&gt;x&lt;/code&gt;，按引用捕获 &lt;code&gt;y&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​初始化捕获（C++14+）&lt;/td&gt;
&lt;td&gt;​	&lt;code&gt;[z = x + 1]&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;创建新变量 &lt;code&gt;z&lt;/code&gt;，其值为 &lt;code&gt;x + 1&lt;/code&gt;（可用于移动语义或复杂初始化）&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;示例代码&#34;&gt;示例代码&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;int a = 1, b = 2;

// 按值捕获 a，按引用捕获 b
auto lambda1 = [a, &amp;amp;b]() &amp;#123; return a + b; &amp;#125;;

// 隐式按引用捕获所有外部变量
auto lambda2 = [&amp;amp;]() &amp;#123; a++; b++; &amp;#125;;

// 初始化捕获（C++14+）
auto lambda3 = [c = a * 2]() &amp;#123; return c; &amp;#125;; // c = 2
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;参数列表（Parameters）&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;与普通函数参数列表一致，支持值传递、引用传递、默认参数等。&lt;/li&gt;
&lt;li&gt;​无参数时可省略：&lt;code&gt;[] &amp;#123; ... &amp;#125;&lt;/code&gt;&lt;br&gt;
&lt;strong&gt;示例&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;auto add = [](int x, int y) &amp;#123; return x + y; &amp;#125;; // 值传递
auto print = [](const std::string&amp;amp; s) &amp;#123; std::cout &amp;lt;&amp;lt; s; &amp;#125;; // 引用传递
auto no_args = [] &amp;#123; return 42; &amp;#125;; // 无参数
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;mutable 关键字&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;默认情况下，按值捕获的变量在 &lt;code&gt;Lambda&lt;/code&gt; 内部是 ​不可修改 的。&lt;/li&gt;
&lt;li&gt;使用 &lt;code&gt;mutable&lt;/code&gt; 后，可以修改按值捕获的变量（修改的是副本，不影响外部变量）。&lt;br&gt;
&lt;strong&gt;示例&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;int count = 0;

auto increment = [count]() mutable &amp;#123;
    count++; // 允许修改按值捕获的 count（副本）
&amp;#125;;

increment(); // 外部 count 仍为 0
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;返回类型（Return Type）&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;返回类型可省略，编译器根据 &lt;code&gt;return&lt;/code&gt; 语句自动推导。&lt;/li&gt;
&lt;li&gt;当函数体包含多个 &lt;code&gt;return&lt;/code&gt; 语句且类型不一致时，必须显式指定返回类型。&lt;br&gt;
&lt;strong&gt;示例&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;// 自动推导返回类型为 int
auto add = [](int x, int y) &amp;#123; return x + y; &amp;#125;;

// 显式指定返回类型为 double
auto divide = [](int x, int y) -&amp;gt; double &amp;#123;
    if (y == 0) return 0.0;
    return static_cast&amp;lt;double&amp;gt;(x) / y;
&amp;#125;;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;Lambda 的应用场景&lt;/h1&gt;
&lt;h2 id=&#34;作为函数对象（Functor）&#34;&gt;作为函数对象（Functor）&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;std::vector&amp;lt;int&amp;gt; nums = &amp;#123;1, 2, 3, 4&amp;#125;;
std::sort(nums.begin(), nums.end(), [](int a, int b) &amp;#123;
    return a &amp;gt; b; // 降序排序
&amp;#125;);
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;异步回调（如-Boost-Asio）&#34;&gt;异步回调（如 Boost.Asio）&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;socket.async_read_some(buffer, [this](const error_code&amp;amp; ec, size_t bytes) &amp;#123;
    if (!ec) handle_read(bytes);
&amp;#125;);
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;封装局部逻辑&#34;&gt;封装局部逻辑&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;void process_data(const std::vector&amp;lt;int&amp;gt;&amp;amp; data) &amp;#123;
    int threshold = 10;
    auto filter = [threshold](int x) &amp;#123; return x &amp;gt; threshold; &amp;#125;;
    std::copy_if(data.begin(), data.end(), std::back_inserter(result), filter);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;注意事项&lt;/h1&gt;
&lt;h2 id=&#34;生命周期管理&#34;&gt;生命周期管理&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;​按引用捕获：确保被引用的对象在 &lt;code&gt;Lambda&lt;/code&gt; 执行时仍然有效，避免悬空引用。&lt;/li&gt;
&lt;li&gt;​按值捕获指针：需谨慎，可能造成内存泄漏或悬空指针。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;性能&#34;&gt;性能&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;小对象按值捕获更高效，大对象（如容器）建议按引用捕获（需确保生命周期）。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;默认捕获的风险&#34;&gt;默认捕获的风险&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;避免使用 [=] 或 [&amp;amp;]：可能导致意外捕获不需要的变量，增加维护难度。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;Lambda-与函数对象的关系&#34;&gt;&lt;code&gt;Lambda&lt;/code&gt; 与函数对象的关系&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;Lambda&lt;/code&gt; 本质上是编译器生成的匿名类（闭包类型）的实例。&lt;/li&gt;
&lt;li&gt;捕获的变量会成为该匿名类的成员变量。&lt;/li&gt;
&lt;li&gt;等价转换示例&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;// Lambda 表达式
auto lambda = [x](int y) &amp;#123; return x + y; &amp;#125;;

// 编译器生成的等价类
class __AnonymousClosure &amp;#123;
private:
    int x;
public:
    __AnonymousClosure(int x) : x(x) &amp;#123;&amp;#125;
    int operator()(int y) const &amp;#123; return x + y; &amp;#125;
&amp;#125;;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;总结&lt;/h1&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;特性&lt;/th&gt;
&lt;th&gt;关键点&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;​捕获列表&lt;/td&gt;
&lt;td&gt;明确指定需要捕获的变量，避免隐式捕获&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​参数列表&lt;/td&gt;
&lt;td&gt;与普通函数一致，支持多种传递方式&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​&lt;strong&gt;mutable&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;允许修改按值捕获的变量副本&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​返回类型&lt;/td&gt;
&lt;td&gt;可省略（自动推导）或显式指定&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​生命周期&lt;/td&gt;
&lt;td&gt;谨慎管理按引用捕获的变量，避免悬空引用&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;​应用场景&lt;/td&gt;
&lt;td&gt;函数对象、异步回调、STL 算法等&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;

 &lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;Boost&lt;/code&gt; 是一个开源的 C++ 库集合，提供了许多实用的功能，如网络编程、图形界面、数学计算等。Boost 库可以与标准 C++ 库无缝集成，扩展了 C++ 的功能。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1&gt;安装 Boost 库&lt;/h1&gt;
&lt;p&gt;通过 APT 包管理器安装 Boost 库：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-shell&#34;&gt;# 1. 更新软件包索引
sudo apt update

# 2. 安装 Boost 核心库和开发文件（包含头文件和静态/动态库）
sudo apt install libboost-all-dev -y

# 3. 验证安装（检查版本）
boostversion=$(cat /usr/include/boost/version.hpp | grep &amp;quot;#define BOOST_VERSION&amp;quot; | awk &#39;&amp;#123;print $3&amp;#125;&#39;)

echo &amp;quot;Boost 版本: $boostversion&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;基本使用&lt;/h1&gt;
&lt;p&gt;同步操作会阻塞当前线程，直到操作完成。异步操作则不会阻塞线程，通过回调函数在操作完成后触发。&lt;/p&gt;
&lt;h2 id=&#34;同步&#34;&gt;同步&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;
#include &amp;lt;iostream&amp;gt;
#include&amp;lt;boost/asio.hpp&amp;gt;
int main()&amp;#123;
    boost::asio::io_context io;
    boost::asio::steady_timer t(io, boost::asio::chrono::seconds(5));
    // 同步,阻塞线程5秒
    t.wait();
    // wait() 返回，定时器资源（如系统句柄）被自动释放
    std::cout&amp;lt;&amp;lt;&amp;quot;Hello,world!&amp;quot;&amp;lt;&amp;lt;std::endl;
    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;定时器&lt;/strong&gt;&lt;br&gt;
&lt;code&gt;steady_timer&lt;/code&gt; 是 &lt;code&gt;Boost.Asio&lt;/code&gt; 提供的定时器类，用于在指定时间后执行回调函数。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;steady_timer &lt;/code&gt;的构造函数需要 &lt;code&gt;io_context&lt;/code&gt; 参数，目的是 &lt;strong&gt;​显式声明&lt;/strong&gt; 该定时器依赖** 的&lt;strong&gt;事件循环&lt;/strong&gt;。这种设计确保类型安全，避免隐式关联导致的错误。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;io_context 的作用&lt;/strong&gt;&lt;br&gt;
&lt;code&gt;io_context&lt;/code&gt; 是 &lt;code&gt;Boost.Asio&lt;/code&gt; 的核心组件，负责调度以及执行所有异步（如 DNS 解析、连接、读写）和同步操作的生命周期。（如定时器、网络 I/O）。&lt;/p&gt;
&lt;h2 id=&#34;异步&#34;&gt;异步&lt;/h2&gt;
&lt;p&gt;异步操作需要事件循环来驱动，&lt;code&gt;io_context::run()&lt;/code&gt; 方法启动事件处理流程。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;iostream&amp;gt;
#include&amp;lt;boost/asio.hpp&amp;gt;

void print(const boost::system::error_code&amp;amp; a /*e*/)
&amp;#123;
    std::cout&amp;lt;&amp;lt;a&amp;lt;&amp;lt;std::endl;
    std::cout&amp;lt;&amp;lt;&amp;quot;Hello,world!&amp;quot;&amp;lt;&amp;lt;std::endl;
&amp;#125;
int main()&amp;#123;
    boost::asio::io_context io;
    boost::asio::steady_timer t(io, boost::asio::chrono::seconds(5)); 
    t.async_wait(&amp;amp;print);   // 异步,不会阻塞线程，回调函数print会在5秒后执行
    io.run();
    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;io.run() &lt;/code&gt;是异步编程的核心，负责监听操作系统异步操作（如定时器到期、网络请求完成）的完成事件，确保资源（如&lt;code&gt;定时器&lt;/code&gt;、&lt;code&gt;socket&lt;/code&gt;）被正确释放，并触发回调函数。&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;特性&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;同步代码&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;异步代码&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​执行方式&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;阻塞等待（&lt;code&gt;wait()&lt;/code&gt;）&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;非阻塞，通过回调触发&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​事件循环&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;无需 &lt;code&gt;io.run()&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;必须调用 &lt;code&gt;io.run()&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​线程占用&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;单线程阻塞&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;单线程/多线程（由 &lt;code&gt;run()&lt;/code&gt; 决定）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​适用场景&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;简单、短耗时操作&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;高并发、实时性要求高的场景&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;hr&gt;
&lt;p&gt;&lt;strong&gt;​时间点计算&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;函数式编程&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;functional&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

void print(const boost::system::error_code&amp;amp; /*e*/,
    boost::asio::steady_timer* t, int* count)
&amp;#123;
  if (*count &amp;lt; 5)
  &amp;#123;
    std::cout &amp;lt;&amp;lt; *count &amp;lt;&amp;lt; std::endl;
    ++(*count);

    // 新到期时间 = 当前到期时间 + 1秒
    t-&amp;gt;expires_at(t-&amp;gt;expiry() + boost::asio::chrono::seconds(1));

    // 异步等待新到期时间
    t-&amp;gt;async_wait(std::bind(print,
        std::placeholders::_1, t, count));
  &amp;#125;
&amp;#125;

int main()
&amp;#123;
  boost::asio::io_context io;

  int count = 0;
  boost::asio::steady_timer t(io, boost::asio::chrono::seconds(1));

  t.async_wait(std::bind(print,
    std::placeholders::_1, &amp;amp;t, &amp;amp;count));

  io.run();

  std::cout &amp;lt;&amp;lt; &amp;quot;Final count is &amp;quot; &amp;lt;&amp;lt; count &amp;lt;&amp;lt; std::endl;

  return 0;
&amp;#125;

// 输出
// 0
// 1
// 2
// 3
// 4
// Final count is 5
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;// 新到期时间 = 当前到期时间 + 1秒
t-&amp;gt;expires_at(t-&amp;gt;expires_at() + boost::asio::chrono::seconds(1));
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;t-&amp;gt;expires_at()&lt;/code&gt; 返回定时器当前的到期时间点（&lt;code&gt;system_clock::time_point&lt;/code&gt; 类型），&lt;code&gt;boost::asio::chrono::seconds(1)&lt;/code&gt;表示一个 ​时间间隔​（&lt;code&gt;duration&lt;/code&gt; 类型）。两者相加会生成新的到期时间点：&lt;/p&gt;
&lt;p&gt;这种设计允许动态调整定时器的触发时间，适用于需要重复执行任务的场景（如每隔&lt;code&gt;1&lt;/code&gt;秒打印一次计数器）。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;​类型匹配的底层原理&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;expires_at()&lt;/code&gt; 的参数类型是 &lt;code&gt;system_clock::time_point&lt;/code&gt;，而 &lt;code&gt;boost::asio::chrono::seconds(1)&lt;/code&gt; 的类型是 &lt;code&gt;duration&lt;/code&gt;,明确指定了时间单位（秒），避免了因隐式类型转换导致的单位混淆（如误用毫秒或微秒）。&lt;br&gt;
&lt;code&gt;Boost.Asio&lt;/code&gt; 的 &lt;code&gt;chrono&lt;/code&gt; 库通过 &lt;strong&gt;​类型推导&lt;/strong&gt; 和 &lt;strong&gt;运算符重载&lt;/strong&gt;，自动将 &lt;code&gt;duration&lt;/code&gt; 转换为 &lt;code&gt;time_point&lt;/code&gt;，确保表达式合法。&lt;br&gt;
若直接使用 &lt;code&gt;t-&amp;gt;expires_at(1)&lt;/code&gt;，编译器会报错，因为 &lt;code&gt;1&lt;/code&gt; 的类型是 &lt;code&gt;int&lt;/code&gt;，无法隐式转换为 &lt;code&gt;time_point&lt;/code&gt;。&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;strong&gt;面向对象编程&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;functional&amp;gt; 
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

class printer
&amp;#123;
public:
    // 构造函数，初始化timer_成员和count_成员
    printer(boost::asio::io_context&amp;amp; io)
    : timer_(io, boost::asio::chrono::seconds(1)),  // 初始化timer_成员
      count_(0)                                     // 初始化count_成员
    &amp;#123;
    // bind() 函数将成员函数print绑定到当前对象上，并作为回调函数传递给timer_.async_wait()
        timer_.async_wait(std::bind(&amp;amp;printer::print, this)); 
    &amp;#125;
    // 析构函数
    ~printer()
    &amp;#123;
        std::cout&amp;lt;&amp;lt; &amp;quot;final count is &amp;quot;&amp;lt;&amp;lt; count_ &amp;lt;&amp;lt;std::endl;
    &amp;#125;

    void print()&amp;#123;
        if(count_&amp;lt;5)
        &amp;#123;
            std::cout &amp;lt;&amp;lt; count_ &amp;lt;&amp;lt;std::endl;
            ++count_;
            // 新到期时间 = 当前到期时间 + 1秒
            timer_.expires_at(timer_.expiry() + boost::asio::chrono::seconds(1));
            timer_.async_wait(std::bind(&amp;amp;printer::print,this));
        &amp;#125;
    &amp;#125;

private:
    boost::asio::steady_timer timer_;
    int count_;
&amp;#125;;

int main()
&amp;#123;
  boost::asio::io_context io;
  printer p(io);
  io.run();
  return 0;
&amp;#125;

// 输出
// 0
// 1
// 2
// 3
// 4
// final count is 5
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;优缺点对比&lt;/strong&gt;&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;维度&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;​函数式&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;​面向对象&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​代码简洁性&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;✅ 代码简短，适合简单场景&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❌ 类定义增加代码量&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​安全性&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❌ 需手动管理指针，易出错&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;✅ 自动管理资源，避免悬垂指针&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​扩展性&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❌ 修改需调整参数传递链&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;✅ 新增功能只需扩展类方法&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​异步上下文&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❌ 依赖外部变量，多线程下可能竞争&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;✅ 成员变量天然隔离，适合多线程异步任务&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​性能开销&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;✅ 无虚函数或类结构开销&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❌ 类实例化带来微小内存开销&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;hr&gt;
&lt;p&gt;&lt;strong&gt;线程安全的异步任务队列（通过 Strand 串行化）&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;functional&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;thread&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;
// 通过 strand_ 序列化回调函数的执行
class printer
&amp;#123;
public:
    printer(boost::asio::io_context&amp;amp; io)
        : strand_(boost::asio::make_strand(io)),     // 初始化strand_成员
        timer1_(io, boost::asio::chrono::seconds(1)),// 初始化timer1_成员
        timer2_(io, boost::asio::chrono::seconds(1)),// 初始化timer2_成员
        count_(0)
    &amp;#123;
        // 使用strand_串行化异步操作,bind_executor()将异步操作绑定到strand_上
        timer1_.async_wait(boost::asio::bind_executor(strand_,
            std::bind(&amp;amp;printer::print1, this)));

        timer2_.async_wait(boost::asio::bind_executor(strand_,
            std::bind(&amp;amp;printer::print2, this)));
    &amp;#125;

    ~printer()
    &amp;#123;
      std::cout &amp;lt;&amp;lt; &amp;quot;Final count is &amp;quot; &amp;lt;&amp;lt; count_ &amp;lt;&amp;lt; std::endl;
    &amp;#125;
    void print1()
    &amp;#123;
        if (count_ &amp;lt; 10)
        &amp;#123;
        std::cout &amp;lt;&amp;lt; &amp;quot;Timer 1: &amp;quot; &amp;lt;&amp;lt; count_ &amp;lt;&amp;lt; std::endl;
        ++count_;

        timer1_.expires_at(timer1_.expiry() + boost::asio::chrono::seconds(1));

        timer1_.async_wait(boost::asio::bind_executor(strand_,
                std::bind(&amp;amp;printer::print1, this)));
        &amp;#125;
    &amp;#125;

    void print2()
    &amp;#123;
        if (count_ &amp;lt; 10)
        &amp;#123;
        std::cout &amp;lt;&amp;lt; &amp;quot;Timer 2: &amp;quot; &amp;lt;&amp;lt; count_ &amp;lt;&amp;lt; std::endl;
        ++count_;

        timer2_.expires_at(timer2_.expiry() + boost::asio::chrono::seconds(1));

        timer2_.async_wait(boost::asio::bind_executor(strand_,
                std::bind(&amp;amp;printer::print2, this)));
        &amp;#125;
    &amp;#125;

private:
  boost::asio::strand&amp;lt;boost::asio::io_context::executor_type&amp;gt; strand_;
  boost::asio::steady_timer timer1_;
  boost::asio::steady_timer timer2_;
  int count_;
&amp;#125;;

int main()
&amp;#123;
  boost::asio::io_context io;
  printer p(io);
  // 创建一个新线程，执行 Lambda 表达式中的代码 (即 io.run())
  std::thread t([&amp;amp;]&amp;#123; io.run(); &amp;#125;);
  io.run();
  // 阻塞主线程，直到 t 线程结束
  t.join();

  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;代码通过多线程运行 &lt;code&gt;io_context &lt;/code&gt;的事件循环，结合 &lt;code&gt;strand_&lt;/code&gt; 的序列化机制，实现了高效的事件响应与线程安全的逻辑处理。虽然有两个线程处理事件，但任务逻辑（&lt;code&gt;print1&lt;/code&gt;/&lt;code&gt;print2&lt;/code&gt;）本质上是单线程化的，因此更准确地说，这是多线程协作处理事件循环，但任务执行是序列化的。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;&lt;code&gt;Lambda&lt;/code&gt; 的捕获方式 [&amp;amp;]&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;[&amp;amp;] 表示以引用方式捕获所有外部变量。&lt;br&gt;
在 &lt;code&gt;Lambda&lt;/code&gt; 内部可以直接访问外部作用域的所有变量（如 &lt;code&gt;io&lt;/code&gt;），且操作的是原变量本身，而非副本。&lt;/li&gt;
&lt;li&gt;​对比其他捕获方式：&lt;br&gt;
[=]：以值方式捕获（创建副本，可能影响性能）。&lt;br&gt;
[io]：仅捕获 io 变量（需显式指定）。&lt;br&gt;
此处 [&amp;amp;] 简化了代码，但需确保 &lt;code&gt;Lambda&lt;/code&gt; 生命周期内外部变量有效。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;代码的多线程机制&lt;br&gt;
&lt;strong&gt;​线程数量与任务类型&lt;/strong&gt;&lt;br&gt;
代码中通过 &lt;code&gt;std::thread t([&amp;amp;]&amp;#123; io.run(); &amp;#125;)&lt;/code&gt; 创建了一个工作线程，主线程也调用 &lt;code&gt;io.run()&lt;/code&gt;，因此 ​总共有两个线程运行 &lt;code&gt;io_context&lt;/code&gt; 的事件循环。这两个线程会并行处理 &lt;code&gt;io_context&lt;/code&gt; 中的异步操作（如定时器到期事件）。&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​异步操作的并行性&lt;/strong&gt;&lt;br&gt;
&lt;code&gt;timer1_&lt;/code&gt; 和 &lt;code&gt;timer2_&lt;/code&gt; 是独立的定时器，它们的异步等待操作会被提交到 &lt;code&gt;io_context&lt;/code&gt; 的任务队列中。理论上，这两个定时器的到期事件可能被分配到不同的线程处理。但由于绑定了 &lt;code&gt;strand_&lt;/code&gt;，所有回调会被强制序列化执行，​实际表现为单线程顺序处理​。&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;Strand 的核心作用&lt;br&gt;
&lt;strong&gt;​线程安全与顺序保证&lt;/strong&gt;&lt;br&gt;
&lt;code&gt;strand_ &lt;/code&gt;是 &lt;code&gt;Boost.Asio&lt;/code&gt; 提供的一种隐式同步机制，其作用包括：&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;​序列化回调执行：所有通过 &lt;code&gt;strand_&lt;/code&gt; 提交的回调（如 &lt;code&gt;print1&lt;/code&gt; 和 &lt;code&gt;print2&lt;/code&gt;）会按提交顺序依次执行，即使多个线程在运行 &lt;code&gt;io_context&lt;/code&gt;。&lt;br&gt;
​消除数据竞争：对共享资源 &lt;code&gt;count_&lt;/code&gt; 的修改（如&lt;code&gt;++count_&lt;/code&gt;）会被限制在同一个线程上下文中，无需显式加锁。&lt;br&gt;
&lt;strong&gt;​代码中的具体实现&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;timer1_.async_wait(boost::asio::bind_executor(strand_, ...));
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;将定时器的回调函数绑定到 &lt;code&gt;strand_&lt;/code&gt; 的执行器上，确保回调在 &lt;code&gt;strand_ &lt;/code&gt;的调度下运行。因此，即使两个定时器的到期事件被不同线程触发，&lt;code&gt;print1&lt;/code&gt; 和 &lt;code&gt;print2&lt;/code&gt; 也不会并发执行。&lt;/p&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;执行流程示例&lt;br&gt;
假设两个定时器同时到期：
&lt;ol&gt;
&lt;li&gt;​事件触发：&lt;code&gt;timer1_&lt;/code&gt; 和 &lt;code&gt;timer2_&lt;/code&gt; 的到期事件被提交到 &lt;code&gt;io_context&lt;/code&gt;。&lt;/li&gt;
&lt;li&gt;​线程分配：事件可能被主线程或工作线程 &lt;code&gt;t&lt;/code&gt; 处理。&lt;/li&gt;
&lt;li&gt;​Strand 调度：无论哪个线程处理事件，回调函数会被 &lt;code&gt;strand_ &lt;/code&gt;序列化。例如：
&lt;ul&gt;
&lt;li&gt;线程1执行 &lt;code&gt;print1&lt;/code&gt; → 输出 &lt;code&gt;Timer 1: 0&lt;/code&gt;。&lt;/li&gt;
&lt;li&gt;线程2执行 &lt;code&gt;print2&lt;/code&gt; → 但需等待 &lt;code&gt;print1&lt;/code&gt; 完成后才能执行，输出 &lt;code&gt;Timer 2: 1&lt;/code&gt;。&lt;/li&gt;
&lt;li&gt;最终 &lt;code&gt;count_&lt;/code&gt; 会严格递增至10，无并发问题&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h1&gt;TCP&lt;/h1&gt;
&lt;p&gt;&lt;strong&gt;TCP连接&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;TCP连接是面向连接的，可靠的，基于字节流的传输层通信协议。&lt;/li&gt;
&lt;li&gt;TCP连接需要三次握手来建立连接，四次挥手来关闭连接。&lt;/li&gt;
&lt;li&gt;TCP连接的建立和关闭都需要消耗一定的资源，因此需要合理管理TCP连接。&lt;/li&gt;
&lt;li&gt;TCP连接的建立和关闭都需要消耗一定的资源，因此需要合理管理TCP连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;UDP连接&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;UDP连接是无连接的，不可靠的，基于数据报的传输层通信协议。&lt;/li&gt;
&lt;li&gt;UDP连接不需要建立连接，只需要发送数据报即可。&lt;/li&gt;
&lt;li&gt;UDP连接不需要关闭连接，只需要发送数据报即可。&lt;/li&gt;
&lt;li&gt;UDP连接的建立和关闭不需要消耗资源，因此不需要管理UDP连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;TCP和UDP的区别&lt;/strong&gt;&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;TCP&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;UDP&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;面向连接&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;无连接&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;可靠&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可靠&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;基于字节流&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;基于数据报&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;需要三次握手&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不需要握手&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;需要四次挥手&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不需要挥手&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;建立和关闭连接需要消耗资源&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;建立和关闭连接不需要消耗资源&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;需要管理连接&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不需要管理连接&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;strong&gt;TCP和UDP的应用场景&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;TCP连接适用于需要可靠传输的场景，如文件传输、邮件发送等。&lt;/li&gt;
&lt;li&gt;UDP连接适用于需要快速传输的场景，如视频直播、实时游戏等。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;TCP和UDP的编程模型&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;TCP连接的编程模型通常包括客户端和服务端两部分，客户端通过 &lt;code&gt;socket&lt;/code&gt; 函数创建一个套接字，然后通过 &lt;code&gt;connect&lt;/code&gt; 函数连接到服务端，然后通过 &lt;code&gt;send&lt;/code&gt; 和 &lt;code&gt;recv&lt;/code&gt; 函数进行数据的发送和接收，最后通过 &lt;code&gt;close&lt;/code&gt; 函数关闭连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;同步TCP时间服务器&#34;&gt;同步TCP时间服务器&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;命令行参数&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;int main(int argc, char* argv[])&amp;#123;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;argc（Argument Count）​&lt;/strong&gt;&lt;br&gt;
表示命令行参数的总数量（包括程序名本身）。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;例如，若用户输入 &lt;code&gt;./myprogram arg1 arg2&lt;/code&gt;，则 &lt;code&gt;argc&lt;/code&gt; 的值为 ​3​（程序名 + 2 个参数）。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;​&lt;strong&gt;argv[]（Argument Vector）​&lt;/strong&gt;&lt;br&gt;
是一个字符串指针数组，存储所有命令行参数的具体值。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;argv[0]&lt;/code&gt;：程序自身的名称（如 “./myprogram”）。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;argv[1]&lt;/code&gt; ~ &lt;code&gt;argv[argc-1]&lt;/code&gt;：用户输入的其他参数。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;argv[argc]&lt;/code&gt;：固定为 NULL（表示数组结束）。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;示例代码：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;stdio.h&amp;gt;

int main(int argc, char* argv[]) &amp;#123;
    printf(&amp;quot;参数总数 argc = %d\n&amp;quot;, argc);

    for (int i = 0; i &amp;lt; argc; i++) &amp;#123;
        printf(&amp;quot;argv[%d] = %s\n&amp;quot;, i, argv[i]);
    &amp;#125;

    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;运行示例：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;./myprogram arg1 arg2 arg3
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;输出：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;参数总数 argc = 4
argv[0] = ./myprogram
argv[1] = arg1
argv[2] = arg2
argv[3] = arg3
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;同步TCP服务端&lt;/li&gt;
&lt;/ol&gt;
&lt;blockquote&gt;
&lt;p&gt;服务端: 监听端口 13 ,发送时间数据&lt;/p&gt;
&lt;/blockquote&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;ctime&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;string&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

using boost::asio::ip::tcp;

std::string make_daytime_string() &amp;#123;
    std::time_t now = std::time(nullptr);
    return std::ctime(&amp;amp;now); // 格式示例: &amp;quot;Wed Oct  2 00:00:00 2023\n&amp;quot;
&amp;#125;

int main() &amp;#123;
    try &amp;#123;
        boost::asio::io_context io_context;

        // 监听端口 13 (需管理员权限) 或改用其他端口如 12345
        tcp::acceptor acceptor(io_context, tcp::endpoint(tcp::v4(), 13));

        std::cout &amp;lt;&amp;lt; &amp;quot;Daytime 服务器启动，监听端口: &amp;quot; &amp;lt;&amp;lt; acceptor.local_endpoint().port() &amp;lt;&amp;lt; std::endl;

        for (;;) &amp;#123;
            tcp::socket socket(io_context);
            acceptor.accept(socket); // 阻塞等待客户端连接

            std::cout &amp;lt;&amp;lt; &amp;quot;客户端连接: &amp;quot; &amp;lt;&amp;lt; socket.remote_endpoint() &amp;lt;&amp;lt; std::endl;

            std::string message = make_daytime_string();
            boost::system::error_code ignored_error;

            // 发送时间数据后立即关闭连接
            boost::asio::write(socket, boost::asio::buffer(message), ignored_error);
        &amp;#125;
    &amp;#125; catch (std::exception&amp;amp; e) &amp;#123;
        std::cerr &amp;lt;&amp;lt; &amp;quot;异常: &amp;quot; &amp;lt;&amp;lt; e.what() &amp;lt;&amp;lt; std::endl;
    &amp;#125;
    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;同步TCP客户端&lt;/li&gt;
&lt;/ol&gt;
&lt;blockquote&gt;
&lt;p&gt;客户端：连接服务器，发送数据，接收响应，关闭连接。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;strong&gt;整体流程&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;**​初始化 I/O 上下文：**创建 io_context 对象，管理所有 I/O 操作。&lt;/li&gt;
&lt;li&gt;**​解析目标地址：**将用户输入的主机名和服务名转换为具体的网络地址列表。&lt;/li&gt;
&lt;li&gt;**​创建套接字：**准备用于通信的套接字对象。&lt;/li&gt;
&lt;li&gt;**​连接服务器：**按地址列表尝试连接，直到成功或全部失败。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;array&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

// using导入某个变量到当前作用域 
using boost::asio::ip::tcp; // tcp命名空间

int main(int argc, char* argv[])
&amp;#123;
  try
  &amp;#123;
    if (argc != 2)
    &amp;#123;
      // std::cerr 通常用于输出错误信息，这些信息不会被重定向到文件或管道，而是直接显示在终端上。
      std::cerr &amp;lt;&amp;lt; &amp;quot;Usage: client &amp;lt;host&amp;gt;&amp;quot; &amp;lt;&amp;lt; std::endl;
      return 1;
    &amp;#125;

    boost::asio::io_context io_context;
    //创建解析器对象，用于将 ​主机名 和 ​服务名/端口号 转换为具体的网络地址（IP + 端口）。
    tcp::resolver resolver(io_context);      // io_context：绑定到同一个 I/O 上下文，确保解析操作由该上下文管理。
    tcp::resolver::results_type endpoints =     
      resolver.resolve(argv[1], &amp;quot;cc&amp;quot;);       // 解析用户输入的主机名和服务名，生成可能的网络端点列表。
    tcp::socket socket(io_context);          // 套接字绑定到同一个 I/O 上下文，确保其操作由该上下文管理。
    boost::asio::connect(socket, endpoints); // 尝试连接到服务器。

    for (;;)
    &amp;#123;
      std::array&amp;lt;char, 128&amp;gt; buf;
      boost::system::error_code error;

      // read_some函数用于从TCP连接中读取数据。buffer函数用于创建一个缓冲区，用于存储读取的数据。size_t类型表示读取的字节数。
      size_t len = socket.read_some(boost::asio::buffer(buf), error); 

      if (error == boost::asio::error::eof) // eof表示连接已关闭。
        break; // Connection closed cleanly by peer.
      else if (error)
        throw boost::system::system_error(error); // Some other error.

      std::cout.write(buf.data(), len);// buf.data()返回缓冲区的指针，len表示读取的字节数。
    &amp;#125;
  &amp;#125;
  catch (std::exception&amp;amp; e)
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.what() &amp;lt;&amp;lt; std::endl;
  &amp;#125;

  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol&gt;
&lt;li&gt;&lt;code&gt;boost::asio::io_context io_context;&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​作用：&lt;/strong&gt; 创建 I/O 上下文对象，管理所有底层 I/O 操作（如网络通信、定时器等）。&lt;br&gt;
&lt;strong&gt;​原理：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;io_context&lt;/code&gt; 是 &lt;code&gt;Boost.Asio&lt;/code&gt; 的 ​事件循环核心，负责调度和处理异步操作。&lt;br&gt;
所有异步操作（如连接、读写）都需要通过它执行。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;code&gt;tcp::resolver resolver(io_context);&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​作用：&lt;/strong&gt; 创建解析器对象，用于将 ​主机名 和 ​服务名/端口号 转换为具体的网络地址（IP + 端口）。&lt;br&gt;
&lt;strong&gt;​参数：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;io_context&lt;/code&gt;：绑定到同一个 I/O 上下文，确保解析操作由该上下文管理。&lt;br&gt;
&lt;strong&gt;​功能：&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;解析器 (&lt;code&gt;resolver&lt;/code&gt;) 支持 &lt;code&gt;DNS&lt;/code&gt; 查询，将域名（如 &lt;code&gt;&amp;quot;example.com&amp;quot;&lt;/code&gt;）解析为 IP 地址。&lt;/li&gt;
&lt;li&gt;将服务名（如 &lt;code&gt;&amp;quot;http&amp;quot;&lt;/code&gt;）解析为端口号（如 &lt;code&gt;80&lt;/code&gt;）。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;&lt;code&gt;tcp::resolver::results_type endpoints = resolver.resolve(argv[1], &amp;quot;cc&amp;quot;);&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​作用：&lt;/strong&gt; 解析用户输入的主机名和服务名，生成可能的网络端点列表。&lt;br&gt;
&lt;strong&gt;​参数：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;argv[1]&lt;/code&gt;：命令行输入的主机名（如 &lt;code&gt;&amp;quot;localhost&amp;quot;&lt;/code&gt; 或 &lt;code&gt;&amp;quot;192.168.1.100&amp;quot;&lt;/code&gt;）。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;&amp;quot;cc&amp;quot;&lt;/code&gt;：服务名或端口号。这里可能是自定义的服务名（需系统配置）或直接表示端口号（如 &lt;code&gt;&amp;quot;12345&amp;quot;&lt;/code&gt;）。&lt;br&gt;
&lt;strong&gt;​返回值：&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;code&gt;endpoints&lt;/code&gt; 是一个端点列表，包含所有可能的 IP 地址和端口组合（例如 &lt;code&gt;IPv4&lt;/code&gt; 和 &lt;code&gt;IPv6&lt;/code&gt; 地址）。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;&lt;code&gt;tcp::socket socket(io_context);&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​作用：&lt;/strong&gt; 创建 &lt;code&gt;TCP&lt;/code&gt; 套接字对象，用于与服务器通信。&lt;br&gt;
&lt;strong&gt;​参数：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;io_context&lt;/code&gt;：套接字绑定到同一个 I/O 上下文，确保其操作由该上下文管理。&lt;br&gt;
&lt;strong&gt;​功能：&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;套接字是网络通信的端点，通过它可以发送和接收数据。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;&lt;code&gt;boost::asio::connect(socket, endpoints);&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​作用：&lt;/strong&gt; 尝试连接到服务器。&lt;br&gt;
&lt;strong&gt;​参数：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;socket&lt;/code&gt;：上一步创建的套接字。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;endpoints&lt;/code&gt;：解析得到的端点列表。&lt;br&gt;
&lt;strong&gt;​行为：&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;按顺序尝试连接 &lt;code&gt;endpoints&lt;/code&gt; 中的每一个端点（如 &lt;code&gt;IPv4&lt;/code&gt; 地址优先，失败后尝试 &lt;code&gt;IPv6&lt;/code&gt;）。&lt;/li&gt;
&lt;li&gt;当某个端点连接成功时，停止尝试。&lt;/li&gt;
&lt;li&gt;如果所有端点均连接失败，抛出异常。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;异步TCP时间服务器&#34;&gt;异步TCP时间服务器&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;主函数入口&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;int main()
&amp;#123;
  try
  &amp;#123;
    boost::asio::io_context io_context;      // 创建IO上下文，管理所有异步操作
    tcp_server server(io_context);          // 创建TCP服务器实例，初始化监听
    io_context.run();                       // 启动事件循环，处理异步操作
  &amp;#125;
  catch (std::exception&amp;amp; e)                 // 异常处理
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.what() &amp;lt;&amp;lt; std::endl;
  &amp;#125;
  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;io_context&lt;/code&gt; 是&lt;code&gt;Boost.Asio&lt;/code&gt;的核心，负责调度异步任务。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;tcp_server&lt;/code&gt; 初始化时会开始监听连接。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;io_context.run()&lt;/code&gt; 会阻塞主线程，持续处理异步事件，直到所有任务完成。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;strong&gt;​TCP服务器初始化（tcp_server构造函数）​&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;tcp_server(boost::asio::io_context&amp;amp; io_context)
  : io_context_(io_context),
    acceptor_(io_context, tcp::endpoint(tcp::v4(), 13)) // 绑定IPv4地址的13端口
&amp;#123;
  start_accept(); // 开始异步等待客户端连接
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;acceptor_&lt;/code&gt; 初始化时绑定到本地13端口。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;start_accept()&lt;/code&gt; 启动异步接受连接的过程。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;&lt;strong&gt;异步接受连接（start_accept）​&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;void start_accept()
&amp;#123;
  tcp_connection::pointer new_connection = tcp_connection::create(io_context_); // 创建新连接对象
  acceptor_.async_accept(                       // 异步接受连接
      new_connection-&amp;gt;socket(),
      [this, new_connection](const boost::system::error_code&amp;amp; error) &amp;#123;
          handle_accept(error, new_connection); // 连接完成时调用处理函数
      &amp;#125;);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;tcp_connection::create&lt;/code&gt; 创建新的连接对象，其&lt;code&gt;socket&lt;/code&gt;由&lt;code&gt;io_context&lt;/code&gt;管理。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;async_accept&lt;/code&gt; 异步等待客户端连接。当有连接到来时，&lt;code&gt;lambda&lt;/code&gt;被调用，传递错误码和连接对象。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;&lt;strong&gt;处理新连接（handle_accept）​&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;void handle_accept(const boost::system::error_code&amp;amp; error, tcp_connection::pointer new_connection)
&amp;#123;
  if (!error)
  &amp;#123;
    new_connection-&amp;gt;start(); // 启动数据发送流程
  &amp;#125;
  start_accept(); // 继续监听下一个连接
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;如果没有错误，调用&lt;code&gt;new_connection-&amp;gt;start()&lt;/code&gt;开始处理客户端请求。&lt;/li&gt;
&lt;li&gt;无论是否出错，再次调用&lt;code&gt;start_accept()&lt;/code&gt;，形成循环监听。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;&lt;strong&gt;TCP连接处理（tcp_connection::start）&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;void start()
&amp;#123;
  message_ = make_daytime_string(); // 生成当前时间字符串
  auto self(shared_from_this());    // 获取shared_ptr，延长对象生命周期
  boost::asio::async_write(         // 异步发送数据
      socket_,
      boost::asio::buffer(message_),
      [this, self](const auto&amp;amp; error, size_t bytes) &amp;#123;
          handle_write(error, bytes); // 发送完成后的回调
      &amp;#125;);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;make_daytime_string()&lt;/code&gt; 生成当前时间的字符串。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;shared_from_this()&lt;/code&gt; 确保在异步操作期间对象不会被销毁。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;async_write&lt;/code&gt; 异步发送数据，完成后调用&lt;code&gt;handle_write&lt;/code&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;&lt;strong&gt;数据发送完成处理（handle_write）​&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;void handle_write(const boost::system::error_code&amp;amp; /*error*/, size_t /*bytes_transferred*/)
&amp;#123;
  // 此处可添加发送完成后的逻辑，例如关闭连接
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;当前代码未处理发送结果，但可在此处添加错误处理或资源释放逻辑。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;7&#34;&gt;
&lt;li&gt;&lt;strong&gt;生成时间字符串（make_daytime_string）​&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;std::string make_daytime_string()
&amp;#123;
  time_t now = time(0);
  return ctime(&amp;amp;now); // 示例输出：&amp;quot;Wed May 22 15:42:36 2024\n&amp;quot;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;返回的字符串末尾包含换行符，符合Daytime协议标准。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;异步执行流程总结：​&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;服务器启动，监听端口13。&lt;/li&gt;
&lt;li&gt;当客户端连接时，async_accept 完成，触发 handle_accept。&lt;/li&gt;
&lt;li&gt;无错误则调用 start() 发送时间数据。&lt;/li&gt;
&lt;li&gt;数据发送完成后，由 handle_write 处理后续逻辑（当前为空）。&lt;/li&gt;
&lt;li&gt;服务器循环调用 start_accept，持续监听新连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;**关键点：**​&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;​生命周期管理：&lt;/strong&gt; 通过 &lt;code&gt;shared_from_this()&lt;/code&gt; 和 &lt;code&gt;shared_ptr&lt;/code&gt; 确保异步操作期间对象存活。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;​异步链式调用：&lt;/strong&gt; &lt;code&gt;async_accept&lt;/code&gt; →&lt;code&gt; handle_accept&lt;/code&gt; → &lt;code&gt;async_write&lt;/code&gt; → &lt;code&gt;handle_write&lt;/code&gt; 形成异步链。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;​端口重用：&lt;/strong&gt; Daytime协议使用13端口，需确保权限允许（Linux/Mac可能需要sudo运行）。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;完整代码：&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;ctime&amp;gt;
#include &amp;lt;functional&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;memory&amp;gt;
#include &amp;lt;string&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

using boost::asio::ip::tcp;

std::string make_daytime_string()
&amp;#123;
  time_t now = time(0);
  return ctime(&amp;amp;now); // 示例输出：&amp;quot;Wed May 22 15:42:36 2024\n&amp;quot;
&amp;#125;

class tcp_connection
  : public std::enable_shared_from_this&amp;lt;tcp_connection&amp;gt;
&amp;#123;
public:
  typedef std::shared_ptr&amp;lt;tcp_connection&amp;gt; pointer;

  static pointer create(boost::asio::io_context&amp;amp; io_context)
  &amp;#123;
    return pointer(new tcp_connection(io_context));
  &amp;#125;

  tcp::socket&amp;amp; socket()
  &amp;#123;
    return socket_;
  &amp;#125;

  void start()
  &amp;#123;
    message_ = make_daytime_string(); // 生成当前时间字符串
    auto self(shared_from_this());    // 获取shared_ptr，延长对象生命周期
    boost::asio::async_write(         // 异步发送数据
        socket_,
        boost::asio::buffer(message_),
        [this, self](const auto&amp;amp; error, size_t bytes) &amp;#123;
            handle_write(error, bytes); // 发送完成后的回调
        &amp;#125;);
  &amp;#125;

private:
  tcp_connection(boost::asio::io_context&amp;amp; io_context)
    : socket_(io_context)
  &amp;#123;
  &amp;#125;

  void handle_write(const boost::system::error_code&amp;amp; /*error*/, size_t /*bytes_transferred*/)
  &amp;#123;
    // 此处可添加发送完成后的逻辑，例如关闭连接
  &amp;#125;

  tcp::socket socket_;
  std::string message_;
&amp;#125;;

class tcp_server
&amp;#123;
public:
  tcp_server(boost::asio::io_context&amp;amp; io_context)
    :io_context_(io_context),
    acceptor_(io_context, tcp::endpoint(tcp::v4(), 13)) // 绑定IPv4地址的13端口
  &amp;#123;
    start_accept(); // 开始异步等待客户端连接
  &amp;#125;

private:
  void start_accept() &amp;#123;
    tcp_connection::pointer new_connection = tcp_connection::create(io_context_);// 创建新连接对象
    acceptor_.async_accept(         // 异步接受连接
        new_connection-&amp;gt;socket(),
        [this, new_connection](const boost::system::error_code&amp;amp; error) &amp;#123;
            // 这里的 this 指向当前 tcp_server 对象
            handle_accept(error, new_connection);
        &amp;#125;
    );
  &amp;#125; 

  void handle_accept(const boost::system::error_code&amp;amp; error, tcp_connection::pointer new_connection)
  &amp;#123;
    if (!error)
    &amp;#123;
      new_connection-&amp;gt;start(); // 启动数据发送流程
    &amp;#125;
    start_accept(); // 继续监听下一个连接
  &amp;#125;

  boost::asio::io_context&amp;amp; io_context_;
  tcp::acceptor acceptor_;
&amp;#125;;

int main()
&amp;#123;
  try
  &amp;#123;
    boost::asio::io_context io_context;      // 创建IO上下文，管理所有异步操作
    tcp_server server(io_context);          // 创建TCP服务器实例，初始化监听
    io_context.run();                       // 启动事件循环，处理异步操作
  &amp;#125;
  catch (std::exception&amp;amp; e)                 // 异常处理
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.what() &amp;lt;&amp;lt; std::endl;
  &amp;#125;
  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;UPD&lt;/h1&gt;
&lt;h2 id=&#34;同步UDP客户端&#34;&gt;同步UDP客户端&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;array&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

using boost::asio::ip::udp;

int main(int argc, char* argv[])
&amp;#123;
  try
  &amp;#123;
    if (argc != 2)
    &amp;#123;
      std::cerr &amp;lt;&amp;lt; &amp;quot;Usage: client &amp;lt;host&amp;gt;&amp;quot; &amp;lt;&amp;lt; std::endl;
      return 1;
    &amp;#125;

    boost::asio::io_context io_context;

    udp::resolver resolver(io_context);
    udp::endpoint receiver_endpoint =
      *resolver.resolve(udp::v4(), argv[1], &amp;quot;daytime&amp;quot;).begin();

    udp::socket socket(io_context);
    socket.open(udp::v4());

    std::array&amp;lt;char, 1&amp;gt; send_buf  = &amp;#123;&amp;#123; 0 &amp;#125;&amp;#125;;
    socket.send_to(boost::asio::buffer(send_buf), receiver_endpoint);

    std::array&amp;lt;char, 128&amp;gt; recv_buf;
    udp::endpoint sender_endpoint;
    size_t len = socket.receive_from(
        boost::asio::buffer(recv_buf), sender_endpoint);

    std::cout.write(recv_buf.data(), len);
  &amp;#125;
  catch (std::exception&amp;amp; e)
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.what() &amp;lt;&amp;lt; std::endl;
  &amp;#125;

  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;异步UDP服务端&#34;&gt;异步UDP服务端&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;array&amp;gt;
#include &amp;lt;ctime&amp;gt;
#include &amp;lt;functional&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;memory&amp;gt;
#include &amp;lt;string&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

using boost::asio::ip::udp;

std::string make_daytime_string()
&amp;#123;
  using namespace std; // For time_t, time and ctime;
  time_t now = time(0);
  return ctime(&amp;amp;now);
&amp;#125;

class udp_server
&amp;#123;
public:
  udp_server(boost::asio::io_context&amp;amp; io_context)
    : socket_(io_context, udp::endpoint(udp::v4(), 13))
  &amp;#123;
    start_receive();
  &amp;#125;

private:
  void start_receive()
  &amp;#123;
    socket_.async_receive_from(
        boost::asio::buffer(recv_buffer_), remote_endpoint_,
        std::bind(&amp;amp;udp_server::handle_receive, this,
          boost::asio::placeholders::error,
          boost::asio::placeholders::bytes_transferred));
  &amp;#125;

  void handle_receive(const boost::system::error_code&amp;amp; error,
      std::size_t /*bytes_transferred*/)
  &amp;#123;
    if (!error)
    &amp;#123;
      std::shared_ptr&amp;lt;std::string&amp;gt; message(
          new std::string(make_daytime_string()));

      socket_.async_send_to(boost::asio::buffer(*message), remote_endpoint_,
          std::bind(&amp;amp;udp_server::handle_send, this, message,
            boost::asio::placeholders::error,
            boost::asio::placeholders::bytes_transferred));

      start_receive();
    &amp;#125;
  &amp;#125;

  void handle_send(std::shared_ptr&amp;lt;std::string&amp;gt; /*message*/,
      const boost::system::error_code&amp;amp; /*error*/,
      std::size_t /*bytes_transferred*/)
  &amp;#123;
  &amp;#125;

  udp::socket socket_;
  udp::endpoint remote_endpoint_;
  std::array&amp;lt;char, 1&amp;gt; recv_buffer_;
&amp;#125;;

int main()
&amp;#123;
  try
  &amp;#123;
    boost::asio::io_context io_context;
    udp_server server(io_context);
    io_context.run();
  &amp;#125;
  catch (std::exception&amp;amp; e)
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.what() &amp;lt;&amp;lt; std::endl;
  &amp;#125;

  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;组合TCP/UDP&lt;/h1&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;array&amp;gt;
#include &amp;lt;ctime&amp;gt;
#include &amp;lt;functional&amp;gt;
#include &amp;lt;iostream&amp;gt;
#include &amp;lt;memory&amp;gt;
#include &amp;lt;string&amp;gt;
#include &amp;lt;boost/asio.hpp&amp;gt;

using boost::asio::ip::tcp;
using boost::asio::ip::udp;

std::string make_daytime_string()
&amp;#123;
  using namespace std; // For time_t, time and ctime;
  time_t now = time(0);
  return ctime(&amp;amp;now);
&amp;#125;

class tcp_connection
  : public std::enable_shared_from_this&amp;lt;tcp_connection&amp;gt;
&amp;#123;
public:
  typedef std::shared_ptr&amp;lt;tcp_connection&amp;gt; pointer;

  static pointer create(boost::asio::io_context&amp;amp; io_context)
  &amp;#123;
    return pointer(new tcp_connection(io_context));
  &amp;#125;

  tcp::socket&amp;amp; socket()
  &amp;#123;
    return socket_;
  &amp;#125;

  void start()
  &amp;#123;
    message_ = make_daytime_string();

    boost::asio::async_write(socket_, boost::asio::buffer(message_),
        std::bind(&amp;amp;tcp_connection::handle_write, shared_from_this()));
  &amp;#125;

private:
  tcp_connection(boost::asio::io_context&amp;amp; io_context)
    : socket_(io_context)
  &amp;#123;
  &amp;#125;

  void handle_write()
  &amp;#123;
  &amp;#125;

  tcp::socket socket_;
  std::string message_;
&amp;#125;;

class tcp_server
&amp;#123;
public:
  tcp_server(boost::asio::io_context&amp;amp; io_context)
    : io_context_(io_context),
      acceptor_(io_context, tcp::endpoint(tcp::v4(), 13))
  &amp;#123;
    start_accept();
  &amp;#125;

private:
  void start_accept()
  &amp;#123;
    tcp_connection::pointer new_connection =
      tcp_connection::create(io_context_);

    acceptor_.async_accept(new_connection-&amp;gt;socket(),
        std::bind(&amp;amp;tcp_server::handle_accept, this, new_connection,
          boost::asio::placeholders::error));
  &amp;#125;

  void handle_accept(tcp_connection::pointer new_connection,
      const boost::system::error_code&amp;amp; error)
  &amp;#123;
    if (!error)
    &amp;#123;
      new_connection-&amp;gt;start();
    &amp;#125;

    start_accept();
  &amp;#125;

  boost::asio::io_context&amp;amp; io_context_;
  tcp::acceptor acceptor_;
&amp;#125;;

class udp_server
&amp;#123;
public:
  udp_server(boost::asio::io_context&amp;amp; io_context)
    : socket_(io_context, udp::endpoint(udp::v4(), 13))
  &amp;#123;
    start_receive();
  &amp;#125;

private:
  void start_receive()
  &amp;#123;
    socket_.async_receive_from(
        boost::asio::buffer(recv_buffer_), remote_endpoint_,
        std::bind(&amp;amp;udp_server::handle_receive, this,
          boost::asio::placeholders::error));
  &amp;#125;

  void handle_receive(const boost::system::error_code&amp;amp; error)
  &amp;#123;
    if (!error)
    &amp;#123;
      std::shared_ptr&amp;lt;std::string&amp;gt; message(
          new std::string(make_daytime_string()));

      socket_.async_send_to(boost::asio::buffer(*message), remote_endpoint_,
          std::bind(&amp;amp;udp_server::handle_send, this, message));

      start_receive();
    &amp;#125;
  &amp;#125;

  void handle_send(std::shared_ptr&amp;lt;std::string&amp;gt; /*message*/)
  &amp;#123;
  &amp;#125;

  udp::socket socket_;
  udp::endpoint remote_endpoint_;
  std::array&amp;lt;char, 1&amp;gt; recv_buffer_;
&amp;#125;;

int main()
&amp;#123;
  try
  &amp;#123;
    boost::asio::io_context io_context;
    tcp_server server1(io_context);
    udp_server server2(io_context);
    io_context.run();
  &amp;#125;
  catch (std::exception&amp;amp; e)
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.what() &amp;lt;&amp;lt; std::endl;
  &amp;#125;

  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;

 &lt;blockquote&gt;
&lt;p&gt;​&lt;strong&gt;编译环境&lt;/strong&gt;：在Wiondows下，使用VScode+WSL2+Ubuntu20.04+GCC编译器&lt;/p&gt;
&lt;/blockquote&gt;
&lt;hr&gt;
&lt;h1&gt;核心命令&lt;/h1&gt;
&lt;h2 id=&#34;项目配置&#34;&gt;项目配置&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;&lt;code&gt;cmake_minimum_required&lt;/code&gt;  指定&lt;code&gt;CMake&lt;/code&gt;的最小版本要求&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;cmake_minimum_required(VERSION 3.10)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;&lt;code&gt;project&lt;/code&gt;  定义项目名称，并可以指定项目使用的编程语言、web主页地址、项目版本号等&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;project(MyProject VERSION 1.0 LANGUAGES CXX)
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;strong&gt;&lt;code&gt;set&lt;/code&gt; 设置变量&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;#方式1 各源文件剪枝空格间隔，并赋值给SOURCE（变量名任取，不要重复即可）变量
set(SOURCES main.cpp foo.cpp bar.cpp)
#方式2 各源文件“；”间隔
set(SOURCES main.cpp;foo.cpp;bar.cpp)
# 使用变量，采用$&amp;#123;&amp;#125;方式
add_executable(MyExecutable $&amp;#123;SOURCES&amp;#125;)
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;&lt;strong&gt;指定使用&lt;code&gt;c++&lt;/code&gt;标准&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;命令行编译时使用c++标准，通过&lt;code&gt;-std=c++11&lt;/code&gt;格式指定&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;    g++  -std=c++11 -o demo main.cpp
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;&lt;strong&gt;通过&lt;code&gt;set&lt;/code&gt;命令指定&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;CMake文件指定c++标准&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;set(CMAKE_CXX_STANDARD 11)
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;&lt;strong&gt;通过&lt;code&gt;project&lt;/code&gt;命令指定&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;project(MyProject VERSION 1.0 LANGUAGES CXX CXX_STANDARD 11)
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;&lt;strong&gt;&lt;code&gt;C++&lt;/code&gt;标准对应有宏&lt;code&gt;-DCMAKE_CXX_STANDARD&lt;/code&gt;，通过&lt;code&gt;cmake&lt;/code&gt;命令指定&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;cmake -DCMAKE_CXX_STANDARD=11 ..  # 注意，..表示上一级目录，指定到CMakeLists.txt所在的目录
&lt;/code&gt;&lt;/pre&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;变量名&lt;/th&gt;
&lt;th&gt;描述&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;CMAKE_SOURCE_DIR&lt;/td&gt;
&lt;td&gt;&lt;code&gt;CMakeLists.txt&lt;/code&gt;所在的目录&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;CMAKE_BINARY_DIR&lt;/td&gt;
&lt;td&gt;构建目录&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;CMAKE_CURRENT_SOURCE_DIR&lt;/td&gt;
&lt;td&gt;当前&lt;code&gt;CMakeLists.txt&lt;/code&gt;所在的目录&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;CMAKE_CURRENT_BINARY_DIR&lt;/td&gt;
&lt;td&gt;当前构建目录&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;CMAKE_CURRENT_LIST_DIR&lt;/td&gt;
&lt;td&gt;当前&lt;code&gt;CMakeLists.txt&lt;/code&gt;所在的目录&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;PROJECT_SOURCE_DIR&lt;/td&gt;
&lt;td&gt;表示项目根目录&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;PROJECT_BINARY_DIR&lt;/td&gt;
&lt;td&gt;表示项目构建目录&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;PROJECT_NAME&lt;/td&gt;
&lt;td&gt;表示项目名称&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;CMAKE_CXX_STANDARD&lt;/td&gt;
&lt;td&gt;表示C++标准&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;hr&gt;
&lt;h2 id=&#34;文件管理&#34;&gt;文件管理&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;指定输出路径&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;在CMake中指定可执行程序输出的路径，也有对应的宏，叫做&lt;code&gt;EXECUTABLE_OUTPUT_PATH&lt;/code&gt;，可通过&lt;code&gt;set&lt;/code&gt;命令指定，例如：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;set(HOME /home/zhang/Linux)
set(EXECUTABLE_OUTPUT_PATH $&amp;#123;HOME&amp;#125;/bin)
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;第一行：定义一个变量存储一个路径&lt;/li&gt;
&lt;li&gt;第二行：将拼接好的路径赋值给&lt;code&gt;EXECUTABLE_OUTPUT_PATH&lt;/code&gt;变量&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;strong&gt;搜索文件&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;code&gt;aux_source_group&lt;/code&gt; 查找&lt;code&gt;某路径&lt;/code&gt;下的&lt;code&gt;所有源文件&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;aux_source_group(&amp;quot;Source Files&amp;quot; variable)
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;Source Files&lt;/code&gt;：表示搜索的文件所在的目录名称&lt;/li&gt;
&lt;li&gt;&lt;code&gt;variable&lt;/code&gt;：将&lt;code&gt;Source Files&lt;/code&gt;目录下搜索到的源文件列表赋值给&lt;code&gt;variable&lt;/code&gt;变量&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;&lt;strong&gt;&lt;code&gt;aux_source_group&lt;/code&gt;查找文件&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;# aux_source_group($&amp;#123;PROJECT_SOURCE_DIR&amp;#125;/src SRC_LIST)  
aux_source_group($&amp;#123;CMAKE_CURRENT_SOURCE_DIR&amp;#125;/src SRC_LIST)
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;PROJECT_SOURCE_DIR&lt;/code&gt;：表示项目根目录&lt;/li&gt;
&lt;li&gt;&lt;code&gt;CMAKE_CURRENT_SOURCE_DIR&lt;/code&gt;：表示当前&lt;code&gt;CMakeLists.txt&lt;/code&gt;所在的目录&lt;br&gt;
搜索&lt;code&gt;CMakeLists.txt&lt;/code&gt;所在的目录&lt;code&gt;src&lt;/code&gt;下所有源文件，并将结果赋值给&lt;code&gt;SRC_LIST&lt;/code&gt;变量。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;&lt;strong&gt;&lt;code&gt;file&lt;/code&gt;查找文件&lt;/strong&gt;&lt;br&gt;
使用&lt;code&gt;file&lt;/code&gt;命令，查找某路径下的&lt;code&gt;某格式文件&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;file(GLOB/GLOB_RECURSE 变量名 要搜索文件路径和文件类型)
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;GLOB&lt;/code&gt;：表示搜索指定目录下所有文件,将满足条件的文件列表赋值给变量&lt;/li&gt;
&lt;li&gt;&lt;code&gt;GLOB_RECURSE&lt;/code&gt;：表示递归搜索指定目录下所有文件,将满足条件的文件列表赋值给变量&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;&lt;strong&gt;包含头文件&lt;/strong&gt;&lt;br&gt;
在编译项目源文件时，需要将源文件对应的头文件包含进来，cmake 提供了&lt;code&gt;include_directories&lt;/code&gt;命令，用于指定头文件的搜索路径：&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;include_directories(headpath)
&lt;/code&gt;&lt;/pre&gt;
&lt;hr&gt;
&lt;h1&gt;构建控制&lt;/h1&gt;
&lt;h2 id=&#34;编译选项&#34;&gt;编译选项&lt;/h2&gt;
&lt;p&gt;在CMake中，可以通过&lt;code&gt;option&lt;/code&gt;命令来定义编译选项，例如：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;option(USE_OPENMP &amp;quot;Use OpenMP for parallelization&amp;quot; ON)
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;USE_OPENMP&lt;/code&gt;：表示编译选项的名称&lt;/li&gt;
&lt;li&gt;&lt;code&gt;Use OpenMP for parallelization&lt;/code&gt;：表示编译选项的描述&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;链接控制&#34;&gt;链接控制&lt;/h2&gt;
&lt;p&gt;在CMake中，可以通过&lt;code&gt;target_link_libraries&lt;/code&gt;命令来指定链接库，例如：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;target_link_libraries(&amp;lt;TARGET&amp;gt;  PRIVATE MyLibrary)
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;TARGET&lt;/code&gt;：需要链接库的目标&lt;/li&gt;
&lt;li&gt;&lt;code&gt;PRIVATE&lt;/code&gt;：表示链接库的作用域，可以是&lt;code&gt;PRIVATE&lt;/code&gt;、&lt;code&gt;PUBLIC&lt;/code&gt;、&lt;code&gt;INTERFACE&lt;/code&gt;之一&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h1&gt;工程实践&lt;/h1&gt;
&lt;h2 id=&#34;标准结构&#34;&gt;标准结构&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;# CMakeLists.txt
cmake_minimum_required(VERSION 3.10)
project(MyProject LANGUAGES CXX)

# 添加源文件
set(SOURCES main.cpp foo.cpp bar.cpp)
add_executable(MyExecutable $&amp;#123;SOURCES&amp;#125;)

# 添加头文件搜索路径

include_directories($&amp;#123;CMAKE_SOURCE_DIR&amp;#125;/include)

# 添加链接库
target_link_libraries(MyExecutable PRIVATE MyLibrary)
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;构建流程&#34;&gt;构建流程&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;mkdir build
cd build
cmake ..
make
&lt;/code&gt;&lt;/pre&gt;
&lt;hr&gt;
&lt;h1&gt;动静态库&lt;/h1&gt;
&lt;h2 id=&#34;生成静态库&#34;&gt;生成静态库&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;add_library&lt;/code&gt;命令用于创建库，其语法如下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;# 静态库
add_library(MyLibrary STATIC [源文件1] [源文件2])

# 动态库
add_library(MyLibrary SHARED  [源文件1] [源文件2])
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;MyLibrary&lt;/code&gt;为生成&lt;code&gt;动静态&lt;/code&gt;的&lt;code&gt;库名&lt;/code&gt;，完整动静态文件名包含三部分：&lt;code&gt;lib&lt;/code&gt;+&lt;code&gt;库名&lt;/code&gt;+&lt;code&gt;扩展名&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;SHARED&lt;/code&gt;：表示生成动态库，动态库扩展名为&lt;code&gt;.so&lt;/code&gt;(Linux)、&lt;code&gt;dll&lt;/code&gt;(Windows)&lt;/p&gt;
&lt;p&gt;&lt;code&gt;STATIC&lt;/code&gt;：表示生成静态库，静态库扩展名为&lt;code&gt;.a&lt;/code&gt;(Linux)、&lt;code&gt;lib&lt;/code&gt;(Windows)&lt;/p&gt;
&lt;p&gt;&lt;code&gt;静态库&lt;/code&gt;默认不具有可执行权限，所以指定静态库路径的时候不可以使用&lt;code&gt;EXECUTABLE_OUTPUT_PATH&lt;/code&gt;，而应该使用&lt;code&gt;LIBRARY_OUTPUT_PATH&lt;/code&gt;，这个宏对于动态库和静态库都有效。&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;&lt;strong&gt;类别&lt;/strong&gt;&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;&lt;strong&gt;编译&lt;/strong&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;strong&gt;静态库&lt;/strong&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;编译时链接&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;strong&gt;动态库&lt;/strong&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;运行时链接&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;使用动静态库&#34;&gt;使用动静态库&lt;/h2&gt;
&lt;p&gt;链接&lt;strong&gt;动静态&lt;/strong&gt;库，需要使用&lt;code&gt;link_libraries&lt;/code&gt;命令&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;link_libraries(&amp;lt;static lib&amp;gt; [&amp;lt;static lib&amp;gt;...])

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;参数1&lt;/code&gt; 指定要链接静态库的名字，可以是文件全名，也可以是文件名（不带&lt;code&gt;lib&lt;/code&gt;前缀和扩展名&lt;code&gt;.a&lt;/code&gt;）&lt;br&gt;
&lt;code&gt;参数2&lt;/code&gt; 要链接的其他静态库的名字&lt;/p&gt;
&lt;p&gt;**注意：**如果该静态库不是系统提供的（自己制作或第三方提供静态库）可能出现找不到的情况，需要指定静态库的路径&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;link_directories(&amp;lt;path&amp;gt;)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;参数&lt;/code&gt; 指定静态库的路径&lt;/p&gt;
&lt;p&gt;&lt;code&gt;target_link_libraries&lt;/code&gt; 用于将动态库链接到目标可执行文件（因此位于&lt;code&gt;add_executable&lt;/code&gt;或&lt;code&gt;add_library&lt;/code&gt;命令之后）&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;target_link_libraries(&amp;lt;target&amp;gt; [PRIVATE|PUBLIC|INTERFACE] &amp;lt;item&amp;gt;...)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;&amp;lt;target&amp;gt;&lt;/code&gt;：表示目标可执行文件或库的名称&lt;br&gt;
&lt;code&gt;[PRIVATE|PUBLIC|INTERFACE]&lt;/code&gt;：表示链接库的访问权限，默认为&lt;code&gt;PUBLIC&lt;/code&gt;,可以是&lt;code&gt;PRIVATE&lt;/code&gt;、&lt;code&gt;PUBLIC&lt;/code&gt;、&lt;code&gt;INTERFACE&lt;/code&gt;之一&lt;br&gt;
&lt;code&gt;&amp;lt;item&amp;gt;&lt;/code&gt;：表示要链接的库的名称，可以是库的名称，也可以是库的路径&lt;/p&gt;
&lt;p&gt;&lt;code&gt;动态库&lt;/code&gt;：具有传递性，即链接动态库的库，也会链接动态库所依赖的动态库，例如：如果&lt;code&gt;动态库A&lt;/code&gt;链接&lt;code&gt;动态库B、C&lt;/code&gt;，&lt;code&gt;动态库D&lt;/code&gt;链接&lt;code&gt;动态库A&lt;/code&gt;，此时链接&lt;code&gt;动态库D&lt;/code&gt;相当于链接了&lt;code&gt;动态库B、C&lt;/code&gt;中定义的方法。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;target_link_libraries(A B C)
target_link_libraries(D A)
&lt;/code&gt;&lt;/pre&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;&lt;strong&gt;权限&lt;/strong&gt;&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;&lt;strong&gt;描述&lt;/strong&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;PRIVATE&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;private后面的库仅被link前面的target中，并且终结掉，第三方库不能感知&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;PUBLIC&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;public后面的库会被link到前面的target中，并且里面的符号会被导出，提供给第三方&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;INTERFACE&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;interface 后面引入的库不会被连接到前面的target中，只会导出符号&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;hr&gt;
&lt;h1&gt;进阶技巧&lt;/h1&gt;
&lt;h2 id=&#34;条件判断&#34;&gt;条件判断&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;&lt;code&gt;if&lt;/code&gt;&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;if (EXISTS $&amp;#123;CMAKE_SOURCE_DIR&amp;#125;/include)
    include_directories($&amp;#123;CMAKE_SOURCE_DIR&amp;#125;/include)
endif()
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;&lt;code&gt;elseif&lt;/code&gt;&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;if (EXISTS $&amp;#123;CMAKE_SOURCE_DIR&amp;#125;/include)
    include_directories($&amp;#123;CMAKE_SOURCE_DIR&amp;#125;/include)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;foreach&lt;/code&gt;命令用于循环&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;foreach(&amp;lt;loop_var&amp;gt; &amp;lt;items&amp;gt;)
    &amp;lt;commands&amp;gt;
endforeach()
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;&amp;lt;loop_var&amp;gt;&lt;/code&gt;：表示循环变量&lt;/p&gt;
&lt;h2 id=&#34;日志&#34;&gt;日志&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;message&lt;/code&gt;命令用于输出日志信息，其语法如下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;message(&amp;lt;mode&amp;gt; &amp;quot;message to display&amp;quot; ...)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;&amp;lt;mode&amp;gt;&lt;/code&gt;：表示输出信息的模式，可以是&lt;code&gt;（空）&lt;/code&gt;、&lt;code&gt;STATUS&lt;/code&gt;、&lt;code&gt;WARNING&lt;/code&gt;、&lt;code&gt;AUTHOR_WARNING&lt;/code&gt;、&lt;code&gt;SEND_ERROR&lt;/code&gt;、&lt;code&gt;FATAL_ERROR&lt;/code&gt;、&lt;code&gt;DEPRECATION&lt;/code&gt;之一&lt;br&gt;
&lt;code&gt;&amp;quot;message to display&amp;quot;&lt;/code&gt;：表示要输出的信息&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;&lt;strong&gt;模式&lt;/strong&gt;&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;&lt;strong&gt;输出信息&lt;/strong&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;(空)&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;输出重要信息&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;STATUS&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;输出普通信息&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;WARNING&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;输出警告信息&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;AUTHOR_WARNING&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;输出作者警告信息&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;SEND_ERROR&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;输出错误信息，继续执行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;FATAL_ERROR&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;输出错误信息，终止执行&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;DEPRECATION&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;输出弃用信息&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;CMake 命令行工具会在stdout上显示STATUS消息，在stderr上显示其他消息。CMake GUI工具会在消息窗口中显示所有消息。&lt;/p&gt;
&lt;h2 id=&#34;变量操作&#34;&gt;变量操作&lt;/h2&gt;
&lt;p&gt;有时候项目源文件比较多并且不再同一目录下，这些源文件需要一起编译生成可执行文件，我们可以通过&lt;code&gt;file&lt;/code&gt;命令对各自目录下的源文件进行搜索，最后还需要做一个字符串拼接操作，关于字符串拼接可以使用&lt;code&gt;set&lt;/code&gt;命令也可以使用&lt;code&gt;list&lt;/code&gt;命令。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;&lt;code&gt;set&lt;/code&gt;命令&lt;/strong&gt;&lt;br&gt;
&lt;code&gt;set&lt;/code&gt;命令用于设置变量的值，其语法如下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;
# 取出$&amp;#123;&amp;#125;中变量的字符串---&amp;gt;拼接字符串---&amp;gt;赋值给变量
set(&amp;lt;变量名&amp;gt; $&amp;#123;变量名1&amp;#125; $&amp;#123;变量名2&amp;#125;... )

# 将string1 string2...的字符串拼接---&amp;gt;赋值给变量
set(&amp;lt;变量名&amp;gt; string1 string2... )
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;set实际是字符串拼接，该命令是将&lt;code&gt;变量名1&lt;/code&gt;、&lt;code&gt;变量名2&lt;/code&gt;…的值进行拼接并赋值给&lt;code&gt;变量名&lt;/code&gt;，如果&lt;code&gt;变量名&lt;/code&gt;已经存在，则覆盖其值，如果&lt;code&gt;变量名&lt;/code&gt;不存在，则创建该变量。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;&lt;code&gt;list&lt;/code&gt;命令&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;字符串拼接&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;list(APPEND &amp;lt;list&amp;gt; [args...])
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;APPEND&lt;/code&gt;：将&lt;code&gt;args&lt;/code&gt;字符串依次添加到&lt;code&gt;list&lt;/code&gt;的末尾，&lt;code&gt;APPEND&lt;/code&gt;之后写法与&lt;code&gt;set&lt;/code&gt;一致，与&lt;code&gt;set&lt;/code&gt;命令不同的是，&lt;code&gt;list&lt;/code&gt;命令不会覆盖&lt;code&gt;list&lt;/code&gt;的值，而是将&lt;code&gt;args&lt;/code&gt;字符串依次添加到&lt;code&gt;list&lt;/code&gt;的末尾。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;字符串移除&lt;/strong&gt;&lt;br&gt;
当通过&lt;code&gt;file&lt;/code&gt;查找某个目录下的所有源文件时，其中有些使我们不需要的，例如下面的main.cpp&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-shell&#34;&gt;$ tree
.
├── add.cpp
├── div.cpp
├── main.cpp
├── mult.cpp
└── sub.cpp
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;其中&lt;code&gt;main&lt;/code&gt;是测试文件，如果我们想把计算器相关的源文件生成动态库给别人使用，只需要&lt;code&gt;add.cpp&lt;/code&gt;、&lt;code&gt;div.cpp&lt;/code&gt;、&lt;code&gt;mult.cpp&lt;/code&gt;、&lt;code&gt;sub.cpp&lt;/code&gt;这四个文件，那么我们可以通过&lt;code&gt;list&lt;/code&gt;命令将&lt;code&gt;main.cpp&lt;/code&gt;移除。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;list(REMOVE_ITEM &amp;lt;list&amp;gt; [value...])
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;REMOVE_ITEM&lt;/code&gt;：将&lt;code&gt;list&lt;/code&gt;中所有&lt;code&gt;value&lt;/code&gt;字符串移除。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;字符串查找&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;list(FIND &amp;lt;list&amp;gt; &amp;lt;value&amp;gt; &amp;lt;variable&amp;gt;)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;FIND&lt;/code&gt;：在&lt;code&gt;list&lt;/code&gt;中查找&lt;code&gt;value&lt;/code&gt;字符串，如果找到，则将&lt;code&gt;value&lt;/code&gt;字符串在&lt;code&gt;list&lt;/code&gt;中的索引赋值给&lt;code&gt;variable&lt;/code&gt;，如果未找到，则将&lt;code&gt;-1&lt;/code&gt;赋值给&lt;code&gt;variable&lt;/code&gt;。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;字符串替换&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;list(REPLACE &amp;lt;list&amp;gt; &amp;lt;value&amp;gt; &amp;lt;newvalue&amp;gt;)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;REPLACE&lt;/code&gt;：将&lt;code&gt;list&lt;/code&gt;中所有&lt;code&gt;value&lt;/code&gt;字符串替换为&lt;code&gt;newvalue&lt;/code&gt;字符串。&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;&lt;strong&gt;命令&lt;/strong&gt;&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;&lt;strong&gt;描述&lt;/strong&gt;&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;&lt;strong&gt;使用示例&lt;/strong&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;APPEND&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;将args添加到列表的末尾&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(APPEND &amp;lt;list&amp;gt; [args...])&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;APPEND_STRING&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;将args添加到列表的末尾&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(APPEND_STRING &amp;lt;list&amp;gt; [args...])&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;APPEND_UNIQUE&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;将args添加到列表的末尾，如果args已经存在，则不添加&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(APPEND_UNIQUE &amp;lt;list&amp;gt; [args...])&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;CLEAR&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;清除列表&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(CLEAR &amp;lt;list&amp;gt;)&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;GET&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;获取列表中的元素&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(GET &amp;lt;list&amp;gt; [&amp;lt;index&amp;gt;...]  [&amp;lt;output variable&amp;gt;...])&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;INSERT&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;在&lt;code&gt;列表&lt;/code&gt;中的&lt;code&gt;某一位置&lt;/code&gt;插入(&lt;em&gt;索引前插入&lt;/em&gt;)&lt;code&gt;元素&lt;/code&gt;得到&lt;code&gt;新字符串&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(INSERT &amp;lt;list&amp;gt; &amp;lt;index&amp;gt; [&amp;lt;index&amp;gt;...] [&amp;lt;output variable&amp;gt;...])&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;LENGTH&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;获取列表的长度并赋值给&lt;code&gt;变量&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(LENGTH &amp;lt;list&amp;gt; &amp;lt;variable&amp;gt;)&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;POP_BACK&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除&lt;code&gt;列表&lt;/code&gt;中的最后一个元素获取&lt;code&gt;新字符串&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(POP_BACK &amp;lt;list&amp;gt; [&amp;lt;output variable&amp;gt;...])&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;POP_FRONT&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除&lt;code&gt;列表&lt;/code&gt;中的第一个元素获取&lt;code&gt;新字符串&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(POP_FRONT &amp;lt;list&amp;gt; [&amp;lt;output variable&amp;gt;...])&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;PREPEND&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;将args添加到列表的开头&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(PREPEND &amp;lt;list&amp;gt; [args...])&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;REMOVE_AT&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除&lt;code&gt;列表&lt;/code&gt;中的&lt;code&gt;某一位置&lt;/code&gt;的元素获取&lt;code&gt;新字符串&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(REMOVE_AT &amp;lt;list&amp;gt; [&amp;lt;index&amp;gt;...] [&amp;lt;output variable&amp;gt;...])&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;REMOVE_ITEM&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除&lt;code&gt;列表&lt;/code&gt;中所有&lt;code&gt;value&lt;/code&gt;字符串&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(REMOVE_ITEM &amp;lt;list&amp;gt; [value...])&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;REMOVE_DUPLICATES&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除&lt;code&gt;列表&lt;/code&gt;中重复的元素&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(REMOVE_DUPLICATES &amp;lt;list&amp;gt;)&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;JOIN&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;将&lt;code&gt;列表&lt;/code&gt;中的元素用&lt;code&gt;连接符&lt;/code&gt;连接成一个&lt;code&gt;新字符串&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(JOIN &amp;lt;list&amp;gt; &amp;lt;glue&amp;gt; &amp;lt;output variable&amp;gt;)&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;REVERSE&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;将&lt;code&gt;列表&lt;/code&gt;中的元素反转&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(REVERSE &amp;lt;list&amp;gt;)&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;SORT&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;将&lt;code&gt;列表&lt;/code&gt;中的元素排序&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;list(SORT &amp;lt;list&amp;gt;)&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;宏定义&#34;&gt;宏定义&lt;/h2&gt;
&lt;p&gt;在程序测试中，我们经常需要定义一些宏，例如&lt;code&gt;DEBUG&lt;/code&gt;，通过这些宏来控制程序是否打印调试信息&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;
#include &amp;lt;iostream&amp;gt;
#define DEBUG
int main()&amp;#123;
  int n =10;
  #ifdef DEBUG
      std::cout &amp;lt;&amp;lt; &amp;quot;debug n=&amp;quot; &amp;lt;&amp;lt; n &amp;lt;&amp;lt; std::endl;
  #endif
  return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;程序通过&lt;code&gt;#ifdef DEBUG&lt;/code&gt;判断&lt;code&gt;DEBUG&lt;/code&gt;是否被定义，如果被定义，则打印调试信息。如果没有被定义，则不打印调试信息，该端代码相当于被注释掉了，因此无法看到日志输出。&lt;/p&gt;
&lt;p&gt;为了使得&lt;code&gt;c++&lt;/code&gt;测试更加方便，我们可以不在代码中定义宏，在&lt;code&gt;g++/gcc&lt;/code&gt; 命令中定义宏，例如&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;g++ -DDEBUG main.cpp -o main
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;g++/gcc&lt;/code&gt;命令通过&lt;code&gt;-D&lt;/code&gt;指定定义宏的名字，这样在代码中就可以使用&lt;code&gt;DEBUG&lt;/code&gt;宏了。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;&lt;code&gt;CMake&lt;/code&gt;中使用&lt;code&gt;add_definitions&lt;/code&gt;定义宏&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;add_definitions(-DDEBUG)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;add_definitions&lt;/code&gt;命令用于定义宏，其中&lt;code&gt;-D&lt;/code&gt;是&lt;code&gt;g++/gcc&lt;/code&gt;命令的参数，&lt;code&gt;DEBUG&lt;/code&gt;是宏的名字。&lt;/p&gt;
&lt;h2 id=&#34;嵌套CMake&#34;&gt;嵌套CMake&lt;/h2&gt;
&lt;p&gt;在Linux的目录是树状结构，所以嵌套CMake也是树状结构，最顶层的CMakeLists.txt文件称为&lt;code&gt;根节点&lt;/code&gt;，其他CMakeLists.txt文件称为&lt;code&gt;子节点&lt;/code&gt;。需要了解关于&lt;code&gt;CMakeLists.txt&lt;/code&gt;的几个信息：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;根节点的&lt;code&gt;CMakeLists.txt&lt;/code&gt;中定义变量全局有效。&lt;/li&gt;
&lt;li&gt;父节点的&lt;code&gt;CMakeLists.txt&lt;/code&gt;中定义的变量，子节点可以访问。&lt;/li&gt;
&lt;li&gt;子节点的&lt;code&gt;CMakeLists.txt&lt;/code&gt;中定义的变量，父节点无法访问。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;添加子目录&lt;/strong&gt;&lt;br&gt;
CMake中父子节点是如何建立的？&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;add_subdirectory(source_dir [binary_dir] [EXCLUDE_FROM_ALL])
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;source_dir&lt;/code&gt;:子目录的路径，&lt;br&gt;
&lt;code&gt;binary_dir&lt;/code&gt;:指定输出文件的路径，一般不需要指定，默认即可。&lt;br&gt;
&lt;code&gt;EXCLUDE_FROM_ALL&lt;/code&gt;:在子路径下的目标默认不会被包含到父路径的&lt;code&gt;ALL&lt;/code&gt;目标中，并且也会排除在IDE工程文件之外。用户必须显式构建在子路径下的目标。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;获取父目录的路径&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cmake&#34;&gt;get_filename_component(PARENT_DIR $&amp;#123;CMAKE_CURRENT_SOURCE_DIR&amp;#125; PATH)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;get_filename_component&lt;/code&gt;命令用于获取文件路径，其中&lt;code&gt;PARENT_DIR&lt;/code&gt;是变量名，&lt;code&gt;$&amp;#123;CMAKE_CURRENT_SOURCE_DIR&amp;#125;&lt;/code&gt;是当前目录的路径，&lt;code&gt;PATH&lt;/code&gt;表示获取路径。&lt;/p&gt;

 &lt;blockquote&gt;
&lt;p&gt;​&lt;strong&gt;环境配置方式&lt;/strong&gt;：🚀 整个过程采用远程的方式，记录树莓派部署&lt;code&gt;YOLOv5s&lt;/code&gt;的过程。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;准备：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;树莓派5-4B&lt;/li&gt;
&lt;li&gt;树莓派系统（安装的官方64位系统）&lt;/li&gt;
&lt;li&gt;USB摄像头&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;h1&gt;获取yolov5s.pt权值文件&lt;/h1&gt;
&lt;p&gt;使用的是轻量的&lt;code&gt;yolov5s&lt;/code&gt;模型,在本地训练后，通过命令发送发到树莓派上:&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;首先查看树莓派地址：&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;    ifconfig  # 查看地址
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;/images/13.webp&#34; alt=&#34;&#34;&gt;&lt;br&gt;
连接的wify，可以看到所属的地址端口。&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;将本地训练好的&lt;code&gt;yolov5s.pt&lt;/code&gt;权值文件发送到树莓派上：&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;    scp yolov5s.pt &amp;lt;用户名&amp;gt;@&amp;lt;树莓派地址&amp;gt;:&amp;lt;保存文件地址&amp;gt;  
&lt;/code&gt;&lt;/pre&gt;
&lt;hr&gt;
&lt;h1&gt;树莓派环境搭建&lt;/h1&gt;
&lt;p&gt;本打算参考其他博主的方法，将&lt;code&gt;pt&lt;/code&gt;权值文件转为&lt;code&gt;ONNX&lt;/code&gt;再利用&lt;code&gt;OpenVINO&lt;/code&gt;转为IR模型部署到树莓派上。&lt;/p&gt;
&lt;p&gt;在本地成功得到&lt;code&gt;IR&lt;/code&gt;模型后，树莓派配置&lt;code&gt;OpenVINO&lt;/code&gt;环境加速推理时，遇到问题有点多😤，准备有空再进行尝试。&lt;/p&gt;
&lt;p&gt;树莓派中运行yolov5s的环境使用&lt;code&gt;Anaconda&lt;/code&gt;配置和管理，步骤如下：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;安装Anaconda&lt;/li&gt;
&lt;li&gt;创建虚拟环境&lt;/li&gt;
&lt;li&gt;下载yolov5源码&lt;/li&gt;
&lt;li&gt;安装依赖库&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;安装Anaconda🌱&lt;br&gt;
下载并安装Anaconda以管理Python环境,分别在终端执行：&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;wget https://repo.anaconda.com/archive/Anaconda3-2021.05-Linux-x86_64.sh
bash Anaconda3-2021.05-Linux-x86_64.sh
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;创建虚拟环境并安装YOLOv5 🌱&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;    conda create -n yolov5 python=3.9 -y                # 创建名为yolov5的虚拟环境，并指定Python版本为3.9
    conda activate yolov5                               # 激活虚拟环境
    git clone https://github.com/ultralytics/yolov5.git # 克隆YOLOv5源码
    cd yolov5
    pip install -r requirements.txt                     # 安装YOLOv5所需的依赖库
&lt;/code&gt;&lt;/pre&gt;
&lt;hr&gt;
&lt;h1&gt;检测图片&lt;/h1&gt;
&lt;ol&gt;
&lt;li&gt;运行程序🌱&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;    python detect.py \
    --weights yolov5s.pt \   # 没有准备可省略该行，自动下载官方权值文件
    --img 320 \              # 指定图片大小，压缩图片，加快检测速度，但是清晰度降低
    --source /image/1.jpg \  # 指定图片路径
    --device cpu \           # 使用cpu进行推理
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;使用的cpu进行推理，速度较慢，看资料显示树莓派也是有GPU的，但是因为树莓派GPU的算力太低，所以还是使用cpu进行推理，如果想使用GPU进行推理，需要安装&lt;code&gt;CUDA&lt;/code&gt;，而且树莓派安装&lt;code&gt;CUDA&lt;/code&gt;比较麻烦。&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;检测效果如下🌱：&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;/images/12.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;hr&gt;
&lt;h1&gt;开启摄像头实时检测&lt;/h1&gt;
&lt;p&gt;🍋检测视频流，遇到无法弹出实时检测界面，这让之前的工作毫无成就感😳，之后通过安装&lt;code&gt;lightdm&lt;/code&gt;来解决的。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;lightdm&lt;/code&gt; 能够提供图形界面服务，使 &lt;code&gt;OpenCV&lt;/code&gt; &lt;code&gt;cv2.imshow()&lt;/code&gt; 能通过 &lt;code&gt;VNC&lt;/code&gt; 的虚拟显示端口渲染窗口。&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;安装&lt;code&gt;lightdm&lt;/code&gt;🌱&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;    sudo apt install lightdm                # 安装图形界面管理器
    sudo dpkg-reconfigure lightdm          # 绑定显示服务到 VNC
    sudo systemctl restart lightdm          # 重启服务使配置生效
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;查看摄像头🌱&lt;br&gt;
使用&lt;code&gt;v4l2-ctl&lt;/code&gt;指令查看所有视频设备&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;    v4l2-ctl --list-devices
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;/images/11.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;可以看到识别到的USB摄像头&lt;code&gt;/dev/video0&lt;/code&gt;、&lt;code&gt;/dev/video1&lt;/code&gt;，使用&lt;code&gt;0&lt;/code&gt;作为&lt;code&gt;source&lt;/code&gt;参数。&lt;/p&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;运行程序🌱&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;    python detect.py \
    --weights yolov5s.pt \
    --source 0 \             # 使用摄像头（0 表示第一个摄像头）
    --view-img \             # 启用实时画面显示--img-size 320
    --device cpu
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;检测效果如下🌱：&lt;/li&gt;
&lt;/ol&gt;
&lt;video width=&#34;100%&#34; controls loading=&#34;lazy&#34;&gt;
  &lt;source src=&#34;/videos/2.mp4&#34; type=&#34;video/mp4&#34;&gt;
&lt;/video&gt;
&lt;p&gt;🍀最终，通过远程的方式，在树莓派上成功部署了&lt;code&gt;yolov5s&lt;/code&gt;模型，实现了实时检测的功能。检测速度差不多8-9帧/s，后续会尝试加速推理。&lt;/p&gt;

 &lt;h1&gt;git基本使用&lt;/h1&gt;
&lt;ol&gt;
&lt;li&gt;git clone 拉取仓库项目&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git clone https://github.com/xxx/xxx.git  #拉取所有分支

git branch -a  #查看所有分支
git checkout -b main  #切换到main分支
git pull origin main  #拉取远程仓库main分支
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;git add 添加文件到暂存区（一般修改后执行）&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git filename  #修改
# 或者添加所有文件
git add .  #
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;git commit 提交文件到本地仓库&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git commit -m &amp;quot;提交信息&amp;quot;  #补充修改日志信息
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;git push 推送文件到远程仓库&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git push origin main  #推送到远程仓库main分支
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;git pull 拉取远程仓库文件&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git pull origin main  #拉取远程仓库main分支
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;git status 查看当前状态&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git status  #查看当前状态
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;7&#34;&gt;
&lt;li&gt;git branch 查看分支&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git branch  #查看本地分支
git branch -r  #查看远程分支
git branch -a  #查看所有分支
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;8&#34;&gt;
&lt;li&gt;git checkout 切换分支&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git checkout main  #切换到main分支
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;9&#34;&gt;
&lt;li&gt;git merge 合并分支&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git merge feature/new-dashboard  #合并feature/new-dashboard分支到当前分支
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;10&#34;&gt;
&lt;li&gt;git branch -d 删除分支&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git branch -d feature/new-dashboard  #删除feature/new-dashboard分支
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;11&#34;&gt;
&lt;li&gt;git log 查看提交记录&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git log  #查看提交记录
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;12&#34;&gt;
&lt;li&gt;git reset 回退版本&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git reset --hard HEAD^  #回退到上一个版本
git reset --hard HEAD~100  #回退到前100个版本
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;📌流程&lt;/h1&gt;
&lt;ol&gt;
&lt;li&gt;克隆仓库并初始化&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;# 克隆仓库到本地（仅检出主分支）
git clone https://github.com/xxx/xxx.git
cd xxx

# 查看所有分支（包括远程分支）
git branch -a
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;创建并切换到功能分支&lt;br&gt;
&lt;strong&gt;创建并切换到新分支（推荐命名格式：feature/xxx）&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git checkout -b feature/new-dashboard
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;分支命名建议	示例&lt;br&gt;
新功能	&lt;code&gt;feature/payment-success&lt;/code&gt;&lt;br&gt;
Bug修复	&lt;code&gt;bugfix/validate-input&lt;/code&gt;&lt;br&gt;
紧急修复	&lt;code&gt;hotfix/ssl-issue&lt;/code&gt;&lt;/p&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;开发并提交代码&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;# 添加修改文件到暂存区
git add .
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;#提交代码（遵循Conventional Commits规范）
git commit -m &amp;quot;feat: add user dashboard&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;推送功能分支到远程仓库&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;# 绑定并推送分支（首次推送必须加-u）
git push -u origin feature/new-dashboard
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;切回主分支并同步最新代码&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;# 切换到主分支
git checkout main

# 拉取远程主分支更新
git pull origin main
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;合并功能分支到主分支&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;# 合并本地分支到主分支
git merge feature/new-dashboard

# ⚠️ 冲突处理：
# 手动编辑冲突文件后执行：
git add conflicted-file.txt
git commit -m &amp;quot;Resolve merge conflicts&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;7&#34;&gt;
&lt;li&gt;提交合并后的主分支&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;# 推送主分支更新
git push origin main
8. 删除本地功能分支（可选）
git branch -d feature/new-dashboard
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;🔐 关键细节与最佳实践&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;分支命名规范（必须遵守）&lt;br&gt;
分支类型	命名规则	示例&lt;br&gt;
新功能	&lt;code&gt;feature/&lt;/code&gt; + 功能描述	&lt;code&gt;feature/new-dashboard&lt;/code&gt;&lt;br&gt;
Bug修复	&lt;code&gt;bugfix/&lt;/code&gt; + 问题ID	&lt;code&gt;bugfix/INPUT-123&lt;/code&gt;&lt;br&gt;
紧急修复	&lt;code&gt;hotfix/&lt;/code&gt; + 问题描述	&lt;code&gt;hotfix/ssl-issue&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;提交信息规范（必须遵守）&lt;br&gt;
类型	前缀	示例&lt;br&gt;
新增功能	&lt;code&gt;feat:&lt;/code&gt;	&lt;code&gt;feat: add login button&lt;/code&gt;&lt;br&gt;
修复 Bug	&lt;code&gt;fix:&lt;/code&gt;	&lt;code&gt;fix: resolve auth bug&lt;/code&gt;&lt;br&gt;
代码重构	&lt;code&gt;refactor:&lt;/code&gt; &lt;code&gt;refactor/api-response&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;拉取最新代码（推荐操作）&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;# 在功能分支开发时定期同步主分支
git checkout feature/new-dashboard
git pull origin main
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;使用 Pull Request 流程（团队协作必备）&lt;br&gt;
在 &lt;code&gt;GitHub&lt;/code&gt; 创建 &lt;code&gt;PR&lt;/code&gt;&lt;br&gt;
添加描述和关联 &lt;code&gt;Issue&lt;/code&gt;&lt;br&gt;
等待 &lt;code&gt;Code Review&lt;/code&gt;和测试通过&lt;br&gt;
合并到主分支后删除功能分支&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;🎯 流程图解&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;+-----------------------------+        +-----------------------------+
|        GitHub 主分支 (main)      |        |        GitHub 主分支 (main)      |
+-----------------------------+        +-----------------------------+
          ↓ (clone/pull)            ↗ (PR合并)          ↓ (clone/pull)
+-----------------------------+        +-----------------------------+
| 本地仓库 (main)              |        | 本地仓库 (main)              |
+-----------------------------+        +-----------------------------+
          ↓ (checkout -b)         ↗ (merge)          ↓ (checkout -b)
+-----------------------------+        +-----------------------------+
| 本地功能分支 (feature/new-dashboard) |      | 本地功能分支 (feature/new-dashboard) |
+-----------------------------+        +-----------------------------+
          ↓ (commit)             ↗ (push)          ↓ (commit)
+-----------------------------+        +-----------------------------+
| GitHub 功能分支              |        | GitHub 功能分支              |
+-----------------------------+        +-----------------------------+
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;关键节点：克隆仓库、创建功能分支、合并到主分支、推送主分支&lt;br&gt;
推荐路径：主流程（↓ → ↗ → ↓）｜合并路径（↗）&lt;br&gt;
&lt;strong&gt;⚠️ 常见错误与解决方案&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;合并冲突&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;# 手动解决冲突后标记为已解决
git add conflicted-file.txt
git commit -m &amp;quot;Resolve merge conflicts&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;忘记关联远程分支&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;# 推送时首次绑定远程分支
git push -u origin feature/new-dashboard
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;主分支落后于远程&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;# 合并前必须拉取最新代码
git pull origin main
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;回滚&lt;/h1&gt;
&lt;p&gt;Step 1 查看提交历史&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git log
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;Step 2 切换到需要回滚的分支&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git checkout main
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;Step 3 回滚到指定提交&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git reset --hard &amp;lt;commit-hash&amp;gt; # 也可以--hard HEAD^   回退上一版本，也可以用HEAD~1   --hard HEAD^^ 回退上两个版本，也可以用HEAD~2表示
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;Step 4 强制推送回滚后的代码到远程仓库&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git push -f origin main
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;📝总结&lt;/h1&gt;
&lt;p&gt;核心原则：隔离开发、频繁同步、明确沟通&lt;br&gt;
推荐工具：&lt;code&gt;GitHub PR&lt;/code&gt;、&lt;code&gt;GitLab Merge Request&lt;/code&gt;&lt;br&gt;
进阶学习：&lt;code&gt;Git Flow&lt;/code&gt; 工作流、&lt;code&gt;GitHub Actions&lt;/code&gt;&lt;br&gt;
文档特点：&lt;/p&gt;
&lt;p&gt;通过加粗/列表/代码块实现逻辑分层&lt;br&gt;
使用表格清晰展示规范要求&lt;br&gt;
流程图解采用&lt;code&gt;ASCII&lt;/code&gt;字符图形化关键路径&lt;br&gt;
错误提示突出显示高频问题解决方案&lt;br&gt;
&lt;code&gt;🔗&lt;/code&gt; 相关链接&lt;br&gt;
&lt;code&gt;Conventional Commits&lt;/code&gt; 规范&lt;br&gt;
&lt;code&gt;Git Flow&lt;/code&gt; 工作流&lt;br&gt;
&lt;code&gt;GitHub Actions&lt;/code&gt; 自动化&lt;/p&gt;
&lt;p&gt;:heavy_plus_sign: &lt;strong&gt;Pull request&lt;/strong&gt;  使用 (合并分支)&lt;/p&gt;
&lt;p&gt;Step 1 克隆仓库或更新本地仓库至最新代码&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git pull origin main         # 从远程仓库的main分支拉取最新的代码
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;Step 2 切换到拉取请求的目标分支（基础分支）&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git checkout main   # 切换到主分支（默认的基础分支）
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;Step 3 将功能分支合并到基础分支&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git merge new-feature # 将新功能分支（new-feature）合并到当前主分支
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;Step 4 推送合并后的代码到远程仓库&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git push -u origin main
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;补充：&lt;/strong&gt;&lt;br&gt;
删除本地分支&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git branch -d new-feature
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;删除远程分支&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;git push origin --delete new-feature
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;补充：&lt;/strong&gt;&lt;br&gt;
推荐练习git网站：&lt;br&gt;
&lt;a href=&#34;https://learngitbranching.js.org/?locale=en_US&#34;&gt;https://learngitbranching.js.org/?locale=en_US&lt;/a&gt;&lt;/p&gt;

 &lt;h1&gt;基础类型(8种)&lt;/h1&gt;
&lt;p&gt;&lt;code&gt;JavaScript&lt;/code&gt; 语言（注意，不是 &lt;code&gt;TypeScript&lt;/code&gt;）将值分成8种类型。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;boolean&lt;/code&gt; 布尔&lt;/li&gt;
&lt;li&gt;&lt;code&gt;string&lt;/code&gt; 字符串&lt;/li&gt;
&lt;li&gt;&lt;code&gt;number&lt;/code&gt; 数量&lt;/li&gt;
&lt;li&gt;&lt;code&gt;bigint&lt;/code&gt; 长整型数字&lt;/li&gt;
&lt;li&gt;&lt;code&gt;symbol&lt;/code&gt; 象征&lt;/li&gt;
&lt;li&gt;&lt;code&gt;object&lt;/code&gt; 对象&lt;/li&gt;
&lt;li&gt;&lt;code&gt;undefined&lt;/code&gt; 未定义的&lt;/li&gt;
&lt;li&gt;&lt;code&gt;null&lt;/code&gt; 零值&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;code&gt;TypeScript&lt;/code&gt; 继承了 &lt;code&gt;JavaScript&lt;/code&gt; 的类型设计，以上&lt;code&gt;8种类型&lt;/code&gt;可以看作 &lt;code&gt;TypeScript&lt;/code&gt; 的基本类型。&lt;br&gt;
注意，上面所有类型的名称都是小写字母，首字母大写的&lt;strong&gt;Number、String、Boolean&lt;/strong&gt;等在 &lt;code&gt;JavaScript&lt;/code&gt; 语言中都是&lt;strong&gt;内置对象&lt;/strong&gt;，而不是类型名称。&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;布尔值&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;let isDone: boolean = false;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;字符串&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;（普通字符串和模板字符串都属于string类型）&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;let str1: string = &amp;quot;bob&amp;quot;;
let str2: string = `$&amp;#123;str1&amp;#125; world`;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;number类型&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;let decLiteral: number = 6;
let hexLiteral: number = 0xf00d;
let binaryLiteral: number = 0b1010;
let octalLiteral: number = 0o744;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;bigint类型&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;bigint 类型是 ES2020 标准引入的。&lt;code&gt;JavaScript&lt;/code&gt; 版本不能低于 ES2020&lt;br&gt;
bigint 类型包含所有的大整数。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;const x:bigint = 123n;
const y:bigint = 0xffffn;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;bigint 与 number 类型不兼容。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;const x:bigint = 123; // 报错
const y:bigint = 3.14; // 报错
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;symbol类型&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;symbol 类型包含所有的 Symbol 值。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;const x:symbol = Symbol();
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;object 类型&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;根据 &lt;code&gt;JavaScript&lt;/code&gt; 的设计，object 类型包含了所有对象、数组和函数。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;const x:object = &amp;#123; foo: 123 &amp;#125;;
const y:object = [1, 2, 3];
const z:object = (n:number) =&amp;gt; n + 1;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;上面示例中，对象、数组、函数都属于 object 类型。&lt;/p&gt;
&lt;p&gt;关于数组，TypeScript 有专门类型定义。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;//第一种写法
let list: number[] = [1, 2, 3];
list.push(4);
list.length = 2;
list[1] = 5; 
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;采用&lt;code&gt;number[]&lt;/code&gt;定义了数组成员是动态的,可以增加、减少、修改成员，但成员类型必须为number类型。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;//第二种写法
let arr:Array&amp;lt;number&amp;gt; = [1, 2, 3];
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;7&#34;&gt;
&lt;li&gt;undefined&lt;/li&gt;
&lt;li&gt;null&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;let u: undefined = undefined;
let n: null = null;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;注意，如果没有声明类型的变量，被赋值为&lt;code&gt;undefined&lt;/code&gt;或&lt;code&gt;null&lt;/code&gt;，在关闭编译设置noImplicitAny和strictNullChecks时，它们的类型会被推断为any。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;// 关闭 noImplicitAny 和 strictNullChecks

let a = undefined;   // any
const b = undefined; // any

let c = null;        // any
const d = null;      // any
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;如果希望避免这种情况，则需要打开编译选项strictNullChecks。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;// 打开编译设置 strictNullChecks

let a = undefined;   // undefined
const b = undefined; // undefined

let c = null;        // null
const d = null;      // null
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;元组&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;let x: [string, number];
x = [&amp;quot;hello&amp;quot;, 10]; // OK
x = [10, &amp;quot;hello&amp;quot;]; // Error
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;any&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;let notSure: any = 4;
notSure = &amp;quot;maybe a string instead&amp;quot;;
notSure = false; // okay, definitely a boolean
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;类型推论&lt;/h1&gt;
&lt;p&gt;变量初始化类型推断，如果没有明确声明类型，&lt;code&gt;TypeScript&lt;/code&gt; 会根据变量初始值推断类型。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;//变量
let someValue = 4;// 初始化时，根据赋值自动推断为 number类型
someValue = &amp;quot;maybe a string instead&amp;quot;;//error

//数组
let list = [1, 2, 3];// 初始化时，根据赋值自动推断为 number[]类型
list.push(&amp;quot;hello&amp;quot;);//error
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;数组变量未声明类型，且为空数组，TypeScript 会推断为 &lt;code&gt;any[]&lt;/code&gt;类型。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;let list = [];//推断为 any[]

list.push(1);//赋值后，推断为number[]类型

list.push(&amp;quot;hello&amp;quot;);//再次赋值，推断为 (number|string)[]类型
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;只读数组，const断言&lt;/h1&gt;
&lt;p&gt;&lt;code&gt;JavaScript&lt;/code&gt; 中，&lt;code&gt;const&lt;/code&gt; 定义的变量，不能重新赋值，但可以修改其成员。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;const arr = [1, 2, 3];//number[]
arr[0] = 4;//ok
arr[0] = &amp;quot;hello world!&amp;quot;;//error,
arr.push(5);//error
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;TsypeScript&lt;/code&gt; 允许声明只读数组，方法是在数组类型前加上&lt;code&gt;redayonly&lt;/code&gt;关键字。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;const arr: readonly number[] = [1, 2, 3];//readonly number[]
arr[0] = 4;//error
arr.push(5);//error
delete arr[0];//error
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;TsypeScript&lt;/code&gt; 将&lt;code&gt;readonly number[]&lt;/code&gt;视为&lt;code&gt;number[]&lt;/code&gt;的父类，子类型具有父类行的特征并具有自己的特征&lt;code&gt;pop\push&lt;/code&gt;,所以子类可以赋值给父类型，反过来不行。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;let arr:readonly number[] = [1, 2, 3];
let arr2:readonly number[] = arr;//ok
arr = arr2;//error

//--------------------------

function getSum(s:number[]) &amp;#123;
  // ...
&amp;#125;
const arr:readonly number[] = [1, 2, 3];
getSum(arr) // error,等价于 getSum(s:number[]=arr:readonly number[])
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;number[]&lt;/code&gt;作为子类继承&lt;code&gt;readonly number[]&lt;/code&gt;父类，而父类没有&lt;code&gt;pop()&lt;/code&gt;、&lt;code&gt;push()&lt;/code&gt;方法,所以两者并不完全等价。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;TypeScript 中，const 定义的变量，不能重新赋值，也不能修改其成员。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;const arr: readonly number[] = [1, 2, 3];
arr[0] = 4;//error
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;只读数组，泛型写法&lt;/h1&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;// error 
const arr:readonly Array&amp;lt;number&amp;gt; = [0, 1];

// method 1
const a1:ReadonlyArray&amp;lt;number&amp;gt; = [0, 1];
// method 2
const a2:Readonly&amp;lt;number[]&amp;gt; = [0, 1];
// method 3 使用“const 断言”实现
const arr1 = [0, 1] as const;
arr1[0] = [2]; // 报错 
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;类型断言&lt;/h1&gt;
&lt;p&gt;对于没有类型声明的值，&lt;code&gt;TypeScript&lt;/code&gt; 会进行类型推断，很多时候得到的结果，未必是开发者想要的，类型断言可以用来告诉编译器变量的类型，可以避免编译器进行类型推断。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;type T = &#39;a&#39;|&#39;b&#39;|&#39;c&#39;;

let foo = &#39;a&#39;;
// let bar:T = foo; // error bar为T类型，foo 推断为string类型
let bar:T = foo as T; // ok 断言foo为T类型
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;断言语法&lt;/h1&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;    // 语法一：`&amp;lt;类型&amp;gt;值`
    &amp;lt;Type&amp;gt;value
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;    // 语法二：`值 as 类型`
    value as Type // 推荐写法
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;对象类型有严格字面量检查，如果存在额外的属性会报错.&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;const p:&amp;#123; x: number &amp;#125; = &amp;#123; x: 0, y: 0 &amp;#125;;// error
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;断言可以绕过字面量检查，存在类型断言，就没有严格字面量检查了，所以不报错。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;const p0:&amp;#123; x: number &amp;#125; =
  &amp;#123; x: 0, y: 0 &amp;#125; as &amp;#123; x: number &amp;#125;;// ok断言使得等号左右两边类型一致

const p1:&amp;#123; x: number &amp;#125; =
  &amp;#123; x: 0, y: 0 &amp;#125; as &amp;#123; x: number; y: number &amp;#125;;// ok 断言使得等号左右两边类型一致
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;值类型&lt;/h1&gt;
&lt;p&gt;TypeScript 规定，单个值也是一种类型，称为“值类型”。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;let x:&#39;hello&#39;;

x = &#39;hello&#39;; // 正确
x = &#39;world&#39;; // 报错
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;TypeScript 推断类型时，遇到&lt;code&gt;const&lt;/code&gt;命令声明的变量，如果代码里面没有注明类型，就会推断该变量是值类型。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;// x 的类型是 &amp;quot;https&amp;quot;
const x = &#39;https&#39;;

// y 的类型是 string
const y:string = &#39;https&#39;;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;这样推断是合理的，因为&lt;code&gt;const&lt;/code&gt;命令声明的变量，一旦声明就不能改变，相当于常量。值类型就意味着不能赋为其他值。&lt;/p&gt;
&lt;p&gt;注意，&lt;code&gt;const&lt;/code&gt;命令声明的变量，如果赋值为对象，并不会推断为值类型。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;// x 的类型是 &amp;#123; foo: number &amp;#125;
const x = &amp;#123; foo: 1 &amp;#125;;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;变量&lt;code&gt;x&lt;/code&gt;没有被推断为值类型，而是推断属性&lt;code&gt;foo&lt;/code&gt;的类型是&lt;code&gt;number&lt;/code&gt;。这是因为&lt;code&gt; &lt;/code&gt;JavaScript&lt;code&gt; &lt;/code&gt;里面，&lt;code&gt;const&lt;/code&gt;变量赋值为对象时，属性值是可以改变的。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;const x:5 = 4 + 1; // 报错
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;上面示例中，等号左侧的类型是数值&lt;code&gt;5&lt;/code&gt;，等号右侧&lt;code&gt;4 + 1&lt;/code&gt;的类型，&lt;code&gt;TypeScript&lt;/code&gt; 推测为&lt;code&gt;number&lt;/code&gt;。由于&lt;code&gt;5&lt;/code&gt;是&lt;code&gt;number&lt;/code&gt;的子类型，&lt;code&gt;number&lt;/code&gt;是&lt;code&gt;5&lt;/code&gt;的父类型，父类型不能赋值给子类型，所以报错了.&lt;br&gt;
但是，反过来是可以的，子类型可以赋值给父类型。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;let x:5 = 5;
let y:number = 4 + 1;

x = y; // 报错
y = x; // 正确
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;如果一定要让子类型可以赋值为父类型的值，就要用到类型断言&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;const x:5 = (4 + 1) as 5; // 正确
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;上面示例中，在&lt;code&gt;4 + 1&lt;/code&gt;后面加上&lt;code&gt;as 5&lt;/code&gt;，就是告诉编译器，可以把&lt;code&gt;4 + 1&lt;/code&gt;的类型视为值类型&lt;code&gt;5&lt;/code&gt;，这样就不会报错了。&lt;/p&gt;
&lt;p&gt;只包含单个值的值类型，用处不大。实际开发中，往往将多个值结合，作为联合类型使用。&lt;/p&gt;
&lt;h1&gt;联合类型&lt;/h1&gt;
&lt;p&gt;联合类型（union types）指的是多个类型组成的一个新类型，使用符号|表示。&lt;/p&gt;
&lt;p&gt;联合类型&lt;code&gt;A|B&lt;/code&gt;表示，任何一个类型只要属于&lt;code&gt;A&lt;/code&gt;或&lt;code&gt;B&lt;/code&gt;，就属于联合类型&lt;code&gt;A|B&lt;/code&gt;。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;// 基本类型的联合类型
let myFavoriteNumber: string | number;
myFavoriteNumber = &#39;seven&#39;; // OK
myFavoriteNumber = 7; // OK

// 值类型的联合类型
let set : true| false;
let name : &#39;Tom&#39; | &#39;Jerry&#39; | &#39;Spike&#39;;
let color: &#39;red&#39; | &#39;blue&#39; | &#39;green&#39;;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;打开编译选项&lt;code&gt;strictNullChecks&lt;/code&gt;后，其他类型的变量不能赋值为&lt;code&gt;undefined&lt;/code&gt;或&lt;code&gt;nul&lt;/code&gt;l。这时，如果某个变量确实可能包含空值，就可以采用联合类型的写法。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;let name:string|null;

name = &#39;John&#39;;
name = null;
// 多行书写联合类型
let x:
  | &#39;one&#39;
  | &#39;two&#39;
  | &#39;three&#39;
  | &#39;four&#39;;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;如果一个变量有多种类型，读取该变量时，往往需要进行“类型缩小”（type narrowing），区分该值到底属于哪一种类型，然后再进一步处理。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;function printId(
  id:number|string
) &amp;#123;
    console.log(id.toUpperCase()); // 报错
&amp;#125;

// 类型缩小
function printId(
  id:number|string
) &amp;#123;
  if (typeof id === &#39;string&#39;) &amp;#123;
    console.log(id.toUpperCase());
  &amp;#125; else &amp;#123;
    console.log(id);
  &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;交叉类型&lt;/h1&gt;
&lt;p&gt;交叉类型（intersection types）指的多个类型组成的一个新类型，使用符号&lt;code&gt;&amp;amp;&lt;/code&gt;表示。&lt;/p&gt;
&lt;p&gt;交叉类型&lt;code&gt;A&amp;amp;B&lt;/code&gt;表示，任何一个类型必须同时属于&lt;code&gt;A&lt;/code&gt;和&lt;code&gt;B&lt;/code&gt;，才属于交叉类型&lt;code&gt;A&amp;amp;B&lt;/code&gt;，即交叉类型同时满足A和B的特征。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;let x:number&amp;amp;string;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;上面示例中，变量&lt;code&gt;x&lt;/code&gt;同时是数值和字符串，这当然是不可能的，所以&lt;code&gt;TypeScript&lt;/code&gt; 会认为x的类型实际是&lt;code&gt;never&lt;/code&gt;。&lt;/p&gt;
&lt;p&gt;交叉类型的主要用途是表示对象的合成。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;let obj:
  &amp;#123; foo: string &amp;#125; &amp;amp;
  &amp;#123; bar: string &amp;#125;;

obj = &amp;#123;
  foo: &#39;hello&#39;,
  bar: &#39;world&#39;
&amp;#125;;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;上面示例中，变量&lt;code&gt;obj&lt;/code&gt;同时具有属性&lt;code&gt;foo&lt;/code&gt;和属性&lt;code&gt;bar&lt;/code&gt;。&lt;/p&gt;
&lt;p&gt;交叉类型常常用来为对象类型添加新属性。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;type A = &amp;#123; foo: number &amp;#125;;

type B = A &amp;amp; &amp;#123; bar: number &amp;#125;;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;上面示例中，类型&lt;code&gt;B&lt;/code&gt;是一个交叉类型，用来在&lt;code&gt;A&lt;/code&gt;的基础上增加了属性&lt;code&gt;bar&lt;/code&gt;。&lt;/p&gt;
&lt;h1&gt;type 命令&lt;/h1&gt;
&lt;p&gt;type命令用来定义一个类型的别名。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;type Age = number;

let age:Age = 55;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;上面示例中，&lt;code&gt;type&lt;/code&gt;命令为&lt;code&gt;number&lt;/code&gt;类型定义了一个别名&lt;code&gt;Age&lt;/code&gt;。这样就能像使用&lt;code&gt;number&lt;/code&gt;一样，使用&lt;code&gt;Age&lt;/code&gt;作为类型。&lt;/p&gt;
&lt;p&gt;别名的作用域是块级作用域。这意味着，代码块内部定义的别名，影响不到外部。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;type Color = &#39;red&#39;;

if (Math.random() &amp;lt; 0.5) &amp;#123;
  type Color = &#39;blue&#39;;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;别名支持使用表达式，也可以在定义一个别名时，使用另一个别名，即别名允许嵌套。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;type World = &amp;quot;world&amp;quot;;
type Greeting = `hello $&amp;#123;World&amp;#125;`;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;typeof 运算符&lt;/h1&gt;
&lt;p&gt;&lt;code&gt;JavaScript&lt;/code&gt; 语言中，&lt;code&gt;typeof&lt;/code&gt; 运算符是一个一元运算符，返回一个字符串，代表操作数的类型。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;typeof &#39;foo&#39;; // &#39;string&#39;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;JavaScript&lt;/code&gt; 里面，&lt;code&gt;typeof&lt;/code&gt;运算符只可能返回八种结果，而且都是字符串。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;typeof undefined; // &amp;quot;undefined&amp;quot;
typeof true; // &amp;quot;boolean&amp;quot;
typeof 1337; // &amp;quot;number&amp;quot;
typeof &amp;quot;foo&amp;quot;; // &amp;quot;string&amp;quot;
typeof &amp;#123;&amp;#125;; // &amp;quot;object&amp;quot;
typeof parseInt; // &amp;quot;function&amp;quot;
typeof Symbol(); // &amp;quot;symbol&amp;quot;
typeof 127n // &amp;quot;bigint&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;由于编译时不会进行 &lt;code&gt;JavaScript&lt;/code&gt; 的值运算，所以&lt;code&gt;TypeScript&lt;/code&gt; 规定，typeof 的参数只能是标识符，不能是需要运算的表达式。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;type T = typeof Date(); // 报错
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;上面示例会报错，原因是 &lt;code&gt;typeof&lt;/code&gt; 的参数不能是一个值的运算式，而&lt;code&gt;Date()&lt;/code&gt;需要运算才知道结果。&lt;/p&gt;
&lt;p&gt;另外，&lt;code&gt;typeof&lt;/code&gt;命令的参数不能是类型。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;type T = typeof Date(); // 报错
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;块圾类型声明&lt;/h1&gt;
&lt;p&gt;TypeScript 支持块级类型声明，即类型可以声明在代码块（用大括号表示）里面，并且只在当前代码块有效。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;if (true) &amp;#123;
  type T = number;
  let v:T = 5;
&amp;#125; else &amp;#123;
  type T = string;
  let v:T = &#39;hello&#39;;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;类型兼容&lt;/h1&gt;
&lt;p&gt;TypeScript 的类型存在兼容关系，某些类型可以兼容其他类型。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;type T = number|string;

let a:number = 1;
let b:T = a;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;TypeScript 的一个规则是，凡是可以使用父类型的地方，都可以使用子类型，但是反过来不行。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-typescript&#34;&gt;let a:&#39;hi&#39; = &#39;hi&#39;;
let b:string = &#39;hello&#39;;

b = a; // 正确
a = b; // 报错
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;上面示例中，&lt;code&gt;hi&lt;/code&gt;是&lt;code&gt;string&lt;/code&gt;的子类型，&lt;code&gt;string&lt;/code&gt;是&lt;code&gt;hi&lt;/code&gt;的父类型。所以，变量&lt;code&gt;a&lt;/code&gt;可以赋值给变量&lt;code&gt;b&lt;/code&gt;，但是反过来就会报错。&lt;/p&gt;

 &lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;I/O多路复用&lt;/code&gt;是一种技术，允许一个进程同时监控多个文件描述符，并在其中任何一个文件描述符准备好进行I/O操作时通知进程。这种技术可以提高程序的性能和效率，特别是在需要同时处理多个网络连接或文件描述符的情况下。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1&gt;select&lt;/h1&gt;
&lt;p&gt;函数原型：使用&lt;code&gt;select&lt;/code&gt;这种&lt;code&gt;IO&lt;/code&gt;多路转接方式需要调用一个同名函数&lt;code&gt;select&lt;/code&gt;，这个函数是跨平台的，&lt;code&gt;Linux&lt;/code&gt;、&lt;code&gt;Windows&lt;/code&gt;、&lt;code&gt;MacOS&lt;/code&gt;等操作系统都是支持的。该函数可以委托内核帮助我们检测若干个文件描述符的状态，其实就是检测这些文件描述符对应的读写缓冲区的状态。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;读缓冲区状态：检测里面是否有数据，如果有数据该缓冲区对应的文件描述符就绪&lt;/li&gt;
&lt;li&gt;写缓冲区状态：检测里面是否还有空闲空间，如果有空闲空间该缓冲区对应的文件描述符就绪&lt;/li&gt;
&lt;li&gt;读取异常状态：检测是否发生异常，比如网络异常、文件异常等，如果发生异常该缓冲区对应的文件描述符就绪&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;委托检测的文件描述符遍历检测完毕之后，已就绪的这些满足的文件描述符会通过select()的参数分为3个集合传出，程序员得到这几个集合依次分情况依次处理即可。&lt;/p&gt;
&lt;p&gt;函数原型：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;sys/select.h&amp;gt;
struct timeval &amp;#123;
    time_t tv_sec; /* 秒 */
    suseconds_t tv_usec; /* 微秒 */
&amp;#125;

int select(int nfds, fd_set *readfds, fd_set *writefds, fd_set *exceptfds, struct timeval *timeout);
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;nfds&lt;/code&gt;：需要检测的文件描述符的范围，即检测的文件描述符从0到&lt;code&gt;nfds-1&lt;/code&gt;，&lt;code&gt;nfds&lt;/code&gt;的值通常为待检测的&lt;em&gt;最大文件描述符&lt;/em&gt;加1。(内核允许最大一般是1024)
&lt;ul&gt;
&lt;li&gt;内核需要线程遍历这些集合中的文件描述符，这个值是循环结束的条件。&lt;/li&gt;
&lt;li&gt;在windows中，该参数是无效的，指定为-1即可。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;readfds&lt;/code&gt;：需要检测读状态的文件描述符集合，即检测这些文件描述符对应的读缓冲区状态。
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;传入传出参数&lt;/code&gt;，读集合一般情况下是需要检测的，这样测能直到通过哪些文件描述符接收数据。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;writefds&lt;/code&gt;：需要检测写状态的文件描述符集合，即检测这些文件描述符对应的写缓冲区状态。
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;传入传出参数&lt;/code&gt;，如果不需要使用该参数可以指定为NULL。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;exceptfds&lt;/code&gt;：需要检测异常状态的文件描述符集合，即检测这些文件描述符对应的异常状态。
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;传入传出参数&lt;/code&gt;，如果不需要使用该参数可以指定为NULL。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;timeout&lt;/code&gt;：超时时间，即检测文件描述符状态的超时时间。&lt;/li&gt;
&lt;li&gt;函数返回值：
&lt;ul&gt;
&lt;li&gt;大于&lt;code&gt;0&lt;/code&gt;：成功，返回集合中已就绪的文件描述符的个数。&lt;/li&gt;
&lt;li&gt;等于&lt;code&gt;-1&lt;/code&gt;：则表示出错。&lt;/li&gt;
&lt;li&gt;等于&lt;code&gt;0&lt;/code&gt;：则表示超时。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;/images/ioduolu.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;另外初始化&lt;code&gt;fd_set&lt;/code&gt;类型的参数还需要使用相关的一些列操作函数，具体如下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;void FD_ZERO(fd_set *set); // 将set集合中的所有文件描述符对应的标志位都设置为0，表示集合中没有文件描述符
void FD_SET(int fd, fd_set *set); // 将set集合中的fd文件描述符对应的标志位设置为1，表示集合中有该文件描述符
void FD_CLR(int fd, fd_set *set); // 将set集合中的fd文件描述符对应的标志位设置为0，表示集合中没有该文件描述符
void FD_ISSET(int fd, fd_set *set); // 判断set集合中的fd文件描述符对应的标志位是否为1，如果为1则表示集合中有该文件描述符，否则表示集合中没有该文件描述符
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;poll&lt;/h1&gt;
&lt;p&gt;函数原型：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;poll.h&amp;gt;
struct pollfd &amp;#123;
    int fd; /* 文件描述符 */
    short events; /* 监控的事件 */
    short revents; /* 实际发生的事件 */
&amp;#125;;
int poll(struct pollfd *fds, nfds_t nfds, int timeout);
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;fds&lt;/code&gt;：需要检测的文件描述符集合，即检测这些文件描述符对应的读缓冲区状态、写缓冲区状态、异常状态。
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;传入传出参数&lt;/code&gt;，读集合一般情况下是需要检测的，这样测能直到通过哪些文件描述符接收数据。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;pollfd&lt;/code&gt;结构体数组，每个&lt;code&gt;pollfd&lt;/code&gt;结构体表示一个文件描述符的检测信息，包括文件描述符、检测的事件、实际发生的事件。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;nfds&lt;/code&gt;：需要检测的文件描述符的个数，即检测的文件描述符从0到&lt;code&gt;nfds-1&lt;/code&gt;，&lt;code&gt;nfds&lt;/code&gt;的值通常为待检测的&lt;em&gt;最大文件描述符&lt;/em&gt;加1。
&lt;ul&gt;
&lt;li&gt;内核需要线程遍历这些集合中的文件描述符，这个值是循环结束的条件。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;timeout&lt;/code&gt;：超时时间，即检测文件描述符状态的超时时间。&lt;/li&gt;
&lt;li&gt;函数返回值：
&lt;ul&gt;
&lt;li&gt;大于&lt;code&gt;0&lt;/code&gt;：成功，返回集合中已就绪的文件描述符的个数。&lt;/li&gt;
&lt;li&gt;等于&lt;code&gt;-1&lt;/code&gt;：则表示出错。&lt;/li&gt;
&lt;li&gt;等于&lt;code&gt;0&lt;/code&gt;：则表示超时。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;创建监听的套接字 lfd = socket();&lt;br&gt;
将监听的套接字和本地的IP和端口绑定 bind()&lt;br&gt;
给监听的套接字设置监听 listen()&lt;br&gt;
创建一个文件描述符集合 fd_set，用于存储需要检测读事件的所有的文件描述符&lt;br&gt;
通过 FD_ZERO() 初始化&lt;br&gt;
通过 FD_SET() 将监听的文件描述符放入检测的读集合中&lt;br&gt;
循环调用select()，周期性的对所有的文件描述符进行检测&lt;br&gt;
select() 解除阻塞返回，得到内核传出的满足条件的就绪的文件描述符集合&lt;br&gt;
通过FD_ISSET() 判断集合中的标志位是否为 1&lt;br&gt;
如果这个文件描述符是监听的文件描述符，调用 accept() 和客户端建立连接&lt;br&gt;
将得到的新的通信的文件描述符，通过FD_SET() 放入到检测集合中&lt;br&gt;
如果这个文件描述符是通信的文件描述符，调用通信函数和客户端通信&lt;br&gt;
如果客户端和服务器断开了连接，使用FD_CLR()将这个文件描述符从检测集合中删除&lt;br&gt;
如果没有断开连接，正常通信即可&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;服务端并发实现：&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;stdio.h&amp;gt;
#include &amp;lt;stdlib.h&amp;gt;
#include&amp;lt;unistd.h&amp;gt;
#include&amp;lt;string.h&amp;gt;
#include&amp;lt;arpa/inet.h&amp;gt;
#include &amp;lt;sys/select.h&amp;gt;
int main()&amp;#123;
    // 1. 创建监听的套接字
    int fd = socket(AF_INET, SOCK_STREAM, 0); // IPV4, TCP, 默认协议
    if(fd == -1)&amp;#123;
        perror(&amp;quot;socket&amp;quot;);
        exit(-1);
    &amp;#125;
    // 2. 绑定IP和端口
    struct sockaddr_in saddr;

    saddr.sin_family = AF_INET; // 初始化IPV4
    saddr.sin_port = htons(9999); // 初始化 端口
    saddr.sin_addr.s_addr = INADDR_ANY; // 0=0.0.0.0 
    int ret = bind(fd,(struct sockaddr *)&amp;amp;saddr,sizeof(saddr));
    if(ret == -1)&amp;#123;
        perror(&amp;quot;bind&amp;quot;);
        return -1;
    &amp;#125;

    // 设置监听
    ret = listen(fd,128);
    if(ret == -1)&amp;#123;
        perror(&amp;quot;listen&amp;quot;);
        return -1;
    &amp;#125;

    fd_set redset;
    FD_ZERO(&amp;amp;redset);
    FD_SET(fd,&amp;amp;redset);

    int maxfd = fd;
    while(1)&amp;#123;
        fd_set temp = redset;
        int ret = select(maxfd + 1, &amp;amp;temp, NULL,NULL, NULL);
        // 判断是不是监听fd
        if(FD_ISSET(fd,&amp;amp;temp))&amp;#123;
            // 接受客户端的连接
            int cfd = accept(fd,NULL,NULL);
            FD_SET(cfd, &amp;amp; redset);
            maxfd = cfd &amp;gt; maxfd ?cfd:maxfd ;
        &amp;#125;
        for(int i = 0; i&amp;lt;= maxfd;++i)&amp;#123;
            if(i!=fd &amp;amp;&amp;amp; FD_ISSET(i,&amp;amp;temp))&amp;#123;
                // 接收数据
                char buf[1024];
                int len = recv(i,buf,sizeof(buf),0);
                if(len&amp;gt;0)&amp;#123;
                    printf(&amp;quot;client say : %s\n&amp;quot;,buf);
                    send(i,buf,len,0);
                &amp;#125;
                else if(len == 0)&amp;#123;
                    printf(&amp;quot;客户端断开连接。。\n&amp;quot;);
                    FD_CLR(i,&amp;amp;redset);
                    close(i);
                    break;
                &amp;#125;
                else&amp;#123;
                    perror(&amp;quot;recv&amp;quot;);
                    break;
                &amp;#125;
            &amp;#125;
        &amp;#125;
    &amp;#125;

    // 关闭文件描述符
    close(fd);

    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;select 与 poll 的并发性能比较：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;select&lt;/code&gt;函数的&lt;code&gt;fd_set&lt;/code&gt;类型参数，在每次调用&lt;code&gt;select&lt;/code&gt;函数时，都需要重新设置，而&lt;code&gt;poll&lt;/code&gt;函数的&lt;code&gt;pollfd&lt;/code&gt;类型参数，只需要在第一次调用&lt;code&gt;poll&lt;/code&gt;函数时设置一次，之后每次调用&lt;code&gt;poll&lt;/code&gt;函数时，只需要修改需要检测的文件描述符的&lt;code&gt;pollfd&lt;/code&gt;结构体即可。&lt;/li&gt;
&lt;/ul&gt;

 &lt;blockquote&gt;
&lt;p&gt;Socket是网络编程的一个抽象概念，它是对&lt;code&gt;TCP/IP&lt;/code&gt;协议的封装，提供了一组接口，使得程序员可以更方便地使用网络功能。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1&gt;Socket的原理&lt;/h1&gt;
&lt;p&gt;&lt;code&gt;Socket&lt;/code&gt;的原理是基于&lt;code&gt;TCP/IP&lt;/code&gt;协议的，它通过&lt;code&gt;TCP/IP&lt;/code&gt;协议来传输数据。&lt;code&gt;TCP/IP&lt;/code&gt;协议是一种网络通信协议，它定义了计算机之间如何进行通信。&lt;/p&gt;
&lt;h2 id=&#34;TCP&#34;&gt;TCP&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;TCP&lt;/code&gt;（Transmission Control Protocol）是一种面向连接的、可靠的、基于字节流的传输层通信协议。它提供了一种可靠的、有序的、无重复的数据传输方式。&lt;code&gt;TCP&lt;/code&gt;协议通过三次握手建立连接，通过四次挥手断开连接。在数据传输过程中，&lt;code&gt;TCP&lt;/code&gt;协议会进行流量控制和拥塞控制，以保证数据的可靠传输。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;三次握手：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;客户端向服务器发送一个&lt;code&gt;SYN&lt;/code&gt;包，表示请求建立连接。&lt;/li&gt;
&lt;li&gt;服务器收到&lt;code&gt;SYN&lt;/code&gt;包后，向客户端发送一个&lt;code&gt;SYN-ACK&lt;/code&gt;包，表示同意建立连接。&lt;/li&gt;
&lt;li&gt;客户端收到&lt;code&gt;SYN-ACK&lt;/code&gt;包后，向服务器发送一个ACK包，表示确认建立连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;四次挥手：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;客户端向服务器发送一个&lt;code&gt;FIN&lt;/code&gt;包，表示请求断开连接。&lt;/li&gt;
&lt;li&gt;服务器收到FIN包后，向客户端发送一个&lt;code&gt;ACK&lt;/code&gt;包，表示确认断开连接。&lt;/li&gt;
&lt;li&gt;服务器向客户端发送一个FIN包，表示请求断开连接。&lt;/li&gt;
&lt;li&gt;客户端收到&lt;code&gt;FIN&lt;/code&gt;包后，向服务器发送一个&lt;code&gt;ACK&lt;/code&gt;包，表示确认断开连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;/images/tcp.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h1&gt;Socket的使用&lt;/h1&gt;
&lt;h2 id=&#34;服务器端通信流程&#34;&gt;服务器端通信流程&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;创建用于监听的套接字, 这个套接字是一个文件描述符:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;
int lfd = socket( AF_INET, SOCK_STREAM, 0 );

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;socket&lt;/code&gt;接受三个参数，分别是&lt;code&gt;地址族&lt;/code&gt;、&lt;code&gt;套接字类型&lt;/code&gt;和&lt;code&gt;协议类型&lt;/code&gt;。&lt;br&gt;
&lt;code&gt;AF_INET&lt;/code&gt;表示使用&lt;code&gt;IPv4&lt;/code&gt;协议，&lt;code&gt;SOCK_STREAM&lt;/code&gt;表示使用&lt;code&gt;TCP&lt;/code&gt;协议，&lt;code&gt;0&lt;/code&gt;表示使用默认协议。&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;绑定套接字到指定的IP地址和端口号:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;struct sockaddr_in serv_addr;
serv_addr.sin_family = AF_INET;
serv_addr.sin_addr.s_addr = htonl(INADDR_ANY); // 使用本地IP地址
serv_addr.sin_port = htons(8888); // 使用指定的端口号

bind( lfd, (struct sockaddr*)&amp;amp;serv_addr, sizeof(serv_addr) );

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;bind&lt;/code&gt;接受三个参数，分别是&lt;code&gt;套接字描述符&lt;/code&gt;、&lt;code&gt;地址结构体&lt;/code&gt;和&lt;code&gt;地址结构体&lt;/code&gt;的大小。&lt;/p&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;监听套接字:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;listen( lfd, 128 );
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;listen接受两个参数，分别是&lt;code&gt;套接字描述符&lt;/code&gt;和&lt;code&gt;监听队列的长度&lt;/code&gt;。&lt;/p&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;接受客户端连接:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;struct sockaddr_in cli_addr;
socklen_t cli_len = sizeof(cli_addr);
int cfd = accept( lfd, (struct sockaddr*)&amp;amp;cli_addr, &amp;amp;cli_len );
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;accept&lt;/code&gt;接受三个参数，分别是&lt;code&gt;套接字描述符&lt;/code&gt;、&lt;code&gt;客户端地址结构体&lt;/code&gt;和&lt;code&gt;客户端地址结构体&lt;/code&gt;的大小。&lt;/p&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;读取客户端发送的数据:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;char buf[1024];
int n = read( cfd, buf, sizeof(buf) );
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;read&lt;/code&gt;接受三个参数，分别是&lt;code&gt;套接字描述符&lt;/code&gt;、&lt;code&gt;缓冲区&lt;/code&gt;和&lt;code&gt;缓冲区大小&lt;/code&gt;。&lt;/p&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;发送数据给客户端:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;write( cfd, &amp;quot;hello world&amp;quot;, 11 );
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;write&lt;/code&gt;接受三个参数，分别是&lt;code&gt;套接字描述符&lt;/code&gt;、&lt;code&gt;数据&lt;/code&gt;和&lt;code&gt;数据大小&lt;/code&gt;。&lt;/p&gt;
&lt;ol start=&#34;7&#34;&gt;
&lt;li&gt;关闭套接字:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;close( lfd );// 关闭监听套接字
close( cfd );// 关闭客户端套接字
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;close&lt;/code&gt;接受一个参数，即&lt;code&gt;套接字描述符&lt;/code&gt;。&lt;/p&gt;
&lt;p&gt;服务端程序的完整代码如下:&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;stdio.h&amp;gt;
#include &amp;lt;stdlib.h&amp;gt;
#include &amp;lt;string.h&amp;gt;
#include &amp;lt;unistd.h&amp;gt;
#include &amp;lt;arpa/inet.h&amp;gt;

int main()
&amp;#123;
    // 1. 创建用于监听的套接字
    int lfd = socket(AF_INET, SOCK_STREAM, 0);
    if (lfd == -1)
    &amp;#123;
        perror(&amp;quot;socket&amp;quot;);
        exit(1);
    &amp;#125;

    // 2. 绑定套接字到指定的IP地址和端口号
    struct sockaddr_in serv_addr;
    serv_addr.sin_family = AF_INET;
    serv_addr.sin_addr.s_addr = htonl(INADDR_ANY);
    serv_addr.sin_port = htons(8888);

    if (bind(lfd, (struct sockaddr*)&amp;amp;serv_addr, sizeof(serv_addr)) == -1)
    &amp;#123;
        perror(&amp;quot;bind&amp;quot;);
        exit(1);
    &amp;#125;

    // 3. 监听套接字
    if (listen(lfd, 128) == -1)
    &amp;#123;
        perror(&amp;quot;listen&amp;quot;);
        exit(1);
    &amp;#125;

    // 4. 接受客户端连接
    struct sockaddr_in cli_addr;
    socklen_t cli_len = sizeof(cli_addr);
    int cfd = accept(lfd, (struct sockaddr*)&amp;amp;cli_addr, &amp;amp;cli_len);
    if (cfd == -1)
    &amp;#123;
        perror(&amp;quot;accept&amp;quot;);
        exit(1);
    &amp;#125;

    // 5. 读取客户端发送的数据
    char buf[1024];
    int n = read(cfd, buf, sizeof(buf));
    if (n == -1)
    &amp;#123;
        perror(&amp;quot;read&amp;quot;);
        exit(1);
    &amp;#125;
    printf(&amp;quot;recv buf: %s\n&amp;quot;, buf);

    // 6. 发送数据给客户端
    if (write(cfd, &amp;quot;hello world&amp;quot;, 11) == -1)
    &amp;#123;
        perror(&amp;quot;write&amp;quot;);
        exit(1);
    &amp;#125;

    // 7. 关闭套接字
    close(lfd);
    close(cfd);

    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;客户端通信流程&#34;&gt;客户端通信流程&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;创建用于连接的套接字:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;int cfd = socket( AF_INET, SOCK_STREAM, 0 );
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;连接服务器:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;struct sockaddr_in serv_addr;
serv_addr.sin_family = AF_INET;
serv_addr.sin_addr.s_addr = inet_addr(&amp;quot;127.0.0.1&amp;quot;); // 使用服务器的IP地址
serv_addr.sin_port = htons(8888); // 使用指定的端口号

connect( cfd, (struct sockaddr*)&amp;amp;serv_addr, sizeof(serv_addr) );
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;发送数据给服务器:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;write( cfd, &amp;quot;hello world&amp;quot;, 11 );
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;读取服务器发送的数据:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;char buf[1024];
int n = read( cfd, buf, sizeof(buf) );
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;关闭套接字:&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;close( cfd );
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;客户端程序的完整代码如下:&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;#include &amp;lt;stdio.h&amp;gt;
#include &amp;lt;stdlib.h&amp;gt;
#include &amp;lt;string.h&amp;gt;
#include &amp;lt;unistd.h&amp;gt;
#include &amp;lt;arpa/inet.h&amp;gt;

int main()
&amp;#123;
    // 1. 创建用于连接的套接字
    int cfd = socket(AF_INET, SOCK_STREAM, 0);
    if (cfd == -1)
    &amp;#123;
        perror(&amp;quot;socket&amp;quot;);
        exit(1);
    &amp;#125;

    // 2. 连接服务器
    struct sockaddr_in serv_addr;
    serv_addr.sin_family = AF_INET;

    serv_addr.sin_addr.s_addr = inet_addr(&amp;quot;127.0.0.1&amp;quot;);
    serv_addr.sin_port = htons(8888);

    if (connect(cfd, (struct sockaddr*)&amp;amp;serv_addr, sizeof(serv_addr)) == -1)
    &amp;#123;
        perror(&amp;quot;connect&amp;quot;);
        exit(1);
    &amp;#125;

    // 3. 发送数据给服务器
    if (write(cfd, &amp;quot;hello world&amp;quot;, 11) == -1)
    &amp;#123;
        perror(&amp;quot;write&amp;quot;);
        exit(1);
    &amp;#125;

    // 4. 读取服务器发送的数据
    char buf[1024];

    int n = read(cfd, buf, sizeof(buf));
    if (n == -1)
    &amp;#123;
        perror(&amp;quot;read&amp;quot;);
        exit(1);
    &amp;#125;
    printf(&amp;quot;recv buf: %s\n&amp;quot;, buf);

    // 5. 关闭套接字
    close(cfd);

    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;

 &lt;blockquote&gt;
&lt;p&gt;SQL (Structured Query Language) 是用于管理和操作关系数据库的标准化编程语言。它允许用户执行各种操作，如查询、更新、插入和删除数据，以及管理数据库结构和权限。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;strong&gt;SQL分类：&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;code&gt;DDL&lt;/code&gt; 数据定义语言，用来定义数据库对象（数据库、表、字段）&lt;/li&gt;
&lt;li&gt;&lt;code&gt;DML&lt;/code&gt; 数据操作语言，用来对数据库表中的数据进行增删改&lt;/li&gt;
&lt;li&gt;&lt;code&gt;QL&lt;/code&gt; 数据查询语言，用来查询数据库中的记录&lt;/li&gt;
&lt;li&gt;&lt;code&gt;DCL&lt;/code&gt; 数据控制语言，用来创建数据库用户、控住数据库的访问权限&lt;/li&gt;
&lt;/ol&gt;
&lt;h1&gt;DDL-数据库操作&lt;/h1&gt;
&lt;p&gt;查询：查询所有数据库  &lt;code&gt;SHOW DATABASES&lt;/code&gt; ;查询当前数据库 &lt;code&gt;SELECT DATABASE()&lt;/code&gt;;&lt;br&gt;
创建：&lt;code&gt;CREATE DATABASE [IF NOT EXISTS]&lt;/code&gt; 数据库名 &lt;code&gt;【DEFAULT CHARSET字符集】``【COLLATE排序规则】&lt;/code&gt;;&lt;br&gt;
删除：&lt;code&gt;DROP DATABASE【IF EXISTS】&lt;/code&gt; 数据库名；&lt;br&gt;
使用：&lt;code&gt;USE&lt;/code&gt; 数据库名；&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;DDL-表操作-查询&lt;/strong&gt;&lt;br&gt;
查询当前数据库所有表 :&lt;code&gt;SHOW TABLES&lt;/code&gt;;&lt;br&gt;
查询表结构：DESC 表名；&lt;br&gt;
查询指定表的建表语句：&lt;code&gt;SHOW CREATE TABLE&lt;/code&gt; 表名；&lt;br&gt;
&lt;strong&gt;DDL-表操作-创建&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-sql&#34;&gt;CREATE TABLE 表名(
    字段1	字段1类型 COMMENT 字段1注释，
    字段2	字段2类型 COMMENT 字段2注释，
    字段3	字段3类型 COMMENT 字段3注释，
    ......
    字段n	字段n类型 COMMENT 字段n注释
    ) COMMENT 表注释；      ##注意：【...】为可选参数，最后一个字段后面没有逗号
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;DDL-表操作-数值类型&lt;/strong&gt;&lt;br&gt;
MySQL中的数据类型很多，主要分为三类：数值类型、字符串类型、日期时间类型。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;数值类型：&lt;br&gt;
|类型|	大小|	范围（有符号）|	范围（无符号）|	用途|&lt;br&gt;
| :----: | :----: | :----: | :----: | :----: |&lt;br&gt;
|&lt;code&gt;TINYINT&lt;/code&gt;|	1字节|	(-128，127)	|0~255|	小整数值|&lt;br&gt;
|&lt;code&gt;SMALLINT&lt;/code&gt;|	2字节|	(-32 768，32 767)|	0~65 535|	大整数值|&lt;br&gt;
|&lt;code&gt;MEDIUMINT&lt;/code&gt;|	3字节|	(-8 388 608，8 388 607)|	0~16 777 215|	大整数值|&lt;br&gt;
|&lt;code&gt;INT&lt;/code&gt;或&lt;code&gt;INTEGER&lt;/code&gt;|	4字节|	(-2 147 483 648，2 147 483 647)|	0~4 294 967 295|	大整数值|&lt;br&gt;
|&lt;code&gt;BIGINT&lt;/code&gt;|	8字节|	(-9,223,372,036,854,775,808，9 223 372 036 854 775 807)|	0~18 446 744 073 709 551 615|	极大整数值|&lt;br&gt;
|&lt;code&gt;FLOAT&lt;/code&gt;|	4字节|	(-3.402 823 466 E+38，-1.175 494 351 E-38)，0，(1.175 494 351 E-38，3.402 823 466 351 E+38)|	0，(1.175 494 351 E-38，3.402 823 466 E+38)|	单精度浮点数值|&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;字符串类型：&lt;br&gt;
|类型|	大小|	用途|&lt;br&gt;
| :----: | :----: | :----: |&lt;br&gt;
|&lt;code&gt;CHAR&lt;/code&gt;|	0~255字节|	定长字符串|&lt;br&gt;
|&lt;code&gt;VARCHAR&lt;/code&gt;|	0~65535字节|	变长字符串|&lt;br&gt;
|&lt;code&gt;TINYBLOB&lt;/code&gt;|	0~255字节|	不超过255个字符的二进制字符串|&lt;br&gt;
|&lt;code&gt;TINYTEXT&lt;/code&gt;|	0~255字节|	短文本字符串|&lt;br&gt;
|&lt;code&gt;BLOB&lt;/code&gt;|	0~65 535字节|	二进制形式的长文本数据|&lt;br&gt;
|&lt;code&gt;TEXT&lt;/code&gt;|	0~65 535字节|	长文本数据|&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;日期时间类型：&lt;br&gt;
|类型|	大小（字节）|	范围|	格式|	用途|&lt;br&gt;
| :----: | :----: | :----: | :----: | :----: |&lt;br&gt;
|&lt;code&gt;DATE&lt;/code&gt;|	3|	1000-01-01/9999-12-31|	YYYY-MM-DD|	日期值|&lt;br&gt;
|&lt;code&gt;TIME&lt;/code&gt;|	3|	‘-838:59:59’/‘838:59:59’|	HH:MM:SS|	时间值或持续时间|&lt;br&gt;
|&lt;code&gt;YEAR&lt;/code&gt;|	1|	1901/2155|	YYYY|	年份值|&lt;br&gt;
|&lt;code&gt;DATETIME&lt;/code&gt;|	8|	1000-01-01 00:00:00/9999-12-31 23:59:59|	YYYY-MM-DD HH:MM:SS|	混合日期和时间值|&lt;br&gt;
|&lt;code&gt;TIMESTAMP&lt;/code&gt;|	4|	1970-01-01 00:00:01/2038 结束时间是第 2147483647 秒，北京时间 2038-1-19 11:14:07，格林尼治时间 2038年1月19日 凌晨 03:14:07|	YYYY-MM-DD HH:MM:SS|	混合日期和时间值，时间戳|&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;DDL-表操作-修改&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;添加字段：&lt;code&gt;ALTER TABLE&lt;/code&gt; 表名&lt;code&gt;ADD&lt;/code&gt;字段名 类型（长度）&lt;code&gt;【COMMENT 注释】``【约束】&lt;/code&gt;;&lt;/li&gt;
&lt;li&gt;修改数据类型：&lt;code&gt;ALTER TABLE&lt;/code&gt;表名&lt;code&gt;MODIFY&lt;/code&gt;字段名 新数据类型（长度）;&lt;/li&gt;
&lt;li&gt;修改字段名和字段类型：&lt;code&gt;ALTER TABLE&lt;/code&gt; 表名&lt;code&gt;CHANGE&lt;/code&gt; 旧字段名 新字段名 类型（长度）&lt;code&gt;【COMMENT注释】``【约束】&lt;/code&gt;;&lt;/li&gt;
&lt;li&gt;删除字段：&lt;code&gt;ALTER TABLE&lt;/code&gt; 表名&lt;code&gt;DROP&lt;/code&gt; 字段名；&lt;/li&gt;
&lt;li&gt;修改表名：&lt;code&gt;ALTER TABLE&lt;/code&gt; 表名 &lt;code&gt;RENAME TO&lt;/code&gt; 新表名；&lt;/li&gt;
&lt;li&gt;删除表：&lt;code&gt;DROP TABLE【IF EXISTS】&lt;/code&gt;表名；&lt;/li&gt;
&lt;li&gt;删除指定表，并重新创建该表：&lt;code&gt;TRUNCATE TABLE&lt;/code&gt; 表名；&lt;/li&gt;
&lt;/ol&gt;
&lt;h1&gt;DML-介绍&lt;/h1&gt;
&lt;blockquote&gt;
&lt;p&gt;DML英文全称是Data Manipulation Language(数据操作语言)，用来对数据库中的数据记录进行增删改操作。&lt;br&gt;
&lt;strong&gt;DML-添加数据：&lt;/strong&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ol&gt;
&lt;li&gt;给制定字段添加数据：&lt;br&gt;
&lt;code&gt;INSERT INTO&lt;/code&gt;表名(字段名1，字段名2，…) &lt;code&gt;VALUES&lt;/code&gt;（值1，值2，…）；&lt;/li&gt;
&lt;li&gt;给全部字段添加数据：&lt;br&gt;
&lt;code&gt;INSERT INTO&lt;/code&gt;表名&lt;code&gt;VALUES&lt;/code&gt;（值1，值2，…）；&lt;/li&gt;
&lt;li&gt;批量添加数据：&lt;br&gt;
&lt;code&gt;INSERT INTO&lt;/code&gt;表名（字段名1，字段名2，…）&lt;code&gt;VALUES&lt;/code&gt;（值1，值2，…），（值1，值2，…）；&lt;br&gt;
&lt;code&gt;INSERT INTO&lt;/code&gt;表名（值1，值2，…），（值1，值2，…），（值1，值2，…）；&lt;/li&gt;
&lt;li&gt;DML-修改数据：&lt;br&gt;
&lt;code&gt;UPDATE&lt;/code&gt; 表名 &lt;code&gt;SET&lt;/code&gt; &lt;code&gt;字段名1 = 值1&lt;/code&gt;，&lt;code&gt;字段名2 = 值2&lt;/code&gt;，…【WHERE 条件】；&lt;/li&gt;
&lt;li&gt;DML-删除数据：&lt;br&gt;
&lt;code&gt;DELETE FROM&lt;/code&gt; 表名【WHERE条件】&lt;/li&gt;
&lt;/ol&gt;
&lt;h1&gt;DQL-介绍&lt;/h1&gt;
&lt;blockquote&gt;
&lt;p&gt;DQL英文全称是Data Query Language(数据查询语言)，数据查询语言，用于查询数据库中表的记录。查询关键字：SELECT&lt;br&gt;
&lt;strong&gt;DQL-基本查询：&lt;/strong&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ol&gt;
&lt;li&gt;查询多个字段：&lt;br&gt;
&lt;code&gt;SELECT&lt;/code&gt; 字段，字段2，字段3…FROM 表名；&lt;br&gt;
&lt;code&gt;SELECT&lt;/code&gt; * FROM 表名；&lt;/li&gt;
&lt;li&gt;设置别名：&lt;br&gt;
&lt;code&gt;SELECT&lt;/code&gt; 字段1【AS 别名】，字段2【AS别名】。。。FROM表名；&lt;/li&gt;
&lt;li&gt;去除重复记录：&lt;br&gt;
&lt;code&gt;SELECT DISTINCT&lt;/code&gt; 字段列表FROM 表名；&lt;/li&gt;
&lt;li&gt;DQL-条件查询
&lt;ul&gt;
&lt;li&gt;语法：&lt;br&gt;
&lt;code&gt;SELECT&lt;/code&gt; 字段列表 &lt;code&gt;FROM&lt;/code&gt; 表名 &lt;code&gt;WHERE&lt;/code&gt; 条件列表；&lt;/li&gt;
&lt;li&gt;条件：&lt;br&gt;
比较运算符:&lt;br&gt;
|比较运算符|	功能|&lt;br&gt;
| :----: | :----: |&lt;br&gt;
|&lt;code&gt;&amp;gt;&lt;/code&gt;	|大于|&lt;br&gt;
|&lt;code&gt;&amp;gt;=&lt;/code&gt;	|大于等于|&lt;br&gt;
|&lt;code&gt;=&lt;/code&gt;	|等于|&lt;br&gt;
|&lt;code&gt;&amp;lt;&amp;gt;&lt;/code&gt;或&lt;code&gt;!=&lt;/code&gt;	|不等于|&lt;br&gt;
|&lt;code&gt;BETWEEN…AND&lt;/code&gt;|	在某个范围之内（含最小、最大值）|&lt;br&gt;
|&lt;code&gt;IN（…）&lt;/code&gt;|	在IN之后的列表中的值，多选一|&lt;br&gt;
|&lt;code&gt;LIKE&lt;/code&gt; 占位符	|模糊匹配（…匹配单个字符，%匹配热议字符）|&lt;br&gt;
|&lt;code&gt;IS NULL&lt;/code&gt;	|是NULL|&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;逻辑运算符:&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;逻辑运算符&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;AND&lt;/code&gt;或&lt;code&gt;&amp;amp;&amp;amp;&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;并且（多个条件同时成立）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;OR&lt;/code&gt;或`&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;NOT&lt;/code&gt;或！&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;非，不是&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;DQL- 聚合函数&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;介绍：将一列数据作为一个整体，进行纵向计算。&lt;/li&gt;
&lt;li&gt;常见聚合函数：&lt;br&gt;
|函数|	功能|&lt;br&gt;
| :----: | :----: |&lt;br&gt;
|&lt;code&gt;COUNT&lt;/code&gt;|	统计数量|&lt;br&gt;
|&lt;code&gt;MAX&lt;/code&gt;	|最大值|&lt;br&gt;
|&lt;code&gt;MIN&lt;/code&gt;|	最下值|&lt;br&gt;
|&lt;code&gt;AVG&lt;/code&gt;|	平均值|&lt;br&gt;
|&lt;code&gt;SUM&lt;/code&gt;	|求和|&lt;/li&gt;
&lt;li&gt;语法：&lt;br&gt;
&lt;code&gt;SELECT&lt;/code&gt; 聚合函数（字段列表）FROM 表名；&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;DQL-分组查询&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;语法&lt;br&gt;
&lt;code&gt; SELECT&lt;/code&gt; 字段列表 &lt;code&gt;FROM&lt;/code&gt; 表名【WHERE条件】&lt;code&gt;GROUP BY&lt;/code&gt; 分组字段名【HAVING 分组后过滤条件】；&lt;/li&gt;
&lt;li&gt;&lt;code&gt;where&lt;/code&gt;与&lt;code&gt;having&lt;/code&gt;区别:
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;执行时机不同：&lt;/strong&gt; where是分组之前进行过滤，不满足where条件，不参与分组；而having是分组之后对结果进行过滤；&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;判断条件不同：&lt;/strong&gt; where不能对聚类函数进行判断，而having可以。&lt;br&gt;
&lt;strong&gt;【注意】&lt;/strong&gt;&lt;br&gt;
执行顺序：where&amp;gt;聚合函数&amp;gt;having&lt;br&gt;
分组之后，查询的字段一般为聚合函数和分组字段，那其他字段无任何意义&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;7&#34;&gt;
&lt;li&gt;DQL-排序查询&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;语法
&lt;ul&gt;
&lt;li&gt;SELECT 字段列表 FROM 表名 ORDER BY 字段1 排序方式1，字段2 排序方式2；&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;排序方式
&lt;ul&gt;
&lt;li&gt;ASC：升序（默认）&lt;/li&gt;
&lt;li&gt;DESC：降序&lt;br&gt;
&lt;strong&gt;【注意】如果是多字段排序，当第一个字段值相同时，才会根据第二个字段进行排序。&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;8&#34;&gt;
&lt;li&gt;DQL-分页查询&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;语法:&lt;br&gt;
SELECT字段列表 FROM 表名 LIMIT起始索引，查询记录数；&lt;br&gt;
&lt;strong&gt;【注意】&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;起始索引从0开始，起始索引= （查询页数-1）*每页显示记录数&lt;/li&gt;
&lt;li&gt;分页查询是数据库的方言，不同的数据库有不同的实现，&lt;code&gt;MYSQL&lt;/code&gt;中是&lt;code&gt;LIMIT&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;如果查询的是第一页数据，起始索引可以省略，直接简写为&lt;code&gt;limit 10&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h1&gt;DCL-介绍&lt;/h1&gt;
&lt;blockquote&gt;
&lt;p&gt;DCL英文全称Data Control Language(数据控制语言)，用来管理数据库 用户、控制数据库的访问 权限。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ol&gt;
&lt;li&gt;DCL-管理用户&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;查询用户：&lt;br&gt;
&lt;code&gt;USE&lt;/code&gt; mysql;&lt;br&gt;
&lt;code&gt;SELECT&lt;/code&gt; * &lt;code&gt;FROM&lt;/code&gt; user;&lt;/li&gt;
&lt;li&gt;创建用户&lt;br&gt;
&lt;code&gt;CREATE USER&lt;/code&gt; ‘用户名’@‘主机名’ &lt;code&gt;IDENTIFIED BY&lt;/code&gt; ‘密码’；&lt;/li&gt;
&lt;li&gt;修改用户密码&lt;br&gt;
&lt;code&gt;ALTER USER&lt;/code&gt; ‘用户名’@‘主机名’&lt;code&gt;IDENTIFIED WITH&lt;/code&gt; mysql_native_password &lt;code&gt;BY&lt;/code&gt;‘新密码’；&lt;/li&gt;
&lt;li&gt;删除用户&lt;br&gt;
&lt;code&gt;DROP USER&lt;/code&gt; ‘用户名’@‘主机名’；&lt;br&gt;
&lt;strong&gt;【注意】&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;主机名可以使用%通配,示例：&lt;code&gt;&#39;root&#39;@&#39;localhost&#39;&lt;/code&gt;表示只能在本地登录；&lt;code&gt;&#39;root&#39;@&#39;%&#39;&lt;/code&gt;表示可以在任意主机登录&lt;/li&gt;
&lt;li&gt;这类SQL开发人员操作的比较少，主要是DBA（Database Administrator 数据库管理员）使用。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;DCL-权限控制&lt;br&gt;
MySQL中定义了很多种权限，但是常用的就一下几种:&lt;/li&gt;
&lt;/ol&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;权限&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;ALL&lt;/code&gt; 、&lt;code&gt;ALL PRIVILEGES&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;所有权限&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;SELECT&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;查询数据&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;INSERT&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;插入数据&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;UPDATE&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;修改数据&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;DELETE&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除数据&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;ALTER&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;修改表&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;DROP&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;删除数据库/表/视图&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;CREATE&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;创建数据库/表&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ul&gt;
&lt;li&gt;查询权限&lt;br&gt;
&lt;code&gt;SHOW&lt;/code&gt; &lt;code&gt;GRANTS&lt;/code&gt; &lt;code&gt;FOR&lt;/code&gt; ‘用户名’@‘主机名’；&lt;/li&gt;
&lt;li&gt;授予权限&lt;br&gt;
&lt;code&gt;GRANT&lt;/code&gt; 权限列表 &lt;code&gt;ON&lt;/code&gt; 数据库名 表名 &lt;code&gt;TO&lt;/code&gt; ‘用户名’@‘主机名’；&lt;/li&gt;
&lt;li&gt;撤销权限&lt;br&gt;
&lt;code&gt;REVOKE&lt;/code&gt; 权限列表 &lt;code&gt;ON&lt;/code&gt; 数据库名 表名 &lt;code&gt;FROM&lt;/code&gt; ‘用户名’@‘主机名’；&lt;br&gt;
&lt;strong&gt;【注意】&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;多个权限之间，使用逗号分隔&lt;/li&gt;
&lt;li&gt;授权书，数据库名和表名可以使用*进行通配，代表所有。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;函数&lt;/strong&gt;&lt;br&gt;
一段可以直接被另一程序调用的程序或代码&lt;br&gt;
字符串函数：MySQL中内置了很多字符串函数，常用的几个如下：&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;函数&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;CONCAT（S1,S2,..Sn）&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;字符串拼接，将S1,S2,…Sn拼接成一个字符穿&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;LOWER（str）&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;将字符串str全部转为小写&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;UPPER（str）&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;将字符串str全部转为大写&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;LPAD（str,n,pad）&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;左填充，用字符串pad对str的左边进行填充，达到n个字符串长度&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;RPAD（str，n，pad）&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;右填充，用字符串pad对str的右边进行填充，达到n个字符串长度&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;TRIM（str）&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;去掉字符串头部和尾部的空格&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;SUBSTRING(str,start,len)&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;返回从字符串str从start位置的len个长度的字符串&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;strong&gt;数值函数：&lt;/strong&gt;&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;函数&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;CEIL(X)&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;向上取整&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;FLOOR(X)&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;向下取整&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;MOD(x,y)&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;返回x/y的模&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;RAND()&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;返回0~1内的随机数&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;ROUND(X,Y)&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;求参数x的四舍五入的值，保留y位小数&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;strong&gt;日期函数：&lt;/strong&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;函数&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;功能&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:----:&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;:----:&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;CURDATE()&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;返回当前日期&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;CURTIME()&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;返回当前时间&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;NOW()&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;返回当前日期和时间&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;YEAR(date)&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;获取制定date的年份&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;MONTH(date)&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;获取指定date的月份&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;DAY（date）&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;获取指定date的日期&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;DATE_ADD(date, INTERVAL expr type)&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;返回日期/时间值加时间间隔expr后的时间&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;DATEDIFF(date1,date2)&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;返回起始时间date1和结束date2之间天数&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;strong&gt;流程函数：&lt;/strong&gt;&lt;br&gt;
流程函数也是很常用的一类函数，可以在SQL语句中实现条件筛选，从而提高语句的效率。&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;函数&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;功能&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;IF(value,t,f)&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;如果value为true,则返回t，否则返回f&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;IFNULL（value1,value2）&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;如果value1不为空，返回value1，否则返回value2&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;CASE&lt;/code&gt; &lt;code&gt;WHEN&lt;/code&gt;【val1】&lt;code&gt;THEN&lt;/code&gt;【res1】…&lt;code&gt;ELSE&lt;/code&gt;【dafault】&lt;code&gt;END&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;如果val1为true,返回res1,…否则返回default默认值&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;code&gt;CASE&lt;/code&gt;【expr】&lt;code&gt;WHEN&lt;/code&gt;【val1】&lt;code&gt;THEN&lt;/code&gt;【res1】…&lt;code&gt;ELSE&lt;/code&gt;【default】&lt;code&gt;END&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;如果expr的值等于val1,返回res1,…否则返回default默认值&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;strong&gt;约束&lt;/strong&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ul&gt;
&lt;li&gt;概念：约束是作用于表中字段上的规则，用于限制存储在表中的数据&lt;/li&gt;
&lt;li&gt;目的：保证数据库中数据的正确、有效性和完整性&lt;br&gt;
&lt;strong&gt;分类：&lt;/strong&gt;&lt;br&gt;
|约束|	描述|	关键字|&lt;br&gt;
| :----: | :----: | :----: |&lt;br&gt;
|非空约束|	限制该字段的数据不能为NULL	|NOT NULL|&lt;br&gt;
|唯一约束	|保证该字段的所有数据都是唯一、不重复的	|UNIQUE|&lt;br&gt;
|主键约束	|主键是一行数据的唯一标识、要求非空且唯一	|PRIMARY|&lt;br&gt;
|默认约束	|保存数据时，如果未指定该字段的值，则采用默认值	|DEFCK|&lt;br&gt;
|检查约束（8.0.16版本之后）|	保证字段满足某一个条件	|CHECK|&lt;br&gt;
|外键约束	|用来让两张表的数据之间建立连接，保证数据的一致性和完整性	|FOREIGN KEY|&lt;br&gt;
&lt;strong&gt;【注意】：约束是作用于表中字段上的，可以在创建表/修改表的时候添加约束。&lt;/strong&gt;&lt;br&gt;
&lt;strong&gt;外键约束&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;概念：外键用来让两张表的数据之间建立连接，从而保证数据的一致性和完整性。&lt;/li&gt;
&lt;li&gt;语法：
&lt;ul&gt;
&lt;li&gt;添加外键：&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-sql&#34;&gt;	CREATE TABLE 表名（
		字段名 数据类型，
		…
		【CONSTRAINT】【外键名称】FOREIGN KEY （外键字段名） REFERENCES 			主表（主表列名）
	）；
	ALTER TABLE 表名 ADD CONSTRAINT 外键名称 FOREIGN KEY （外键字段名） REFERENCES 主表（主表列名）；
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;删除外键：&lt;br&gt;
&lt;code&gt;ALTER ``TABLE&lt;/code&gt; 表名 &lt;code&gt;DROP&lt;/code&gt; &lt;code&gt;FPREIGN&lt;/code&gt; &lt;code&gt;KEY&lt;/code&gt; 外键名称；&lt;/li&gt;
&lt;li&gt;删除/更新行为：	&lt;br&gt;
|行为	|说明|&lt;br&gt;
| :----: | :----: |&lt;br&gt;
|&lt;code&gt;NO ACTION&lt;/code&gt;	|当在父表中删除/更新对应记录时，首先检查该记录是否有对应外键，如果有则不允许删除/更新。（与RESTRICT一致）|&lt;br&gt;
|&lt;code&gt;RESTRICT&lt;/code&gt;	|当父表中删除/更新记录时，首先检查记录是否有对应外键，如果有则不允许删除/更新。（与NO ACTION 一致）|&lt;br&gt;
|&lt;code&gt;CASCADE&lt;/code&gt;	|当父表中删除/更新记录时，首先检查记录是否有对应外键，如果有，则也删除/更新外键在子表中的记录。|&lt;br&gt;
|&lt;code&gt;SET NULL&lt;/code&gt;	|当父表中删除/更新记录时，首先检查记录是否有对应外键，如果有则设置子表中该外键值为NULL（这就要求该外键允许取NULL）|&lt;br&gt;
|&lt;code&gt;SET DEFAULT&lt;/code&gt;	|父表有变更时，子表将外键列设置成一个默认的值（lnnodb不支持）|&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;ALTER TABLE 表名 ADD CONSTRAINT 外键名称 FOREIGN KEY(外键字段) REFERENCES 主表名&lt;/p&gt;
&lt;h1&gt;多表查询&lt;/h1&gt;
&lt;p&gt;&lt;strong&gt;多表关系&lt;/strong&gt;&lt;br&gt;
项目开发中，在进行数据库表格结构设计时，会根据业务需求及业务模块之间的关系，分析并设计表结构，由于业务之间相互关联，所以各个表结构之间也存在着各种联系，基本分为三种： 一对多（多对一）、多对多、一对一。&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;一对多（多对一）：&lt;br&gt;
案例：部门与员工的关系&lt;br&gt;
关系：一个部门对应多个员工，一个员工对应一个部门&lt;br&gt;
实现：在多的一方建立外键，指向一的一方为主键&lt;/li&gt;
&lt;li&gt;多对多：&lt;br&gt;
案例：学生与课程的关系&lt;br&gt;
关系：一个学生可以选修对门课程，一门课程也可以供多个学生选择&lt;br&gt;
实现：建立第三张中间表，中间表至少包含两个外键，分别关联两方主键&lt;/li&gt;
&lt;li&gt;一对一：&lt;br&gt;
案例：用户与用户详情的关系&lt;br&gt;
关系：一对一关系，多用于单表拆分，将一张表的基础字段放在一张表中，		其他详情字段放在另一张表中，以提高操作效率。&lt;br&gt;
实现：在任意一方加入外键，关联另一方的主键，并且设置外键为唯一的			（UNIQUE）&lt;br&gt;
&lt;strong&gt;多表查询概述：&lt;/strong&gt;&lt;br&gt;
概述：指从多张表中查询数据。&lt;br&gt;
笛卡尔积：笛卡尔乘积是指在数学中，两个集合A集合和B集合的所有组合情况。（在多表查询时，需要消除无效的笛卡尔积）。&lt;br&gt;
&lt;strong&gt;多表查询分类：&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;连接查询：
&lt;ul&gt;
&lt;li&gt;内连接：相当于查询A、B交集部分数据&lt;/li&gt;
&lt;li&gt;外连接：
&lt;ul&gt;
&lt;li&gt;左外连接：查询左表所有数据，以及两张表交集部分数据&lt;/li&gt;
&lt;li&gt;右外连接：查询右表所有数据，以及两张表交集部分数据&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;自连接：当前表与自身的连接查询，自连接必须使用表别名&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;子查询：&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;连接查询-内连接（查询两表交集的部分）&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;内连接查询语法：
&lt;ul&gt;
&lt;li&gt;隐式内连接：
&lt;ul&gt;
&lt;li&gt;SELECT 字段列表 FROM 表1，表2 WHERE 条件…；&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;显示内连接：
&lt;ul&gt;
&lt;li&gt;SELECT 字段列表 FROM 表1【INNER】JOIN表2 ON 连接条件…;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;连接查询-外连接：&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;外连接查询语法：
&lt;ul&gt;
&lt;li&gt;左外连接：
&lt;ul&gt;
&lt;li&gt;SELECT字段列表 FROM 表1 LEFT【OUTER】JOIN 表2 ON条件…；&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;右外连接：
&lt;ul&gt;
&lt;li&gt;SELECT 字段列表 FROM 表1 RIGHT 【OUTER】JOIN表2ON条件…；&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;连接查询-自连接：&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;自连接查询语法：
&lt;ul&gt;
&lt;li&gt;SELECT 字段列表 FROM 表A 别名A JOIN 表A 别名B ON条件…；&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;自连接查询，可以是内连接查询，也可以是外连接查询。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;联合查询- union,union all&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;对于union查询，就是把多次查询结果联合起来，形成一个新的查询结果集&lt;/li&gt;
&lt;/ul&gt;

 &lt;h1&gt;多线程&lt;/h1&gt;
&lt;h2 id=&#34;线程池&#34;&gt;线程池&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;函数指针在线程池中的应用&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;// 定义任务结构体
struct Task &amp;#123;
    void (*function)(void* arg);  // 函数指针
    void* arg;                    // 参数
&amp;#125;;

// 线程池中的工作线程执行任务
void worker_thread(void* arg) &amp;#123;
    while (1) &amp;#123;
        struct Task* task = get_task_from_queue();
        task-&amp;gt;function(task-&amp;gt;arg);  // 执行具体任务
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;**​灵活性：**可以动态添加不同类型的任务（如网络请求、文件操作、计算任务）。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;​解耦：&lt;/strong&gt; 线程池代码无需知道任务具体内容，只需调用 &lt;code&gt;function(arg)&lt;/code&gt;。&lt;/li&gt;
&lt;/ul&gt;

 &lt;h1&gt;数据处理&lt;/h1&gt;
&lt;h2 id=&#34;大小端转换&#34;&gt;大小端转换&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;大端和小端是指字节序的存储方式，大端是指高位字节存储在低地址，小端是指低位字节存储在低地址。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ol&gt;
&lt;li&gt;基本定义与存储方式&lt;br&gt;
&lt;strong&gt;大端模式&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;高位字节存放在低地址上，低位字节存放在高地址上。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;0x12345678&lt;/code&gt;在内存中的存储方式为：&lt;code&gt;低地址--&amp;gt; 0x12 0x34 0x56 0x78 --&amp;gt;高地址&lt;/code&gt;&lt;br&gt;
&lt;strong&gt;小端模式&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;高位字节存放在高地址上，低位字节存放在低地址上。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;0x12345678&lt;/code&gt;在内存中的存储方式为： &lt;code&gt;低地址--&amp;gt;  0x78 0x56 0x34 0x12  --&amp;gt;高地址&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;直观对比​（以&lt;code&gt;0x1234&lt;/code&gt;为例）：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;|内存地址	|大端模式|	小端模式|&lt;br&gt;
|–|----|----|----|&lt;br&gt;
|0x4000	|0x12	|0x34|&lt;br&gt;
|0x4001	|0x34	|0x12|&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;设计原因与应用场景&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;为何存在两种模式？&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;硬件差异：&lt;/strong&gt; 不同处理器架构对多字节数据的处理逻辑不同。例如，x86架构（如Intel/AMD CPU）采用小端模式，而PowerPC、MIPS等处理器多采用大端模式。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;​效率考量：&lt;/strong&gt; 小端模式在强制类型转换时无需调整字节顺序（直接截取低地址数据即可），而大端模式便于快速判断符号位（符号位位于低地址）&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;应用场景&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;网络通信&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;网络传输：&lt;/strong&gt; TCP/IP协议规定数据传输采用大端模式(网络字节序)，因此小端设备需通过&lt;code&gt;htonl()&lt;/code&gt;等函数转换字节序传输。&lt;/li&gt;
&lt;li&gt;例如，发送&lt;code&gt;0x12345678&lt;/code&gt;时，小端设备需先转换为大端模式&lt;code&gt;0x78563412&lt;/code&gt;再传输，接收后需转回小端。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;跨平台开发&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;文件存储（如二进制文件）需明确字节序，否则不同平台读取时可能出错。&lt;/li&gt;
&lt;li&gt;例如，嵌入式设备与服务器通信时需统一字节序。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;判断当前系统的字节序&lt;/strong&gt;&lt;br&gt;
可通过以下方法检测当前系统是大端还是小端：&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;**联合体法：**利用联合体的内存共享特性读取多字节数据的首字节。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;
#include &amp;lt;iostream&amp;gt;
using namespace std;

bool isLittleEndian()&amp;#123;

    union &amp;#123; 
        uint32_t i; 
        uint8_t c[4]; 
    &amp;#125; test = &amp;#123;0x01020304&amp;#125;;

    return test.c[0] == 0x04; // 若为小端，则首字节为0x04
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;**宏定义法：**利用宏定义计算多字节数据的值。&lt;br&gt;
使用__BYTE_ORDER宏（Linux/Unix）或std::endian::native（C++20）直接判断&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;&lt;strong&gt;字节序转换函数&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;大端转小端：&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;uint16_t ntohs(uint16_t netshort);&lt;/code&gt;：将16位无符号整数从网络字节序转换为主机字节序。(windows下为&lt;code&gt;htons&lt;/code&gt;)&lt;/li&gt;
&lt;li&gt;&lt;code&gt;uint32_t ntohl(uint32_t netlong);&lt;/code&gt;：将32位无符号整数从网络字节序转换为主机字节序。(windows下为&lt;code&gt;htonl&lt;/code&gt;)&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;小端转大端：&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;uint16_t htons(uint16_t hostshort);&lt;/code&gt;：将16位无符号整数从主机字节序转换到网络字节序。(windows下为&lt;code&gt;ntohs&lt;/code&gt;)&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h1&gt;野指针&lt;/h1&gt;
&lt;blockquote&gt;
&lt;p&gt;指向无效内存地址（如未初始化、已释放或越界的内存）的指针，访问时可能导致程序崩溃或数据损坏&lt;/p&gt;
&lt;/blockquote&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;int* p;  
*p = 10;  // p 未初始化，指向随机地址（野指针）  
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;野指针的常见成因:&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;|场景	|描述	|示例|&lt;br&gt;
|–|----|----|----|&lt;br&gt;
|​未初始化指针	|指针变量未赋初值，默认指向随机内存区域| &lt;code&gt;int* p&lt;/code&gt; ;（未初始化为 NULL 或有效地址）|&lt;br&gt;
|​释放后未置空	|&lt;code&gt;free&lt;/code&gt; 或 &lt;code&gt;delete&lt;/code&gt; 后未将指针设为 &lt;code&gt;NULL&lt;/code&gt;，仍指向已释放内存| &lt;code&gt;free(p)&lt;/code&gt; ; 后未执行 &lt;code&gt;p = NULL&lt;/code&gt;;|&lt;br&gt;
|​越界访问	|指针操作超出变量作用域（如返回局部变量地址）|	函数返回栈内存指针导致后续访问失效|&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;规避野指针的最佳实践&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;初始化与置空
&lt;ul&gt;
&lt;li&gt;**初始化：**在声明指针时立即赋初值，避免指向随机内存。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;int* p = NULL;  // 初始化为 NULL  
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;**置空：**释放内存后立即将指针置为 &lt;code&gt;NULL&lt;/code&gt;，防止重复释放或访问已释放内存。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;free(p);  
p = NULL;    
&lt;/code&gt;&lt;/pre&gt;
&lt;/li&gt;
&lt;li&gt;作用域与生命周期管理
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;作用域：&lt;/strong&gt; 确保指针操作在变量有效作用域内，避免返回局部变量地址。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;边界检查：&lt;/strong&gt; 访问数组元素时进行边界检查，防止越界访问。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;智能指针：&lt;/strong&gt; 使用智能指针（如 &lt;code&gt;std::unique_ptr&lt;/code&gt;、&lt;code&gt;std::shared_ptr&lt;/code&gt;）自动管理内存，避免手动释放内存带来的问题。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;多线程环境下的防御措施
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;隔离线程数据：&lt;/strong&gt; 通过动态分配或线程局部存储（thread_local）为每个线程提供独立数据副本，避免数据竞争。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;互斥锁：&lt;/strong&gt; 在多线程访问共享数据时使用互斥锁（mutex）保护，防止并发访问导致的问题。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;原子操作：&lt;/strong&gt; 使用原子操作（atomic）确保对共享数据的访问是线程安全的。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h1&gt;拷贝构造与运算符重载&lt;/h1&gt;
&lt;blockquote&gt;
&lt;p&gt;拷贝构造函数和赋值运算符重载是C++中用于对象复制的两种机制，它们在对象创建和赋值时非常重要。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;拷贝构造函数&#34;&gt;拷贝构造函数&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;拷贝构造函数&lt;/strong&gt;是一种特殊的构造函数，用于创建一个新对象，并将另一个对象的值复制到新对象中。它的定义形式如下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;ClassName(const ClassName&amp;amp; other);
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;其中，&lt;code&gt;ClassName&lt;/code&gt;是类名，&lt;code&gt;other&lt;/code&gt;是另一个对象，类型为&lt;code&gt;ClassName&lt;/code&gt;的引用。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;拷贝构造函数的用途：&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;对象初始化：&lt;/strong&gt; 当使用一个已存在的对象来初始化另一个对象时，拷贝构造函数会被调用。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;ClassName obj1;
ClassName obj2 = obj1;  // 调用拷贝构造函数
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;strong&gt;函数参数传递：&lt;/strong&gt; 当将一个对象作为函数参数传递时，拷贝构造函数会被调用。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;void func(ClassName obj) &amp;#123;
    // ...
&amp;#125;

ClassName obj1;
func(obj1);  // 调用拷贝构造函数
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;&lt;strong&gt;函数返回值：&lt;/strong&gt; 当一个函数返回一个对象时，拷贝构造函数会被调用。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;ClassName func() &amp;#123;
    ClassName obj;  // ...
    return obj;  // 调用拷贝构造函数
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;赋值运算符重载&#34;&gt;赋值运算符重载&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;赋值运算符重载&lt;/strong&gt;是一种运算符重载，用于将一个对象的值赋给另一个对象。它的定义形式如下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;ClassName&amp;amp; operator=(const ClassName&amp;amp; other);
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;其中，&lt;code&gt;ClassName&lt;/code&gt;是类名，&lt;code&gt;other&lt;/code&gt;是另一个对象，类型为&lt;code&gt;ClassName&lt;/code&gt;的引用。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;赋值运算符重载的用途：&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;对象赋值：&lt;/strong&gt; 当使用一个已存在的对象来赋值给另一个对象时，赋值运算符重载会被调用。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;ClassName obj1;
ClassName obj2;
obj2 = obj1;  // 调用赋值运算符重载
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;strong&gt;函数返回值：&lt;/strong&gt; 当一个函数返回一个对象时，赋值运算符重载会被调用。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;ClassName func() &amp;#123;
    ClassName obj;  // ...
    return obj;  // 调用赋值运算符重载
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;拷贝构造函数与赋值运算符重载的区别&#34;&gt;拷贝构造函数与赋值运算符重载的区别&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;调用时机：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;拷贝构造函数在对象创建时调用，用于初始化新对象。   - 赋值运算符重载在对象赋值时调用，用于将一个对象的值赋给另一个对象。&lt;/li&gt;
&lt;li&gt;例如，当使用一个已存在的对象来初始化另一个对象时，会调用拷贝构造函数；当使用一个已存在的对象来赋值给另一个对象时，会调用赋值运算符重载。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;参数类型：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;拷贝构造函数的参数类型为&lt;code&gt;const ClassName&amp;amp;&lt;/code&gt;，表示引用另一个对象。   - 赋值运算符重载的参数类型为&lt;code&gt;const ClassName&amp;amp;&lt;/code&gt;，表示引用另一个对象。&lt;/li&gt;
&lt;li&gt;例如，拷贝构造函数的参数类型为&lt;code&gt;const ClassName&amp;amp;&lt;/code&gt;，表示引用另一个对象；赋值运算符重载的参数类型为&lt;code&gt;const ClassName&amp;amp;&lt;/code&gt;，表示引用另一个对象。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;返回值类型：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;拷贝构造函数的返回值类型为&lt;code&gt;ClassName&lt;/code&gt;，表示返回新对象。   - 赋值运算符重载的返回值类型为&lt;code&gt;ClassName&amp;amp;&lt;/code&gt;，表示返回对象的引用。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;拷贝构造函数与赋值运算符重载的示例&#34;&gt;拷贝构造函数与赋值运算符重载的示例&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;class MyClass &amp;#123;
public:
    int data;

    // 拷贝构造函数
    MyClass(const MyClass&amp;amp; other) &amp;#123;
        data = other.data;
    &amp;#125;

    // 赋值运算符重载
    MyClass&amp;amp; operator=(const MyClass&amp;amp; other) &amp;#123;
        if (this != &amp;amp;other) &amp;#123;
            data = other.data;
        &amp;#125;
        return *this;
    &amp;#125;
&amp;#125;;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;拷贝构造函数与赋值运算符重载的最佳实践&#34;&gt;拷贝构造函数与赋值运算符重载的最佳实践&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;避免浅拷贝：&lt;/strong&gt; 在拷贝构造函数和赋值运算符重载中，应避免浅拷贝，即直接复制指针而不是复制指针指向的内容。如果需要复制指针指向的内容，可以使用深拷贝。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;避免循环引用：&lt;/strong&gt; 在拷贝构造函数和赋值运算符重载中，应避免循环引用，即两个对象相互引用对方。如果需要相互引用，可以使用智能指针（如&lt;code&gt;std::shared_ptr&lt;/code&gt;）来管理对象的生命周期。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;避免内存泄漏：&lt;/strong&gt; 在拷贝构造函数和赋值运算符重载中，应避免内存泄漏，即释放内存后未将指针置为&lt;code&gt;NULL&lt;/code&gt;。如果需要释放内存，应将指针置为&lt;code&gt;NULL&lt;/code&gt;。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;避免异常安全：&lt;/strong&gt; 在拷贝构造函数和赋值运算符重载中，应确保异常安全，即当异常发生时，对象的状态应保持不变。可以使用RAII（Resource Acquisition Is Initialization）模式来确保资源正确释放。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;避免未定义行为：&lt;/strong&gt; 在拷贝构造函数和赋值运算符重载中，应避免未定义行为，即访问未初始化的指针或释放已释放的内存。可以使用断言（assert）来检测指针是否为&lt;code&gt;NULL&lt;/code&gt;，或使用智能指针来管理内存。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;避免性能问题：&lt;/strong&gt; 在拷贝构造函数和赋值运算符重载中，应避免性能问题，即复制大量数据或进行复杂的操作。可以使用移动语义（move semantics）来优化性能。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;避免代码重复：&lt;/strong&gt; 在拷贝构造函数和赋值运算符重载中，应避免代码重复，即重复编写相同的代码。可以使用模板函数或模板类来减少代码重复。&lt;/li&gt;
&lt;/ol&gt;
&lt;h1&gt;浅拷贝与深拷贝&lt;/h1&gt;
&lt;h2 id=&#34;浅拷贝&#34;&gt;浅拷贝&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;仅复制对象的顶层结构（如指针或引用），底层数据仍共享同一内存地址。修改拷贝后的对象会影响原对象&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;strong&gt;场景&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;默认拷贝构造函数：C++ 中类未重写拷贝构造函数时，默认进行浅拷贝。&lt;/li&gt;
&lt;li&gt;​数组/结构体赋值：直接复制数组或结构体时，引用类型成员共享地址&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;风险&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;**​数据竞争：**多线程环境下共享数据可能引发不一致问题。&lt;/li&gt;
&lt;li&gt;**​双重释放：**若共享内存被多次释放，可能导致内存泄漏或崩溃&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;浅拷贝的示例代码如下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;class MyClass &amp;#123;
public:
    int data;
    int* ptr;

    MyClass(int value) : data(value), ptr(new int(value)) &amp;#123;&amp;#125;

    // 浅拷贝构造函数
    MyClass(const MyClass&amp;amp; other) : data(other.data), ptr(other.ptr) &amp;#123;&amp;#125;

    // 浅拷贝赋值运算符重载
    MyClass&amp;amp; operator=(const MyClass&amp;amp; other) &amp;#123;
        if (this != &amp;amp;other) &amp;#123;
            data = other.data;
            ptr = other.ptr;
        &amp;#125;
        return *this;
    &amp;#125;
&amp;#125;;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;深拷贝&#34;&gt;深拷贝&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;复制对象的顶层结构及底层数据，确保拷贝后的对象与原对象完全独立。修改拷贝后的对象不会影响原对象&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;strong&gt;实现方式&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;手动递归复制：&lt;/strong&gt; 对于复杂对象，手动递归复制每个成员变量。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;拷贝构造函数：&lt;/strong&gt; 重载拷贝构造函数，实现深拷贝。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;赋值运算符重载：&lt;/strong&gt; 重载赋值运算符重载，实现深拷贝。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;优势&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;数据独立：&lt;/strong&gt; 拷贝后的对象与原对象完全独立，修改一个对象不影响另一个对象。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;内存安全：&lt;/strong&gt; 避免数据竞争和双重释放问题，确保内存安全。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;劣势&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;性能开销：&lt;/strong&gt; 深拷贝需要复制大量数据，可能导致性能开销。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;深拷贝的示例代码如下：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-cpp&#34;&gt;class MyClass &amp;#123;
public:
    int data;
    int* ptr;

    MyClass(int value) : data(value), ptr(new int(value)) &amp;#123;&amp;#125;

    // 深拷贝构造函数
    MyClass(const MyClass&amp;amp; other) : data(other.data), ptr(new int(*other.ptr)) &amp;#123;&amp;#125;

    // 深拷贝赋值运算符重载
    MyClass&amp;amp; operator=(const MyClass&amp;amp; other) &amp;#123;
        if (this != &amp;amp;other) &amp;#123;
            data = other.data;
            delete ptr;  // 释放原指针指向的内存
            ptr = new int(*other.ptr);  // 分配新内存并复制数据
        &amp;#125;
        return *this;
    &amp;#125;
&amp;#125;;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;浅拷贝与深拷贝的区别&#34;&gt;浅拷贝与深拷贝的区别&lt;/h2&gt;
&lt;p&gt;| 特性  | 浅拷贝  | 深拷贝   |&lt;/p&gt;
&lt;p&gt;| :---- | :----- | :------ |&lt;/p&gt;
&lt;p&gt;| 复制方式 | 复制顶层结构，共享底层数据 | 复制顶层结构及底层数据，独立内存 |&lt;/p&gt;
&lt;p&gt;| 修改影响 | 修改拷贝后的对象会影响原对象 | 修改拷贝后的对象不影响原对象 |&lt;/p&gt;
&lt;p&gt;| 内存管理 | 共享内存，可能导致数据竞争或内存泄漏 | 独立内存，内存安全 |&lt;/p&gt;
&lt;p&gt;| 性能开销 | 较低，直接复制指针 | 较高，需要复制大量数据 |&lt;/p&gt;

 &lt;blockquote&gt;
&lt;p&gt;LSTM（Long Short-Term Memory）是一种特殊的循环神经网络（RNN），它通过引入门控机制来缓解梯度消失和梯度爆炸问题，从而能够更好地处理长序列数据。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;LSTM的结构&#34;&gt;LSTM的结构&lt;/h2&gt;
&lt;p&gt;LSTM的基本结构包括三个门：输入门（input gate）、遗忘门（forget gate）和输出门（output gate），以及一个记忆单元（cell state）。这些门和单元共同作用，使得LSTM能够记住长序列中的信息。&lt;/p&gt;
&lt;p&gt;LSTM的输入包括当前时间步的输入数据 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;x_t&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.5806em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.2806em;&#34;&gt;&lt;span style=&#34;top:-2.55em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 和前一时间步的隐藏状态 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;h_{t-1}&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.9028em;vertical-align:-0.2083em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;h&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.3011em;&#34;&gt;&lt;span style=&#34;top:-2.55em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mbin mtight&#34;&gt;−&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.2083em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;。输入门控制着当前时间步的输入数据如何更新记忆单元，遗忘门控制着前一时间步的记忆单元如何被遗忘，输出门控制着当前时间步的记忆单元如何被输出。&lt;/p&gt;
&lt;p&gt;LSTM的输出包括当前时间步的隐藏状态 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;h_t&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8444em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;h&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.2806em;&#34;&gt;&lt;span style=&#34;top:-2.55em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 和记忆单元 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;c&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;c_t&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.5806em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;c&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.2806em;&#34;&gt;&lt;span style=&#34;top:-2.55em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;。隐藏状态 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;h_t&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8444em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;h&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.2806em;&#34;&gt;&lt;span style=&#34;top:-2.55em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是LSTM的输出，可以用于后续的神经网络层。记忆单元 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;c&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;c_t&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.5806em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;c&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.2806em;&#34;&gt;&lt;span style=&#34;top:-2.55em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是LSTM的记忆状态，可以保留长序列中的信息。&lt;/p&gt;
&lt;h2 id=&#34;LSTM的数学表达式&#34;&gt;LSTM的数学表达式&lt;/h2&gt;
&lt;p&gt;LSTM的输入门、遗忘门和输出门的计算公式如下：&lt;/p&gt;
&lt;p class=&#34;katex-block &#34;&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mtable rowspacing=&#34;0.25em&#34; columnalign=&#34;right left&#34; columnspacing=&#34;0em&#34;&gt;&lt;mtr&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;true&#34;&gt;&lt;msub&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;true&#34;&gt;&lt;mrow&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;σ&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;W&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;msub&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;W&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;msub&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;/mtr&gt;&lt;mtr&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;true&#34;&gt;&lt;msub&gt;&lt;mi&gt;f&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;true&#34;&gt;&lt;mrow&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;σ&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;W&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mi&gt;f&lt;/mi&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;msub&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;W&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mi&gt;f&lt;/mi&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;msub&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;mi&gt;f&lt;/mi&gt;&lt;/msub&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;/mtr&gt;&lt;mtr&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;true&#34;&gt;&lt;msub&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;true&#34;&gt;&lt;mrow&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;σ&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;W&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;msub&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;W&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;msub&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;/msub&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;/mtr&gt;&lt;/mtable&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\begin{aligned}
i_t &amp;amp;= \sigma(W_{xi}x_t + W_{hi}h_{t-1} + b_i)\\
f_t &amp;amp;= \sigma(W_{xf}x_t + W_{hf}h_{t-1} + b_f)\\
o_t &amp;amp;= \sigma(W_{xo}x_t + W_{ho}h_{t-1} + b_o)\\
