34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;W&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.3361em;&#34;&gt;&lt;span style=&#34;top:-2.55em;margin-left:-0.1389em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;h&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;c&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;h&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.3011em;&#34;&gt;&lt;span style=&#34;top:-2.55em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mbin mtight&#34;&gt;−&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.2083em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;b&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.1514em;&#34;&gt;&lt;span style=&#34;top:-2.55em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;c&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.5em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;其中，&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∘&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\circ&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.4445em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;∘&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是元素级乘积，&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;tanh&lt;/mi&gt;&lt;mo&gt;⁡&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\tanh&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.6944em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop&#34;&gt;tanh&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是双曲正切函数，&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;W&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mi&gt;c&lt;/mi&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;W_{xc}&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;W&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.1514em;&#34;&gt;&lt;span style=&#34;top:-2.55em;margin-left:-0.1389em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;c&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;、&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;W&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mi&gt;c&lt;/mi&gt;&lt;/mrow&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;W_{hc}&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;W&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.3361em;&#34;&gt;&lt;span style=&#34;top:-2.55em;margin-left:-0.1389em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;h&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;c&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;、&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;mi&gt;c&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;b_c&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8444em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;b&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.1514em;&#34;&gt;&lt;span style=&#34;top:-2.55em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;c&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是可学习的参数。&lt;/p&gt;
&lt;p&gt;LSTM的隐藏状态的更新公式如下：&lt;/p&gt;
&lt;p class=&#34;katex-block &#34;&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mtable rowspacing=&#34;0.25em&#34; columnalign=&#34;right left&#34; columnspacing=&#34;0em&#34;&gt;&lt;mtr&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;true&#34;&gt;&lt;msub&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mstyle scriptlevel=&#34;0&#34; displaystyle=&#34;true&#34;&gt;&lt;mrow&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;mo&gt;∘&lt;/mo&gt;&lt;mi&gt;tanh&lt;/mi&gt;&lt;mo&gt;⁡&lt;/mo&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;c&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/msub&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;/mstyle&gt;&lt;/mtd&gt;&lt;/mtr&gt;&lt;/mtable&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\begin{aligned}
h_t &amp;amp;= o_t \circ \tanh(c_t)
\end{aligned}
&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.5em;vertical-align:-0.5em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mtable&#34;&gt;&lt;span class=&#34;col-align-r&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:1em;&#34;&gt;&lt;span style=&#34;top:-3.16em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;h&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.2806em;&#34;&gt;&lt;span style=&#34;top:-2.55em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.5em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;col-align-l&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:1em;&#34;&gt;&lt;span style=&#34;top:-3.16em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.2806em;&#34;&gt;&lt;span style=&#34;top:-2.55em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;∘&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop&#34;&gt;tanh&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;c&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.2806em;&#34;&gt;&lt;span style=&#34;top:-2.55em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.5em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;其中，&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;tanh&lt;/mi&gt;&lt;mo&gt;⁡&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\tanh&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.6944em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop&#34;&gt;tanh&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是双曲正切函数。&lt;/p&gt;
&lt;h2 id=&#34;LSTM的应用&#34;&gt;LSTM的应用&lt;/h2&gt;
&lt;p&gt;LSTM在许多领域都有广泛的应用，包括但不限于：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;自然语言处理：LSTM可以用于文本分类、情感分析、机器翻译等任务。&lt;/li&gt;
&lt;li&gt;语音识别：LSTM可以用于语音识别、语音合成等任务。&lt;/li&gt;
&lt;li&gt;时间序列预测：LSTM可以用于股票价格预测、天气预测等任务。&lt;/li&gt;
&lt;/ul&gt;

 &lt;h1&gt;进程管理&lt;/h1&gt;
&lt;p&gt;&lt;strong&gt;Windows&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-powerShell&#34;&gt;# 查找进程 PID
tasklist | findstr &amp;quot;uvicorn&amp;quot;
# 终止进程（将 12345 替换为实际 PID）
taskkill /F /PID 12345
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;Linux&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;# 查找进程 PID
ps -ef | grep &amp;quot;python&amp;quot;
# 终止进程（将 12345 替换为实际 PID）
kill -9 12345
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;文件操作&lt;/h1&gt;
&lt;p&gt;&lt;strong&gt;Windows&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-powershell&#34;&gt;# 查找文件
dir /s /p &amp;quot;C:\Users\用户名\Downloads\*.pdf&amp;quot;
# 删除文件
del /s /q &amp;quot;C:\Users\用户名\Downloads\*.pdf&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;Linux&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;# 查找文件
find /home/用户名/Downloads -name &amp;quot;*.pdf&amp;quot;
# 删除文件
rm -rf /home/用户名/Downloads/*.pdf
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;解压文件&lt;/h1&gt;
&lt;p&gt;&lt;strong&gt;Windows&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-powershell&#34;&gt;# 解压 zip 文件
expand &amp;quot;C:\Users\用户名\Downloads\file.zip&amp;quot; &amp;quot;C:\Users\用户名\Downloads\file&amp;quot;
# 解压 rar 文件
rar x &amp;quot;C:\Users\用户名\Downloads\file.rar&amp;quot; &amp;quot;C:\Users\用户名\Downloads\file&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;Linux&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;# 解压 zip 文件
unzip &amp;quot;file.zip&amp;quot; -d &amp;quot;file&amp;quot;
# 解压 rar 文件
unrar x &amp;quot;file.rar&amp;quot; &amp;quot;file&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;移动文件&lt;/h1&gt;
&lt;p&gt;&lt;strong&gt;Windows&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-powershell&#34;&gt;# 移动文件
move &amp;quot;C:\Users\用户名\Downloads\file&amp;quot; &amp;quot;C:\Users\用户名\Documents&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;Linux&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-bash&#34;&gt;# 移动文件
mv &amp;quot;file&amp;quot; &amp;quot;Documents&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;Linux常用指令&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;文件目录类&lt;br&gt;
|格式|示例|说明|&lt;br&gt;
|:—:|:—:|:—:|&lt;br&gt;
|&lt;code&gt;ls&lt;/code&gt;|&lt;code&gt;ls -l&lt;/code&gt;|列出目录内容|&lt;br&gt;
|&lt;code&gt;cd&lt;/code&gt;|&lt;code&gt;cd Documents&lt;/code&gt;|切换目录|&lt;br&gt;
|&lt;code&gt;pwd&lt;/code&gt;|&lt;code&gt;pwd&lt;/code&gt;|显示当前目录|&lt;br&gt;
|&lt;code&gt;mkdir&lt;/code&gt;|&lt;code&gt;mkdir new_folder&lt;/code&gt;|创建新目录|&lt;br&gt;
|&lt;code&gt;rmdir&lt;/code&gt;|&lt;code&gt;rmdir empty_folder&lt;/code&gt;|删除空目录|&lt;br&gt;
|&lt;code&gt;rm&lt;/code&gt;|&lt;code&gt;rm file&lt;/code&gt;|删除文件|&lt;br&gt;
|&lt;code&gt;cp&lt;/code&gt;|&lt;code&gt;cp file1 file2&lt;/code&gt;|复制文件|&lt;br&gt;
|&lt;code&gt;mv&lt;/code&gt;|&lt;code&gt;mv file1 file2&lt;/code&gt;|移动或重命名文件|&lt;br&gt;
|&lt;code&gt;find&lt;/code&gt;|&lt;code&gt;find . -name &amp;quot;*.txt&amp;quot;&lt;/code&gt;|查找文件|&lt;br&gt;
|&lt;code&gt;grep&lt;/code&gt;|&lt;code&gt;grep &amp;quot;text&amp;quot; file.txt&lt;/code&gt;|在文件中查找文本|&lt;br&gt;
|&lt;code&gt;cat&lt;/code&gt;|&lt;code&gt;cat file.txt&lt;/code&gt;|显示文件内容|&lt;br&gt;
|&lt;code&gt;more&lt;/code&gt;|&lt;code&gt;more file.txt&lt;/code&gt;|逐页显示文件内容|&lt;br&gt;
|&lt;code&gt;less&lt;/code&gt;|&lt;code&gt;less file.txt&lt;/code&gt;|逐页显示文件内容，可向上翻页|&lt;br&gt;
|&lt;code&gt;head&lt;/code&gt;|&lt;code&gt;head -n 10 file.txt&lt;/code&gt;|显示文件前 10 行|&lt;br&gt;
|&lt;code&gt;tail&lt;/code&gt;|&lt;code&gt;tail -n 10 file.txt&lt;/code&gt;|显示文件后 10 行|&lt;br&gt;
|&lt;code&gt;chmod&lt;/code&gt;|&lt;code&gt;chmod 755 file&lt;/code&gt;|更改文件权限|&lt;br&gt;
|&lt;code&gt;chown&lt;/code&gt;|&lt;code&gt;chown user:group file&lt;/code&gt;|更改文件所有者|&lt;br&gt;
|&lt;code&gt;tar&lt;/code&gt;|&lt;code&gt;tar -cvf archive.tar file1 file2&lt;/code&gt;|创建 tar 归档文件|&lt;br&gt;
|&lt;code&gt;gzip&lt;/code&gt;|&lt;code&gt;gzip file&lt;/code&gt;|压缩文件|&lt;br&gt;
|&lt;code&gt;gunzip&lt;/code&gt;|&lt;code&gt;gunzip file.gz&lt;/code&gt;|解压 gzip 压缩文件|&lt;br&gt;
|&lt;code&gt;zip&lt;/code&gt;|&lt;code&gt;zip archive.zip file1 file2&lt;/code&gt;|创建 zip 压缩文件|&lt;br&gt;
|&lt;code&gt;unzip&lt;/code&gt;|&lt;code&gt;unzip archive.zip&lt;/code&gt;|解压 zip 压缩文件|&lt;br&gt;
|&lt;code&gt;mv&lt;/code&gt;|&lt;code&gt;mv file1 file2&lt;/code&gt;|移动或重命名文件|&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;系统管理类&lt;br&gt;
|格式|示例|说明|&lt;br&gt;
|:—:|:—:|:—:|&lt;br&gt;
|&lt;code&gt;ps&lt;/code&gt;|&lt;code&gt;ps -ef&lt;/code&gt;|显示当前进程|&lt;br&gt;
|&lt;code&gt;top&lt;/code&gt;|&lt;code&gt;top&lt;/code&gt;|实时显示系统资源使用情况|&lt;br&gt;
|&lt;code&gt;kill&lt;/code&gt;|&lt;code&gt;kill -9 12345&lt;/code&gt;|终止进程|&lt;br&gt;
|&lt;code&gt;free&lt;/code&gt;|&lt;code&gt;free -h&lt;/code&gt;|显示内存使用情况|&lt;br&gt;
|&lt;code&gt;df&lt;/code&gt;|&lt;code&gt;df -h&lt;/code&gt;|显示磁盘使用情况|&lt;br&gt;
|&lt;code&gt;du&lt;/code&gt;|&lt;code&gt;du -sh /path/to/directory&lt;/code&gt;|显示目录大小|&lt;br&gt;
|&lt;code&gt;scp&lt;/code&gt;|&lt;code&gt;scp file user@hostname:/path/to/destination&lt;/code&gt;|远程复制文件|&lt;br&gt;
|&lt;code&gt;wget&lt;/code&gt;|&lt;code&gt;wget http://example.com/file&lt;/code&gt;|下载文件|&lt;br&gt;
|&lt;code&gt;curl&lt;/code&gt;|&lt;code&gt;curl -O http://example.com/file&lt;/code&gt;|下载文件|&lt;br&gt;
|&lt;code&gt;apt&lt;/code&gt;|&lt;code&gt;apt-get install package&lt;/code&gt;|安装软件包|&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;用户管理类&lt;br&gt;
|格式|示例|说明|&lt;br&gt;
|:—:|:—:|:—:|&lt;br&gt;
|&lt;code&gt;who&lt;/code&gt;|&lt;code&gt;who&lt;/code&gt;|显示当前登录用户|&lt;br&gt;
|&lt;code&gt;w&lt;/code&gt;|&lt;code&gt;w&lt;/code&gt;|显示当前登录用户及其活动|&lt;br&gt;
|&lt;code&gt;id&lt;/code&gt;|&lt;code&gt;id user&lt;/code&gt;|显示用户信息|&lt;br&gt;
|&lt;code&gt;useradd&lt;/code&gt;|&lt;code&gt;useradd newuser&lt;/code&gt;|创建新用户|&lt;br&gt;
|&lt;code&gt;userdel&lt;/code&gt;|&lt;code&gt;userdel newuser&lt;/code&gt;|删除用户|&lt;br&gt;
|&lt;code&gt;passwd&lt;/code&gt;|&lt;code&gt;passwd user&lt;/code&gt;|更改用户密码|&lt;br&gt;
|&lt;code&gt;su&lt;/code&gt;|&lt;code&gt;su - user&lt;/code&gt;|切换用户|&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;网络管理类&lt;br&gt;
|格式|示例|说明|&lt;br&gt;
|:—:|:—:|:—:|&lt;br&gt;
|&lt;code&gt;ifconfig&lt;/code&gt;|&lt;code&gt;ifconfig&lt;/code&gt;|显示网络接口信息|&lt;br&gt;
|&lt;code&gt;ping&lt;/code&gt;|&lt;code&gt;ping www.google.com&lt;/code&gt;|测试网络连接|&lt;br&gt;
|&lt;code&gt;traceroute&lt;/code&gt;|&lt;code&gt;traceroute www.google.com&lt;/code&gt;|追踪网络路径|&lt;br&gt;
|&lt;code&gt;netstat&lt;/code&gt;|&lt;code&gt;netstat -an&lt;/code&gt;|显示网络连接|&lt;br&gt;
|&lt;code&gt;ssh&lt;/code&gt;|&lt;code&gt;ssh user@hostname&lt;/code&gt;|远程登录|&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;

 &lt;h1&gt;面向对象&lt;/h1&gt;
&lt;blockquote&gt;
&lt;p&gt;面向对象编程是一种编程范式或编程风格。它以类和对象为核心，将数据（属性）和操作（方法）封装在一起，通过继承和多态等机制实现代码的重用和扩展。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;类&#34;&gt;类&lt;/h2&gt;
&lt;p&gt;类是面向对象编程中的基本概念，它是一种抽象的数据类型，用于定义对象的属性和行为。类可以看作是对象的模板，通过类可以创建多个具有相同属性和行为的对象。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;类的定义&lt;/strong&gt;&lt;br&gt;
在Python中，使用&lt;code&gt;class&lt;/code&gt;关键字来定义一个类。&lt;/p&gt;
&lt;p&gt;注意：类名通常使用大写字母开头，遵循驼峰命名法。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;# 基本格式：
# class 类名:
#     类的属性和方法

class ClassName:
    # 类的属性
    name = &amp;quot;name&amp;quot;

    # 类的方法
    def method(self):
        print(&amp;quot;method id：&amp;quot;, self)  # self是类实例的引用，用于访问类的属性和方法

# 实例化
class_instance = ClassName()
print(&amp;quot;class_instance id is:&amp;quot;, class_instance)
class_instance.method()

&amp;quot;&amp;quot;&amp;quot;
结果：
class_instance id is: &amp;lt;__main__.ClassName object at 0x000001CE2FEA9FD0&amp;gt;
method id： &amp;lt;__main__.ClassName object at 0x000001CE2FEA9FD0&amp;gt;
&amp;quot;&amp;quot;&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol&gt;
&lt;li&gt;构造函数&lt;code&gt;__init__()&lt;/code&gt;
&lt;ul&gt;
&lt;li&gt;构造函数是类的一个特殊方法，用于初始化对象的状态。当创建对象时，Python会自动调用构造函数。&lt;/li&gt;
&lt;li&gt;构造函数的第一个参数必须是&lt;code&gt;self&lt;/code&gt;，表示对象本身的引用。&lt;/li&gt;
&lt;li&gt;构造函数可以接受任意数量的参数，用于初始化对象的属性。&lt;/li&gt;
&lt;li&gt;构造函数可以返回任意类型的值，但通常返回&lt;code&gt;None&lt;/code&gt;。&lt;/li&gt;
&lt;li&gt;构造函数可以包含任意数量的代码，用于执行初始化操作。&lt;/li&gt;
&lt;li&gt;构造函数可以调用其他方法，用于执行初始化操作。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class ClassName:
    def __init__(self, name): #self--实例本身，name--实例属性（非类属性）
        self.name = name

class_instance = ClassName(&amp;quot;name&amp;quot;)
print(&amp;quot;class_instance.name is:&amp;quot;, class_instance.name)
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;析构函数&lt;code&gt;__del__()&lt;/code&gt;
&lt;ul&gt;
&lt;li&gt;析构函数是类的一个特殊方法，用于在对象被销毁时执行清理操作。当对象被销毁时，Python会自动调用析构函数。&lt;/li&gt;
&lt;li&gt;析构函数的第一个参数必须是&lt;code&gt;self&lt;/code&gt;，表示对象本身的引用。&lt;/li&gt;
&lt;li&gt;析构函数可以接受任意数量的参数，用于执行清理操作。&lt;/li&gt;
&lt;li&gt;析构函数可以返回任意类型的值，但通常返回&lt;code&gt;None&lt;/code&gt;。&lt;/li&gt;
&lt;li&gt;析构函数可以包含任意数量的代码，用于执行清理操作。&lt;/li&gt;
&lt;li&gt;析构函数可以调用其他方法，用于执行清理操作。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class ClassName:
    def __init__(self, name):
        self.name = name

    def __del__(self):
        print(&amp;quot;del ClassName&amp;quot;)

class_instance = ClassName(&amp;quot;name&amp;quot;)
del class_instance # 或者 class_instance = None (删除对象)
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;封装&lt;/h1&gt;
&lt;p&gt;封装：面向对象编程中的一个重要概念，它指的是将对象的属性和方法封装在一起，形成一个独立的单元。&lt;br&gt;
目的：隐藏对象的内部实现细节，只对外提供必要的接口，从而提高代码的可维护性和安全性。&lt;/p&gt;
&lt;p&gt;在Python中，可以通过以下方式实现封装：&lt;/p&gt;
&lt;h2 id=&#34;隐藏属性&#34;&gt;隐藏属性&lt;/h2&gt;
&lt;p&gt;使用&lt;code&gt;__&lt;/code&gt;双下划线开头的属性名或方法名，表示私有，只能在类的内部访问。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class ClassName:
    name = &amp;quot;name&amp;quot;
    __age = 18

class_instance = ClassName()

print(&amp;quot;class_instance.name is:&amp;quot;, class_instance.name) # √

print(&amp;quot;class_instance.__age is:&amp;quot;, class_instance.__age) # × AttributeError: &#39;ClassName&#39; object has no attribute &#39;__age&#39;

## 隐藏属性实际上是将类名修改为： _类名__属性名 
print(&amp;quot;class_instance.__age is:&amp;quot;, class_instance._ClassName__age) # √
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;私有属性-方法&#34;&gt;私有属性/方法&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;xxx&lt;/code&gt;：普通属性/方法，可以在类的外部访问。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;_xxx&lt;/code&gt;：受保护的属性/方法，如果定义在类中，可以外部访问，也可以子类中访问。但是另外的&lt;code&gt;.py&lt;/code&gt;文件通过&lt;code&gt;from import *&lt;/code&gt;导入时，&lt;code&gt;_xxx&lt;/code&gt;属性/方法不会被导入。
&lt;ul&gt;
&lt;li&gt;这种一般是为了避免与python关键字冲突而采用的命名方法。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;__xxx&lt;/code&gt;：双下划线开头，隐藏的属性/方法，只能在类的内部访问，如果定义在类中，子类不会继承。
&lt;ul&gt;
&lt;li&gt;这种命名一般是python中的魔法方法或者属性，都是有特殊含义和功能的，自己不要轻易定义。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;私有属性&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class ClassName:
    name = &amp;quot;name&amp;quot;
    _age = 18
    __sex = &amp;quot;male&amp;quot;

class_instance = ClassName()

print(&amp;quot;class_instance.name is:&amp;quot;, class_instance.name) # √
print(&amp;quot;class_instance._age is:&amp;quot;, class_instance._age) # √
print(&amp;quot;class_instance.__sex is:&amp;quot;, class_instance.__sex) # × AttributeError: &#39;ClassName&#39; object has no attribute &#39;__sex&#39;
print(&amp;quot;class_instance._ClassName__sex is:&amp;quot;, class_instance._ClassName__sex) # √
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;隐藏方法&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Man:
    def __play(self):
        print(&amp;quot;write code&amp;quot;)
    def funa(self):
        # 内部调用私有方法
        self.__play() # 类内部调用私有方法
        Man.__play(self) # 类内部调用私有方法（不推荐）

man = Man()
man.funa() # √ 类内部调用私有方法
man.__play() # × AttributeError: &#39;Man&#39; object has no attribute &#39;__play&#39;
&amp;quot;&amp;quot;&amp;quot;
输出：
write code
&amp;quot;&amp;quot;&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;私有方法&lt;/strong&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Gril:
    def _play(self): #私有方法
        print(&amp;quot;play game&amp;quot;)

gril = Gril()
gril._play() # √
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;继承&lt;/h1&gt;
&lt;p&gt;继承：面向对象编程中的一个重要概念，它指的是一个类可以继承另一个类的属性和方法，从而实现代码的重用和扩展。&lt;/p&gt;
&lt;p&gt;格式：&lt;code&gt;class 子类名(父类名):&lt;/code&gt;&lt;/p&gt;
&lt;h2 id=&#34;单继承&#34;&gt;单继承&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Persion:
    def eat(self):
        print(&amp;quot;eat&amp;quot;)
    def sing(self):
        print(&amp;quot;sing&amp;quot;)

class Student(Persion):
    pass # 占位符，表示不添加任何新的属性和方法

student = Student()
student.eat() # √
student.sing() # √
&amp;quot;&amp;quot;&amp;quot;
输出：
eat
sing
&amp;quot;&amp;quot;&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;继承的传递（多重继承）&#34;&gt;继承的传递（多重继承）&lt;/h2&gt;
&lt;p&gt;子类可以继承父类的属性和方法，也可以继承父类的父类的属性和方法。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Persion:
    def eat(self):
        print(&amp;quot;eat&amp;quot;)
    def sing(self):
        print(&amp;quot;sing&amp;quot;)

class Student(Persion):
    pass

class Teacher(Student):
    pass

teacher = Teacher()
teacher.eat() # √
teacher.sing() # √
&amp;quot;&amp;quot;&amp;quot;
输出：
eat
sing
&amp;quot;&amp;quot;&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;重写&#34;&gt;重写&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;子类重写父类的方法&lt;br&gt;
子类可以重写父类的方法，即在子类中定义一个与父类方法同名的方法，从而覆盖父类的方法。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Persion:
    def eat(self):
        print(&amp;quot;eat&amp;quot;)

class Student(Persion):
    def eat(self):
        print(&amp;quot;eat food&amp;quot;)

student = Student()
student.eat() # eat food
&amp;quot;&amp;quot;&amp;quot;
输出：
eat food
&amp;quot;&amp;quot;&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;子类拓展父类的方法(不会改变父类方法)&lt;br&gt;
&lt;strong&gt;写法1&lt;/strong&gt;：子类在需要拓展的父类方法下写&lt;code&gt;父类名.方法名()&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Persion:
    def eat(self):
        print(&amp;quot;eat&amp;quot;)

class Student(Persion):
    def eat(self):
        Persion.eat(self)
        print(&amp;quot;eat food&amp;quot;)

#拓展父类方法
student1 = Student()
student1.eat() # eat food
# 不会改变父类方法
stuent2 = Persion()
stuent2.eat()
&amp;quot;&amp;quot;&amp;quot;
输出：
eat
eat food
eat
&amp;quot;&amp;quot;&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;写法2&lt;/strong&gt;：子类在需要拓展的父类方法下写&lt;code&gt;super().方法名()&lt;/code&gt;&lt;br&gt;
注意：&lt;code&gt;super&lt;/code&gt;在python里面是一个特殊的类，super()是使用super类创建的一个对象，这个对象是父类，但是不是父类的实例，而是父类的子类，所以super()可以调用父类的方法。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Persion:
    def eat(self):
        print(&amp;quot;eat&amp;quot;)

class Student(Persion):
    def eat(self):
        super().eat()
        print(&amp;quot;eat food&amp;quot;)

#拓展父类方法
student1 = Student()
student1.eat() # eat food
# 不会改变父类方法
stuent2 = Persion()
stuent2.eat()
&amp;quot;&amp;quot;&amp;quot;
输出：
eat
eat food
eat
&amp;quot;&amp;quot;&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;新式类写法&#34;&gt;新式类写法&lt;/h2&gt;
&lt;p&gt;python中，类有两种写法：经典类和新式类。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;class A&lt;/code&gt;&lt;br&gt;
经典类：不由任意内置类型派生的类。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Animal:
    def eat(self):
        print(&amp;quot;eat&amp;quot;)
# 经典类：没有新的属性和方法
class Dog(Animal):
    pass

# 派生类
class Cat(Animal):
    name = &amp;quot;cat&amp;quot;
    def play(self):
        print(&amp;quot;play&amp;quot;)
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;class A()&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;code&gt;class A(object) &lt;/code&gt;新式类：继承了object类或者该类的子类都是新式类。 --推荐使用&lt;br&gt;
&lt;code&gt;object&lt;/code&gt;类是所有类的基类，所有类都继承自object类,是python为所有对象提供的基类(顶级父类)。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;注意：python3中如果一个类没有继承任何类，则默认继承&lt;code&gt;object&lt;/code&gt;类，所以python3中所有的类都是新式类。&lt;/p&gt;
&lt;h2 id=&#34;多继承&#34;&gt;多继承&lt;/h2&gt;
&lt;p&gt;一个类可以继承多个类，多个类之间用逗号分隔。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Student:
    def study(self):
        print(&amp;quot;study&amp;quot;)

class Teacher:
    def teach(self):
        print(&amp;quot;teach&amp;quot;)

class TeacherStudent(Teacher, Student):
    pass

teacher_student = TeacherStudent()

teacher_student.study() # study
teacher_student.teach() # teach
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;注意：&lt;/strong&gt; 多个父类具有同名方法，则调用顺序为：&lt;code&gt;从左到右，深度优先&lt;/code&gt;。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;方法的搜索顺序：&lt;/strong&gt;&lt;br&gt;
python中内置的&lt;code&gt;__mro__&lt;/code&gt;属性可以查看类的继承顺序。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class A:
    def funa(self):
        print(&amp;quot;A.funa&amp;quot;)

class B(A):
    def funb(self):
        print(&amp;quot;B.funb&amp;quot;)

class C(A):
    def funa(self):
        print(&amp;quot;C.funa&amp;quot;)

class D(B, C):
    pass

d = D()
d.funa() # C.funa
print(D.__mro__)
&amp;quot;&amp;quot;&amp;quot;
输出：（从左到右，深度优先）
(&amp;lt;class &#39;__main__.D&#39;&amp;gt;, &amp;lt;class &#39;__main__.B&#39;&amp;gt;, &amp;lt;class &#39;__main__.C&#39;&amp;gt;, &amp;lt;class &#39;__main__.A&#39;&amp;gt;, &amp;lt;class &#39;object&#39;&amp;gt;)
&amp;quot;&amp;quot;&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;多态&lt;/h1&gt;
&lt;p&gt;多态：面向对象编程中的一个重要概念，它指的是一个对象可以有多种形态，即同一个方法可以在不同的对象上调用，从而实现不同的功能。&lt;/p&gt;
&lt;p&gt;多态的前提：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;继承&lt;/li&gt;
&lt;li&gt;重写&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;多态的体现：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;父类引用指向子类对象&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Animal:
    def eat(self):
        print(&amp;quot;eat&amp;quot;)

class Dog(Animal):
    def eat(self):
        print(&amp;quot;dog eat&amp;quot;)

class Cat(Animal):
    def eat(self):
        print(&amp;quot;cat eat&amp;quot;)

animal = Animal()
animal.eat() # eat

dog = Dog()
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;多态性：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;同一个方法，不同的对象调用，产生不同的结果。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Animal:
    def eat(self):
        print(&amp;quot;eat&amp;quot;)

class Dog(Animal):
    def eat(self):
        print(&amp;quot;dog eat&amp;quot;)

class Cat(Animal):
    def eat(self):
        print(&amp;quot;cat eat&amp;quot;)

def funa(obj):
    obg.eat()

animal = Animal()
funa(animal) # eat

dog = Dog()
funa(dog) # dog eat

cat = Cat()
funa(cat) # cat eat
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;静态方法&#34;&gt;静态方法&lt;/h2&gt;
&lt;p&gt;静态方法：不需要实例化对象就可以直接调用的方法，使用&lt;code&gt;@staticmethod&lt;/code&gt;装饰器来定义。&lt;/p&gt;
&lt;p&gt;静态方法的特点：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;不需要实例化对象就可以直接调用&lt;/li&gt;
&lt;li&gt;不需要&lt;code&gt;self&lt;/code&gt;参数&lt;/li&gt;
&lt;li&gt;静态方法可以访问类变量和实例变量&lt;/li&gt;
&lt;li&gt;静态方法不能访问实例方法&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;静态方法的使用场景：当方法不需要访问实例变量和类变量时，可以使用静态方法。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Animal:
    @staticmethod
    def say_hello():
        print(&amp;quot;hello&amp;quot;)
# 静态方法既可以使用对象访问，也可以使用类名访问

# 实例对象访问
animal = Animal(&amp;quot;dog&amp;quot;)
animal.say_hello() # hello

# 类名访问
Animal.say_hello() # hello
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;注意：类方法可以直接方法时传参数，例如Animal.say_hello(name)&lt;/p&gt;
&lt;h2 id=&#34;类方法&#34;&gt;类方法&lt;/h2&gt;
&lt;p&gt;类方法：使用&lt;code&gt;@classmethod&lt;/code&gt;装饰器来定义，对于类方法，第一个参数必须是类对象，通常命名为&lt;code&gt;cls&lt;/code&gt;，表示类本身。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Animal:
    name = &amp;quot;animal&amp;quot;
    @classmethod
    def say_hello(cls):
        print(&amp;quot;hello&amp;quot;)
# 类方法既可以使用对象访问，也可以使用类名访问

# 实例对象访问
animal = Animal(&amp;quot;dog&amp;quot;)
animal.say_hello() # hello

# 类名访问
Animal.say_hello() # hello
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;当方法中需要使用到类对象（如访问私有类属性时），定义类方法&lt;br&gt;
类方法一般配合类属性使用&lt;/p&gt;
&lt;p&gt;总结：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;实例方法：方法内部访问实例属性，方法内部可以通过&lt;code&gt;类名.类属性名&lt;/code&gt;来访问类属性。&lt;/li&gt;
&lt;li&gt;静态方法&lt;code&gt;@staticmethod&lt;/code&gt;：方法内部，不需要访问实例属性和类属性。
&lt;ul&gt;
&lt;li&gt;如果需要访问类属性，方法内部可以通过&lt;code&gt;类名.类属性名&lt;/code&gt;来访问，不能访问实例属性。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;类方法&lt;code&gt;@classmethod&lt;/code&gt;：方法内部只需要访问类属性，方法内部可以通过&lt;code&gt;cls.类属性名&lt;/code&gt;来访问类属性，不能访问实例属性。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Person(object):
    name = &amp;quot;小明&amp;quot; # 类属性
    def __init__(self):
        self.age = 18 # 实例属性:对象私有

    def play(self):  # 实例方法
        # 在实例方法中访问类属性
        print(f&#39;&amp;#123;Person.name&amp;#125;在玩游戏&#39;)
        # 在实例方法中访问实例属性
        print(f&#39;&amp;#123;self.age&amp;#125;岁&#39;)

    @staticmethod
    def eat():  # 静态方法： 类中的函数，形参没有限制,没有self指向实例对象的概念
        print(f&amp;quot;&amp;#123;Person.name&amp;#125;eat food&amp;quot;) # 静态方法可访问类属性，但是无意义，静态方法既不传递类对象，也不传递实例对象
        # print(f&amp;quot;&amp;#123;self.age&amp;#125;岁&amp;quot;) # × 静态方法不能访问实例属性

    @classmethod # 类方法:针对类存在的方法
    def say_hello(cls):  # 类方法：cls 代表类对象本身，不用类名.属性名 
        print(f&#39;&amp;#123;cls.name&amp;#125;在说话&#39;)
        # print(f&amp;quot;&amp;#123;self.age&amp;#125;岁&amp;quot;) # × 不能访问实例属性
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;单例模式&lt;/h1&gt;
&lt;p&gt;含义：一种常见的设计模式，用于确保一个类只有一个实例，并提供一个全局访问点。&lt;br&gt;
优点：节省内存，避免重复创建对象。&lt;br&gt;
弊端：多线程访问容易引发线程安全问题。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;方式&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;通过@classmethod实现&lt;/li&gt;
&lt;li&gt;通过装饰器实现&lt;/li&gt;
&lt;li&gt;通过重写__new__方法实现&lt;/li&gt;
&lt;li&gt;通过模块导入实现&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;new-方法&#34;&gt;__new__方法&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;__new__&lt;/code&gt;方法是&lt;code&gt;object基类&lt;/code&gt;提供的内置的&lt;code&gt;静态方法&lt;/code&gt;，它是在对象被创建之前调用的，用于创建对象。&lt;code&gt;__new__&lt;/code&gt;方法返回一个对象，这个对象会被&lt;code&gt;__init__&lt;/code&gt;方法初始化。&lt;/p&gt;
&lt;p&gt;作用：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;在内存中为对象分配空间&lt;/li&gt;
&lt;li&gt;返回对象的引用&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Person(object):
    def __init__(self, name):
        print(&amp;quot;Person.__init__&amp;quot;)
        self.name = name

    def __new__(cls, *args, **kwargs): # 重写new不再调用父类的new方法
        print(&amp;quot;Person.__new__&amp;quot;)
        # 对父类方法进行扩展 super().方法名()
        res = super().__new__(cls) #方法重写，res里面保存的是实例对象的引用
        return res

person = Person(&amp;quot;小明&amp;quot;)

&amp;quot;&amp;quot;&amp;quot;
输出：
Person.__new__
&amp;quot;&amp;quot;&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;通过重写-new-方法实现单例模式&#34;&gt;通过重写__new__方法实现单例模式&lt;/h2&gt;
&lt;p&gt;设计流程：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;定义一个类属性，初始化为None，用来记录单利对象的引用&lt;/li&gt;
&lt;li&gt;重写__new__方法&lt;/li&gt;
&lt;li&gt;进行判断，如果类属性为None，把__new__()返回对象的引用保存进去&lt;/li&gt;
&lt;li&gt;返回类型属性中记录的对象引用&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Singleton(object):
    __instance = None # 类属性
    def __new__(cls, *args, **kwargs):
        print(&amp;quot;Singleton.__new__&amp;quot;)
        return super().__new__(cls)

    def __init__(self):
        print(&amp;quot;Singleton.__init__&amp;quot;)

s1 = Singleton()
s2 = Singleton()
print(s1 is s2) # True
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;通过导入模块实现单例模式&#34;&gt;通过导入模块实现单例模式&lt;/h2&gt;
&lt;p&gt;模块的&lt;code&gt;__init__.py&lt;/code&gt;文件中的代码在模块第一次被导入时执行，只会执行一次，因此可以利用这个特性来实现单例模式。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;# my_singleton.py
class Singleton(object):
    def __init__(self):
        print(&amp;quot;Singleton.__init__&amp;quot;)

    def __new__(cls, *args, **kwargs):
        print(&amp;quot;Singleton.__new__&amp;quot;)
        return super().__new__(cls)

singleton = Singleton()
&lt;/code&gt;&lt;/pre&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;# main.py
from my_singleton import singleton

print(singleton)
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;应用场景&#34;&gt;应用场景&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;ol&gt;
&lt;li&gt;回收站对象&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;音乐播放器&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;开发游戏软件 场景管理器&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;数据库配置、数据库连接池的设计&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;线程池、连接池、缓存、日志对象&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1&gt;魔法方法&amp;amp;魔法属性&lt;/h1&gt;
&lt;p&gt;魔法方法：在Python中，以双下划线开头和结尾的方法称为魔法方法，也称为特殊方法。魔法方法在特定的情况下自动调用，不需要手动调用。&lt;/p&gt;
&lt;h2 id=&#34;doc-属性&#34;&gt;__doc__属性&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;__doc__&lt;/code&gt;: 类、函数的描述信息&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Person(object):
    &amp;quot;&amp;quot;&amp;quot;这是一个描述信息&amp;quot;&amp;quot;&amp;quot; # 只能使用多行注释，单行注释无效
    pass
print(Person.__doc__) # 这是一个描述信息

def fun():
    &amp;quot;&amp;quot;&amp;quot;这是一个描述信息&amp;quot;&amp;quot;&amp;quot;
    pass
print(fun.__doc__) # 这是一个描述信息
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;modeule-属性&#34;&gt;__modeule__属性&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;__module__&lt;/code&gt;: 类所属的模块名&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Person(object):
    pass
print(Person.__module__) # __main__
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;class-属性&#34;&gt;__class__属性&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;__class__&lt;/code&gt;: 类所属的类名&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Person(object):
    pass
print(Person.__class__) # &amp;lt;class &#39;type&#39;&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;str-方法&#34;&gt;&lt;strong&gt;str&lt;/strong&gt;()方法&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;__str__&lt;/code&gt;: 当使用print输出对象时，自动调用&lt;code&gt;__str__&lt;/code&gt;方法，返回一个字符串&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Person(object):
    def __str__(self):
        return &amp;quot;这是一个Person对象&amp;quot;

person = Person()
print(person) # 这是一个Person对象
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;del-方法&#34;&gt;&lt;strong&gt;del&lt;/strong&gt;()方法&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;__del__&lt;/code&gt;: 当对象被销毁时，自动调用&lt;code&gt;__del__&lt;/code&gt;方法&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Person(object):
    def __del__(self):
        print(&amp;quot;Person对象被销毁&amp;quot;)

person = Person()
del person # Person对象被销毁
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;call-方法&#34;&gt;&lt;strong&gt;call&lt;/strong&gt;()方法&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;__call__&lt;/code&gt;: 当对象被当作函数调用时，自动调用&lt;code&gt;__call__&lt;/code&gt;方法&lt;br&gt;
callable: 判断对象是否可调用&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Person(object):
    def __call__(self, *args, **kwargs):
        print(&amp;quot;Person对象被当作函数调用&amp;quot;)

person = Person()
person() # 调用一个可调用的实例对象，其实就是在调用它的__call__()方法

# 判断对象是否可调用
print(callable(person)) # True
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;dict-属性&#34;&gt;__dict__属性&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;__dict__&lt;/code&gt;: 类或对象的属性字典&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;class Person(object):
    def __init__(self, name):
        self.name = name

person = Person(&amp;quot;小明&amp;quot;)
print(person.__dict__) # &amp;#123;&#39;name&#39;: &#39;小明&#39;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;文件操作&lt;/h1&gt;
&lt;p&gt;文件：存储在硬盘上的数据&lt;/p&gt;
&lt;p&gt;文件操作步骤：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;打开文件&lt;/li&gt;
&lt;li&gt;读写文件&lt;/li&gt;
&lt;li&gt;关闭文件&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;文件对象的方法&#34;&gt;文件对象的方法&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;open()函数&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;code&gt;open()&lt;/code&gt;创建一个file对象，默认是以只读模式打开。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;file = open(&amp;quot;文件路径&amp;quot;, &amp;quot;打开模式&amp;quot;)
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;read(n)&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;code&gt;read()&lt;/code&gt;方法用于读取文件内容，n表示读取的字符个数，如果不指定n，则表示读取整个文件。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;file = open(&amp;quot;文件路径&amp;quot;, &amp;quot;打开模式&amp;quot;)
content = file.read()
file.close()
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;write()&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;code&gt;write()&lt;/code&gt;方法用于向文件中写入内容。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;file = open(&amp;quot;文件路径&amp;quot;, &amp;quot;打开模式&amp;quot;)
file.write(&amp;quot;要写入的内容&amp;quot;)
file.close()
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;close()&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;code&gt;close()&lt;/code&gt;方法用于关闭文件。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;file = open(&amp;quot;文件路径&amp;quot;, &amp;quot;打开模式&amp;quot;)
file.close()
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;属性&#34;&gt;属性&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;name&lt;br&gt;
&lt;code&gt;name&lt;/code&gt;: 返回要打开文件的文件名，可以包含具体的路径。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;file = open(&amp;quot;文件路径&amp;quot;, &amp;quot;打开模式&amp;quot;)
print(file.name)
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;mode&lt;br&gt;
&lt;code&gt;mode&lt;/code&gt;: 返回打开文件时使用的模式,如’r’、‘w’、&#39;a’等。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;file = open(&amp;quot;文件路径&amp;quot;, &amp;quot;打开模式&amp;quot;)
print(file.mode)
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;closed&lt;br&gt;
&lt;code&gt;closed&lt;/code&gt;: 返回文件是否已经关闭,True表示已经关闭，False表示已经打开。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;
file = open(&amp;quot;文件路径&amp;quot;, &amp;quot;打开模式&amp;quot;)
print(file.closed)
&lt;/code&gt;&lt;/pre&gt;

 &lt;h1&gt;变量和标识符&lt;/h1&gt;
&lt;h2 id=&#34;变量&#34;&gt;变量&lt;/h2&gt;
&lt;p&gt;变量是用于存储数据的容器，变量名可以包含字母、数字和下划线，但不能以数字开头。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = 1
b = 2
c = a + b
print(c)
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;标识符&#34;&gt;标识符&lt;/h2&gt;
&lt;p&gt;标识符是用于标识变量、函数、类、模块等的名称。标识符的命名规则如下：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;标识符可以包含字母、数字和下划线，但不能以数字开头。&lt;/li&gt;
&lt;li&gt;标识符不能包含空格和特殊字符。&lt;/li&gt;
&lt;li&gt;标识符区分大小写。&lt;/li&gt;
&lt;li&gt;标识符不能是Python的关键字。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;
# 合法的标识符
my_variable = 10
my_variable_2 = 20
my_variable3 = 30

# 非法的标识符

# my-variable = 10 # 包含空格
# 2my_variable = 10 # 以数字开头
# my-variable-2 = 20 # 包含特殊字符
# class = 10 # 是Python关键字

&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;数据类型&lt;/h1&gt;
&lt;h2 id=&#34;整数&#34;&gt;整数&lt;/h2&gt;
&lt;p&gt;整数是用于表示整数的类型，例如1、2、3等。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = 10
b = -20
c = 0
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;浮点数&#34;&gt;浮点数&lt;/h2&gt;
&lt;p&gt;浮点数是用于表示小数的类型，例如1.0、2.5、3.14等。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = 1.0
b = -2.5
c = 0.0
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;字符串&#34;&gt;字符串&lt;/h2&gt;
&lt;p&gt;字符串是用于表示文本的类型，例如&amp;quot;hello&amp;quot;、&amp;quot;world&amp;quot;等。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;string1 = &amp;quot;hello&amp;quot;
string2 = &#39;world&#39;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;字符串常见操作：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;字符串拼接：使用 &lt;code&gt;+&lt;/code&gt; 运算符将两个字符串连接起来。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;quot;hello&amp;quot; + &amp;quot;world&amp;quot; # a=&amp;quot;helloworld&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;字符串重复：使用 &lt;code&gt;*&lt;/code&gt; 运算符将字符串重复指定次数。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;quot;hello&amp;quot; * 3 # a=&amp;quot;hellohellohello&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;字符串长度：使用 &lt;code&gt;len()&lt;/code&gt; 函数获取字符串的长度。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;quot;hello&amp;quot; 
print(len(a)) # 输出5
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;字符串切片：使用 &lt;code&gt;[:]&lt;/code&gt; 运算符获取字符串的子串。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;quot;hello&amp;quot;
print(a[1:3]) # 输出&amp;quot;el&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;字符串查找：使用 &lt;code&gt;find()&lt;/code&gt; 函数查找子串在字符串中的位置。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;quot;hello&amp;quot;
print(a.find(&amp;quot;l&amp;quot;)) # 输出2
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;字符串替换：使用 &lt;code&gt;replace()&lt;/code&gt; 函数替换字符串中的子串。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;quot;hello&amp;quot;
print(a.replace(&amp;quot;l&amp;quot;, &amp;quot;x&amp;quot;)) # 输出&amp;quot;hexxo&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;7&#34;&gt;
&lt;li&gt;字符串分割：使用 &lt;code&gt;split()&lt;/code&gt; 函数将字符串分割成子串列表。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;quot;hello world&amp;quot;
print(a.split(&amp;quot; &amp;quot;)) # 输出[&amp;quot;hello&amp;quot;, &amp;quot;world&amp;quot;]
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;8&#34;&gt;
&lt;li&gt;字符串大小写转换：使用 &lt;code&gt;upper()&lt;/code&gt;、&lt;code&gt;lower()&lt;/code&gt;、&lt;code&gt;capitalize()&lt;/code&gt;、&lt;code&gt;title()&lt;/code&gt; 函数进行大小写转换。&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;upper()&lt;/code&gt;：将字符串转换为大写。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;lower()&lt;/code&gt;：将字符串转换为小写。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;capitalize()&lt;/code&gt;：将字符串的首字母转换为大写。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;title()&lt;/code&gt;：将字符串的每个单词的首字母转换为大写。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;quot;hello&amp;quot;
print(a.upper()) # 输出&amp;quot;HELLO&amp;quot;
print(a.lower()) # 输出&amp;quot;hello&amp;quot;
print(a.capitalize()) # 输出&amp;quot;Hello&amp;quot;
print(a.title()) # 输出&amp;quot;Hello&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;9&#34;&gt;
&lt;li&gt;字符串格式化：使用 &lt;code&gt;%&lt;/code&gt; 运算符或 &lt;code&gt;format()&lt;/code&gt; 函数进行字符串格式化。&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;%&lt;/code&gt; 运算符：使用 &lt;code&gt;%&lt;/code&gt; 运算符进行字符串格式化，格式化字符串中的 &lt;code&gt;%s&lt;/code&gt;、&lt;code&gt;%d&lt;/code&gt; 等占位符会被后面的参数替换。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;format()&lt;/code&gt; 函数：使用 &lt;code&gt;format()&lt;/code&gt; 函数进行字符串格式化，格式化字符串中的 &lt;code&gt;&amp;#123;&amp;#125;&lt;/code&gt; 占位符会被后面的参数替换。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;name = &amp;quot;Alice&amp;quot;
age = 25
print(&amp;quot;My name is %s and I am %d years old.&amp;quot; % (name, age)) # 输出&amp;quot;My name is Alice and I am 25 years old.&amp;quot;
print(&amp;quot;My name is &amp;#123;&amp;#125; and I am &amp;#123;&amp;#125; years old.&amp;quot;.format(name, age)) # 输出&amp;quot;My name is Alice and I am 25 years old.&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol&gt;
&lt;li&gt;字符串拼接：使用 &lt;code&gt;join()&lt;/code&gt; 函数将列表中的字符串拼接成一个字符串。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [&amp;quot;hello&amp;quot;, &amp;quot;world&amp;quot;]
print(&amp;quot; &amp;quot;.join(a)) # 输出&amp;quot;hello world&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;11&#34;&gt;
&lt;li&gt;字符串判断：使用 &lt;code&gt;startswith()&lt;/code&gt;、&lt;code&gt;endswith()&lt;/code&gt;、&lt;code&gt;isalpha()&lt;/code&gt;、&lt;code&gt;isdigit()&lt;/code&gt;、&lt;code&gt;isalnum()&lt;/code&gt;、&lt;code&gt;isspace()&lt;/code&gt; 函数判断字符串的属性。&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;startswith()&lt;/code&gt;：判断字符串是否以指定子串开头。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;endswith()&lt;/code&gt;：判断字符串是否以指定子串结尾。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;isalpha()&lt;/code&gt;：判断字符串是否只包含字母。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;isdigit()&lt;/code&gt;：判断字符串是否只包含数字。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;isalnum()&lt;/code&gt;：判断字符串是否只包含字母和数字。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;isspace()&lt;/code&gt;：判断字符串是否只包含空白字符。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;quot;hello&amp;quot;
print(a.startswith(&amp;quot;h&amp;quot;)) # 输出True
print(a.endswith(&amp;quot;o&amp;quot;)) # 输出True
print(a.isalpha()) # 输出True
print(a.isdigit()) # 输出False
print(a.isalnum()) # 输出True
print(a.isspace()) # 输出False
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;列表&lt;/h1&gt;
&lt;p&gt;列表是用于存储多个元素的有序集合，可以包含不同类型的元素。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3, 4, 5]
b = [&amp;quot;hello&amp;quot;, &amp;quot;world&amp;quot;]
c = [1, &amp;quot;hello&amp;quot;, 3.14]
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;列表常见操作：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;访问列表元素：使用索引访问列表中的元素。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3, 4, 5]
print(a[0]) # 输出1
print(a[2]) # 输出3
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;修改列表元素：使用索引修改列表中的元素。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3, 4, 5]
a[0] = 10
print(a) # 输出[10, 2, 3, 4, 5]
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;删除列表元素：使用 &lt;code&gt;del&lt;/code&gt; 语句删除列表中的元素。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3, 4, 5]
del a[0]
print(a) # 输出[2, 3, 4, 5]
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;列表切片：使用 &lt;code&gt;[:]&lt;/code&gt; 运算符获取列表的子列表。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3, 4, 5]
print(a[1:3]) # 输出[2, 3]
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;列表长度：使用 &lt;code&gt;len()&lt;/code&gt; 函数获取列表的长度。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3, 4, 5]
print(len(a)) # 输出5
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;列表追加：使用 &lt;code&gt;append()&lt;/code&gt; 方法将元素追加到列表末尾。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3, 4, 5]
a.append(6)
print(a) # 输出[1, 2, 3, 4, 5, 6]
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;7&#34;&gt;
&lt;li&gt;列表插入：使用 &lt;code&gt;insert()&lt;/code&gt; 方法将元素插入到列表指定位置。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3, 4, 5]
a.insert(1, 10)
print(a) # 输出[1, 10, 2, 3, 4, 5]
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;8&#34;&gt;
&lt;li&gt;列表删除：使用 &lt;code&gt;remove()&lt;/code&gt; 方法删除列表中指定值的第一个元素。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3, 4, 5]
a.remove(3)
print(a) # 输出[1, 2, 4, 5]
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;9&#34;&gt;
&lt;li&gt;列表排序：使用 &lt;code&gt;sort()&lt;/code&gt; 方法对列表进行排序。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [5, 3, 1, 4, 2]
a.sort()
print(a) # 输出[1, 2, 3, 4, 5]
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;10&#34;&gt;
&lt;li&gt;列表反转：使用 &lt;code&gt;reverse()&lt;/code&gt; 方法将列表中的元素反转。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3, 4, 5]
a.reverse()
print(a) # 输出[5, 4, 3, 2, 1]
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;11&#34;&gt;
&lt;li&gt;列表合并：使用 &lt;code&gt;+&lt;/code&gt; 运算符将两个列表合并成一个列表。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3]
b = [4, 5, 6]
c = a + b
print(c) # 输出[1, 2, 3, 4, 5, 6]
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;12&#34;&gt;
&lt;li&gt;列表复制：使用 &lt;code&gt;copy()&lt;/code&gt; 方法复制列表。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3]
b = a.copy()
print(b) # 输出[1, 2, 3]
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;元组&lt;/h1&gt;
&lt;p&gt;元组是用于存储多个元素的有序集合，与列表类似，但元组中的元素不可修改。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = (1, 2, 3, 4, 5)
b = (&amp;quot;hello&amp;quot;, &amp;quot;world&amp;quot;)
c = (1, &amp;quot;hello&amp;quot;, 3.14)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;元组常见操作：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;访问元组元素：使用索引访问元组中的元素。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = (1, 2, 3, 4, 5)
print(a[0]) # 输出1
print(a[2]) # 输出3
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;列表切片：使用 &lt;code&gt;[:]&lt;/code&gt; 运算符获取元组的子元组。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = (1, 2, 3, 4, 5)
print(a[1:3]) # 输出(2, 3)
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;元组长度：使用 &lt;code&gt;len()&lt;/code&gt; 函数获取元组的长度。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = (1, 2, 3, 4, 5)
print(len(a)) # 输出5
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;元组解包：使用 &lt;code&gt;=&lt;/code&gt; 运算符将元组中的元素赋值给多个变量。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = (1, 2, 3)
x, y, z = a
print(x) # 输出1
print(y) # 输出2
print(z) # 输出3
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;字典&lt;/h1&gt;
&lt;p&gt;字典是用于存储键值对的集合，键值对之间用冒号分隔，键值对之间用逗号分隔。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;#123;&amp;quot;name&amp;quot;: &amp;quot;Alice&amp;quot;, &amp;quot;age&amp;quot;: 25, &amp;quot;city&amp;quot;: &amp;quot;New York&amp;quot;&amp;#125;
b = &amp;#123;1: &amp;quot;one&amp;quot;, 2: &amp;quot;two&amp;quot;, 3: &amp;quot;three&amp;quot;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;字典常见操作：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;访问字典元素：使用键访问字典中的值。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;#123;&amp;quot;name&amp;quot;: &amp;quot;Alice&amp;quot;, &amp;quot;age&amp;quot;: 25, &amp;quot;city&amp;quot;: &amp;quot;New York&amp;quot;&amp;#125;
print(a[&amp;quot;name&amp;quot;]) # 输出&amp;quot;Alice&amp;quot;
print(a[&amp;quot;age&amp;quot;]) # 输出25
print(a[&amp;quot;city&amp;quot;]) # 输出&amp;quot;New York&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;修改字典元素：使用键修改字典中的值。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;#123;&amp;quot;name&amp;quot;: &amp;quot;Alice&amp;quot;, &amp;quot;age&amp;quot;: 25, &amp;quot;city&amp;quot;: &amp;quot;New York&amp;quot;&amp;#125;
a[&amp;quot;age&amp;quot;] = 26
print(a) # 输出&amp;#123;&amp;quot;name&amp;quot;: &amp;quot;Alice&amp;quot;, &amp;quot;age&amp;quot;: 26, &amp;quot;city&amp;quot;: &amp;quot;New York&amp;quot;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;删除字典元素：使用 &lt;code&gt;del&lt;/code&gt; 语句删除字典中的键值对。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;#123;&amp;quot;name&amp;quot;: &amp;quot;Alice&amp;quot;, &amp;quot;age&amp;quot;: 25, &amp;quot;city&amp;quot;: &amp;quot;New York&amp;quot;&amp;#125;
del a[&amp;quot;age&amp;quot;]
print(a) # 输出&amp;#123;&amp;quot;name&amp;quot;: &amp;quot;Alice&amp;quot;, &amp;quot;city&amp;quot;: &amp;quot;New York&amp;quot;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;字典长度：使用 &lt;code&gt;len()&lt;/code&gt; 函数获取字典的长度。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;#123;&amp;quot;name&amp;quot;: &amp;quot;Alice&amp;quot;, &amp;quot;age&amp;quot;: 25, &amp;quot;city&amp;quot;: &amp;quot;New York&amp;quot;&amp;#125;
print(len(a)) # 输出3
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;字典遍历：使用 &lt;code&gt;for&lt;/code&gt; 循环遍历字典中的键值对。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;#123;&amp;quot;name&amp;quot;: &amp;quot;Alice&amp;quot;, &amp;quot;age&amp;quot;: 25, &amp;quot;city&amp;quot;: &amp;quot;New York&amp;quot;&amp;#125;
for key, value in a.items():
    print(key, value)
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;集合&lt;/h1&gt;
&lt;p&gt;集合是用于存储多个元素的集合，元素不重复且无序。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;#123;1, 2, 3, 4, 5&amp;#125;
b = &amp;#123;&amp;quot;hello&amp;quot;, &amp;quot;world&amp;quot;&amp;#125;
c = &amp;#123;1, &amp;quot;hello&amp;quot;, 3.14&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;集合常见操作：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;添加元素：使用 &lt;code&gt;add()&lt;/code&gt; 方法向集合中添加元素。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;#123;1, 2, 3, 4, 5&amp;#125;
a.add(6)
print(a) # 输出&amp;#123;1, 2, 3, 4, 5, 6&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;删除元素：使用 &lt;code&gt;remove()&lt;/code&gt; 方法从集合中删除指定元素。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;#123;1, 2, 3, 4, 5&amp;#125;
a.remove(3)
print(a) # 输出&amp;#123;1, 2, 4, 5&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;集合长度：使用 &lt;code&gt;len()&lt;/code&gt; 函数获取集合的长度。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;#123;1, 2, 3, 4, 5&amp;#125;
print(len(a)) # 输出5
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;集合遍历：使用 &lt;code&gt;for&lt;/code&gt; 循环遍历集合中的元素。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;
a = &amp;#123;1, 2, 3, 4, 5&amp;#125;
for i in a:
    print(i)
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;集合交集：使用 &lt;code&gt;&amp;amp;&lt;/code&gt; 运算符计算两个集合的交集。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;#123;1, 2, 3, 4, 5&amp;#125;
b = &amp;#123;4, 5, 6, 7, 8&amp;#125;
print(a &amp;amp; b) # 输出&amp;#123;4, 5&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;集合并集：使用 &lt;code&gt;|&lt;/code&gt; 运算符计算两个集合的并集。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;#123;1, 2, 3, 4, 5&amp;#125;
b = &amp;#123;4, 5, 6, 7, 8&amp;#125;
print(a | b) # 输出&amp;#123;1, 2, 3, 4, 5, 6, 7, 8&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;7&#34;&gt;
&lt;li&gt;集合差集：使用 &lt;code&gt;-&lt;/code&gt; 运算符计算两个集合的差集。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;#123;1, 2, 3, 4, 5&amp;#125;
b = &amp;#123;4, 5, 6, 7, 8&amp;#125;
print(a - b) # 输出&amp;#123;1, 2, 3&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;8&#34;&gt;
&lt;li&gt;集合对称差集：使用 &lt;code&gt;^&lt;/code&gt; 运算符计算两个集合的对称差集。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = &amp;#123;1, 2, 3, 4, 5&amp;#125;
b = &amp;#123;4, 5, 6, 7, 8&amp;#125;
print(a ^ b) # 输出&amp;#123;1, 2, 3, 6, 7, 8&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;布尔值&#34;&gt;布尔值&lt;/h2&gt;
&lt;p&gt;布尔值是用于表示真假的类型，只有两个值：True和False。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = True
b = False
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;运算符&lt;/h1&gt;
&lt;h2 id=&#34;算术运算符&#34;&gt;算术运算符&lt;/h2&gt;
&lt;p&gt;算术运算符用于执行基本的数学运算，例如加法、减法、乘法、除法等。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = 10
b = 20
c = a + b # c=30
d = a - b # d=-10
e = a * b # e=200
f = a / b # f=0.5
g = a % b # g=10

&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;比较运算符&#34;&gt;比较运算符&lt;/h2&gt;
&lt;p&gt;比较运算符用于比较两个值的大小关系，例如大于、小于、等于、不等于等。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = 10
b = 20
c = a &amp;gt; b  # c=False
d = a &amp;lt; b  # d=True
e = a == b # e=False
f = a != b # f=True
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;逻辑运算符&#34;&gt;逻辑运算符&lt;/h2&gt;
&lt;p&gt;逻辑运算符用于执行逻辑运算，例如与、或、非等。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = True
b = False
c = a and b # c=False
d = a or b  # d=True
e = not a   # e=False
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;赋值运算符&#34;&gt;赋值运算符&lt;/h2&gt;
&lt;p&gt;赋值运算符用于将一个值赋给一个变量，例如等于、加等于、减等于等。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = 10
b = 20
a = b # a=20
a += b # a=40
a -= b # a=20
a *= b # a=400
a /= b # a=2.0
a %= b # a=0
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;流程控制&lt;/h1&gt;
&lt;h2 id=&#34;条件语句&#34;&gt;条件语句&lt;/h2&gt;
&lt;p&gt;条件语句用于根据条件执行不同的代码块，例如if语句、if-else语句、if-elif-else语句等。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = 10
b = 20

if a &amp;gt; b:
    print(&amp;quot;a大于b&amp;quot;)
elif a &amp;lt; b:
    print(&amp;quot;a小于b&amp;quot;)
else:
    print(&amp;quot;a等于b&amp;quot;)
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;循环语句&#34;&gt;循环语句&lt;/h2&gt;
&lt;p&gt;循环语句用于重复执行一段代码，例如for循环、while循环等。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;for&lt;/code&gt;循环：用于遍历一个可迭代对象，例如&lt;code&gt;列表&lt;/code&gt;、&lt;code&gt;元组&lt;/code&gt;、&lt;code&gt;字符串&lt;/code&gt;等。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3, 4, 5]
for i in a:
    print(i)
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;while循环：用于在满足条件时重复执行一段代码。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = 1
while a &amp;lt; 6:
    print(a)
    a += 1
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;函数&lt;/h1&gt;
&lt;p&gt;函数是一段可重复使用的代码块，可以接受参数并返回结果。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def add(a, b):
    return a + b
result = add(1, 2)
print(result)
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;函数文档字符串&#34;&gt;函数文档字符串&lt;/h2&gt;
&lt;p&gt;函数文档字符串用于描述函数的功能和用法，可以使用三引号 &lt;code&gt;&amp;quot;&amp;quot;&amp;quot;&lt;/code&gt; 包围。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def add(a, b):
    &amp;quot;&amp;quot;&amp;quot;
    This function adds two numbers.

    Parameters:
    a (int): The first number.
    b (int): The second number.

    Returns:
    int: The sum of the two numbers.
    &amp;quot;&amp;quot;&amp;quot;
    return a + b
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;函数参数&#34;&gt;函数参数&lt;/h2&gt;
&lt;p&gt;函数参数用于传递数据给函数。&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;位置参数：按照参数的顺序传递参数。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def add(a, b):
    return a + b
result = add(1, 2)
print(result) # 输出3
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;默认参数：为参数指定默认值。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def add(a, b=2):
    return a + b
result = add(1)
print(result) # 输出3
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;可变参数：使用&lt;code&gt;*&lt;/code&gt;传递可变数量的参数。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def add(*args):  
# 以元组类型接 args = (1, 2, 3, 4, 5) 
    result = 0
    for i in args:
        result += i
    return result
result = add(1, 2, 3, 4, 5)
print(result) # 输出15
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;注意：函数接收可变数量的参数，使用&lt;code&gt;*args&lt;/code&gt;接收参数，&lt;code&gt;args&lt;/code&gt;是一个元组类型&lt;code&gt;()&lt;/code&gt;。&lt;/p&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;关键字参数：通过&lt;code&gt;**&lt;/code&gt;传递关键字参数。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def fund(**kwargs):
# 以字典类型接 kwargs = &amp;#123;&amp;quot;name&amp;quot;: &amp;quot;Alice&amp;quot;, &amp;quot;age&amp;quot;: 25, &amp;quot;city&amp;quot;: &amp;quot;New York&amp;quot;&amp;#125;
    for key, value in kwargs.items():
        print(key, value)
fund(name=&amp;quot;Alice&amp;quot;, age=25, city=&amp;quot;New York&amp;quot;)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;注意：函数接收关键字参数，使用&lt;code&gt;**kwargs&lt;/code&gt;接收参数，&lt;code&gt;kwargs&lt;/code&gt;是一个字典类型&lt;code&gt;&amp;#123;&amp;#125;&lt;/code&gt;。&lt;/p&gt;
&lt;h2 id=&#34;函数返回值&#34;&gt;函数返回值&lt;/h2&gt;
&lt;p&gt;函数返回值用于返回函数执行的结果，可以使用&lt;code&gt;return&lt;/code&gt;语句。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def add(a, b):
    return a + b

result = add(1, 2)
print(result) # 输出3
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;函数嵌套&#34;&gt;函数嵌套&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;嵌套调用&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;函数嵌套调用是指在一个函数内部调用另一个函数。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def add(a, b):
    return a + b

def multiply(a, b):
    return a * b

result = multiply(add(1, 2), 3)
print(result) # 输出9
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;嵌套定义&lt;br&gt;
函数嵌套是指在一个函数内部定义另一个函数。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def outer():
    def inner():
        print(&amp;quot;This is inner function&amp;quot;)
    inner()
outer()
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;匿名函数&#34;&gt;匿名函数&lt;/h2&gt;
&lt;p&gt;匿名函数是指没有名字的函数，使用&lt;code&gt;lambda&lt;/code&gt;关键字定义。&lt;/p&gt;
&lt;p&gt;格式：&lt;code&gt;函数名 = lambda 参数列表: 表达式(返回值)&lt;/code&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;无参数匿名函数&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;add = lambda: 1 + 2
print(add()) # 输出3
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;有参数匿名函数&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;add = lambda a, b: a + b
print(add(1, 2)) # 输出3
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;带默认参数匿名函数&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;add = lambda a, b=2: a + b
print(add(1)) # 输出3
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;带可变参数匿名函数&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;add = lambda *args: sum(args)
print(add(1, 2, 3, 4, 5)) # 输出15
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;带关键字参数匿名函数&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;add = lambda **kwargs: sum(kwargs.values())
print(add(a=1, b=2, c=3)) # 输出6
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;内置函数&#34;&gt;内置函数&lt;/h2&gt;
&lt;p&gt;内置函数是指Python语言自带的函数，例如&lt;code&gt;len()&lt;/code&gt;、&lt;code&gt;max()&lt;/code&gt;、&lt;code&gt;min()&lt;/code&gt;等。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3, 4, 5]
print(len(a)) # 输出5
print(max(a)) # 输出5
print(min(a)) # 输出1
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;查看所有内置函数：&lt;code&gt;dir(__builtins__)&lt;/code&gt;&lt;br&gt;
&lt;code&gt;dir&lt;/code&gt; 函数用于返回一个列表，包含指定对象的所有属性和方法。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;import math
print(dir(math))
# 大写的为常量，小写的为函数
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;map函数&#34;&gt;map函数&lt;/h3&gt;
&lt;p&gt;map函数用于将一个函数应用于可迭代对象的每个元素，并返回一个迭代器。&lt;/p&gt;
&lt;p&gt;格式：&lt;code&gt;map(函数, 可迭代对象)&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3, 4, 5]
result = map(lambda x: x * 2, a) # 将每个元素乘以2
print(list(result)) # 输出[2, 4, 6, 8, 10]
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;filter函数&#34;&gt;filter函数&lt;/h3&gt;
&lt;p&gt;filter函数用于过滤可迭代对象中的元素，并返回一个迭代器。&lt;/p&gt;
&lt;p&gt;格式：&lt;code&gt;filter(函数, 可迭代对象)&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3, 4, 5]
result = filter(lambda x: x % 2 == 0, a) # 过滤出偶数
print(list(result)) # 输出[2, 4]
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;reduce函数&#34;&gt;reduce函数&lt;/h3&gt;
&lt;p&gt;reduce函数用于将一个函数应用于可迭代对象的每个元素，并返回一个值。&lt;br&gt;
格式：&lt;code&gt;reduce(函数, 可迭代对象)&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;from functools import reduce
a = [1, 2, 3, 4, 5]
result = reduce(lambda x, y: x + y, a) # 将每个元素相加
print(result) # 输出15
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;zip函数&#34;&gt;zip函数&lt;/h3&gt;
&lt;p&gt;zip函数用于将多个可迭代对象中的元素打包成一个个元组，并返回一个迭代器。&lt;/p&gt;
&lt;p&gt;格式：&lt;code&gt;zip(可迭代对象1, 可迭代对象2, ...)&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = [1, 2, 3]
b = [&#39;a&#39;, &#39;b&#39;, &#39;c&#39;]
result = zip(a, b) # 将每个元素打包成元组
print(list(result)) # 输出[(1, &#39;a&#39;), (2, &#39;b&#39;), (3, &#39;c&#39;)]
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;拆包&#34;&gt;拆包&lt;/h3&gt;
&lt;p&gt;对于函数中的多个返回数据，去掉元组，列表或者字典的括号，直接赋值给多个变量。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;arr = [1, 2, 3]
a, b, c = arr
print(a) # 输出1
print(b) # 输出2
print(c) # 输出3
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;闭包&#34;&gt;闭包&lt;/h2&gt;
&lt;p&gt;闭包是指在一个函数内部定义另一个函数，并且内部函数可以访问外部函数的变量。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def outer():
    x = 10
    def inner():
        print(x)
    return inner
closure = outer()
closure() # 输出10
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;作用域&lt;/h1&gt;
&lt;p&gt;作用域是指变量可访问的范围，分为全局作用域和局部作用域。&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;全局作用域：在函数外部定义的变量，可以在整个程序中访问。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = 10
def add(b):
    return a + b
result = add(5)
print(result) # 输出15
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;局部作用域：在函数内部定义的变量，只能在函数内部访问。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def add(a, b):
    c = a + b
    return c
result = add(1, 2)
print(result) # 输出3
print(c) # 报错，c未定义
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;**注意：**局部变量&lt;code&gt;c&lt;/code&gt;只能在&lt;code&gt;add&lt;/code&gt;函数内部访问，不能在函数外部访问。&lt;/p&gt;
&lt;p&gt;局部变量升级为全局变量：使用&lt;code&gt;global&lt;/code&gt;关键字声明变量为全局变量。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;a = 10
def add(b):
    global a
    a = a + b
    return a
result = add(5)
print(result) # 输出15
print(a) # 输出15
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;局部变量&lt;code&gt;a&lt;/code&gt;升级为全局变量，可以在函数外部访问。&lt;/p&gt;
&lt;h1&gt;异常&lt;/h1&gt;
&lt;p&gt;异常是指程序运行过程中出现的错误。&lt;/p&gt;
&lt;p&gt;异常种类：&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;异常类型&lt;/th&gt;
&lt;th&gt;描述&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;ZeroDivisionError&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;除数为0&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;TypeError&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;类型错误&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;ValueError&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;值错误&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;IndexError&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;索引错误&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;KeyError&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;键错误&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;NameError&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;名称错误&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;AttributeError&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;属性错误&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;SyntaxError&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;语法错误&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;IndentationError&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;缩进错误&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;IOError&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;输入输出错误&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;EOFError&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;文件结束错误&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;ImportError&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;导入错误&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;ModuleNotFoundError&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;模块未找到错误&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;AssertionError&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;断言错误&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;KeyboardInterrupt&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;键盘中断&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;SystemExit&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;系统退出&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;Exception&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;所有异常的基类&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;捕获异常。&#34;&gt;捕获异常。&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;格式一：&lt;code&gt;try-except&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;try:
    # 可能出现异常的代码
except 异常类型:
    # 异常处理代码
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;示例：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;try:
    a = 10 / 0
except ZeroDivisionError:
    print(&amp;quot;除数不能为0&amp;quot;)
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;格式二：&lt;code&gt;try-except-else&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;try:
    # 可能出现异常的代码
except 异常类型1:
    # 异常处理代码1
else:
    # 没有异常时执行的代码
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;格式三：try-except-finally&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;try:
    # 可能出现异常的代码
except 异常类型1:
    # 异常处理代码1
finally:
    # 无论是否出现异常都会执行的代码
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;格式四：try-except-else-finally&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;try:
    # 可能出现异常的代码
except 异常类型1:
    # 异常处理代码1
except 异常类型2:
    # 异常处理代码2
else:
    # 没有异常时执行的代码
finally:
    # 无论是否出现异常都会执行的代码
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;抛出异常&#34;&gt;抛出异常&lt;/h2&gt;
&lt;p&gt;使用&lt;code&gt;raise&lt;/code&gt;关键字抛出异常。&lt;/p&gt;
&lt;p&gt;格式：&lt;code&gt;raise 异常类型(异常信息)&lt;/code&gt;&lt;br&gt;
示例：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def divide(a, b):
    if b == 0:
        raise ZeroDivisionError(&amp;quot;除数不能为0&amp;quot;)
    return a / b
try:
    result = divide(10, 0)
except ZeroDivisionError as e:
    print(e)
&lt;/code&gt;&lt;/pre&gt;
&lt;h1&gt;模块&lt;/h1&gt;
&lt;p&gt;模块是包含一组函数、类和变量的文件，可以导入到其他文件中使用。&lt;/p&gt;
&lt;h2 id=&#34;内置模块&#34;&gt;内置模块&lt;/h2&gt;
&lt;p&gt;Python内置了一些模块，可以直接使用，例如&lt;code&gt;math&lt;/code&gt;、&lt;code&gt;random&lt;/code&gt;、&lt;code&gt;datetime&lt;/code&gt;等。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;import math
print(math.sqrt(16)) # 输出4.0
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;第三方模块（第三方库）&#34;&gt;第三方模块（第三方库）&lt;/h2&gt;
&lt;p&gt;第三方模块是指由其他开发者编写的模块，需要先安装才能使用。&lt;/p&gt;
&lt;p&gt;安装第三方模块：使用&lt;code&gt;pip&lt;/code&gt;命令安装。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;pip install 模块名
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;使用第三方模块：使用&lt;code&gt;import&lt;/code&gt;关键字导入。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;import 模块名
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;使用第三方模块中的函数：使用&lt;code&gt;模块名.函数名()&lt;/code&gt;调用。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;import math
print(math.sqrt(16)) # 输出4.0
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;自定义模块&#34;&gt;自定义模块&lt;/h2&gt;
&lt;p&gt;自定义模块是指用户自己编写的模块，需要先定义一个&lt;code&gt;.py&lt;/code&gt;文件，然后在其他文件中导入使用。&lt;/p&gt;
&lt;p&gt;注意：自定义模块的文件名不能与Python内置模块的文件名相同。&lt;/p&gt;
&lt;h2 id=&#34;导入模块&#34;&gt;导入模块&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;导入模块：使用&lt;code&gt;import&lt;/code&gt;关键字导入。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;import 模块名
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;使用模块中的函数：使用&lt;code&gt;模块名.函数名()&lt;/code&gt;调用。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;import math
print(math.sqrt(16)) # 输出4.0
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;导入模块中的特定函数：使用&lt;code&gt;from 模块名 import 函数名&lt;/code&gt;导入。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;from math import sqrt
print(sqrt(16)) # 输出4.0
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;导入模块中的所有函数：使用&lt;code&gt;from 模块名 import *&lt;/code&gt;导入。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;from math import *
print(sqrt(16)) # 输出4.0
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;导入模块中的特定变量：使用&lt;code&gt;from 模块名 import 变量名&lt;/code&gt;导入。&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;from math import pi
print(pi) # 输出3.141592653589793
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;起别名&#34;&gt;起别名&lt;/h2&gt;
&lt;h3 id=&#34;模块起别名&#34;&gt;模块起别名&lt;/h3&gt;
&lt;p&gt;使用&lt;code&gt;as&lt;/code&gt;关键字给模块起别名。&lt;/p&gt;
&lt;p&gt;语法：&lt;code&gt;import 模块名 as 别名&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;import math as m
print(m.sqrt(16)) # 输出4.0
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;功能起别名&#34;&gt;功能起别名&lt;/h3&gt;
&lt;p&gt;使用&lt;code&gt;as&lt;/code&gt;关键字给功能起别名。&lt;/p&gt;
&lt;p&gt;语法：&lt;code&gt;from 模块名 import 功能 as 别名&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;from math import sqrt as s
print(s(16)) # 输出4.0
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;注意：导入多个功能时，可以使用‘，’隔开，后面功能也可以使用取别名：&lt;code&gt;from math import sqrt as s, pi as p&lt;/code&gt;&lt;/p&gt;
&lt;h2 id=&#34;内置全局变量&#34;&gt;内置全局变量&lt;/h2&gt;
&lt;p&gt;语法：&lt;br&gt;
if &lt;strong&gt;name&lt;/strong&gt; == “&lt;strong&gt;main&lt;/strong&gt;”:&lt;/p&gt;
&lt;p&gt;作用：用来控制py文件在不同应用场景下执行不同的逻辑,当模块被直接运行时，&lt;code&gt;__name__&lt;/code&gt;的值为&lt;code&gt;&amp;quot;__main__&amp;quot;&lt;/code&gt;，当模块被导入时，&lt;code&gt;__name__&lt;/code&gt;的值为模块名。&lt;br&gt;
例如：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;if __name__ == &amp;quot;__main__&amp;quot;:
    print(&amp;quot;直接运行&amp;quot;)
else:
    print(&amp;quot;被导入&amp;quot;)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;直接运行该文件输出：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-shell&#34;&gt;直接运行
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;被导入该文件输出：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-shell&#34;&gt;被导入
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;总结：导入不会执行&lt;code&gt;if __name__ == &amp;quot;__main__&amp;quot;:&lt;/code&gt;下的代码，只有直接运行该文件才会执行&lt;code&gt;if __name__ == &amp;quot;__main__&amp;quot;:&lt;/code&gt;下的代码。&lt;/p&gt;
&lt;h2 id=&#34;包&#34;&gt;包&lt;/h2&gt;
&lt;p&gt;包是指包含一组模块的文件夹，文件夹中必须包含一个&lt;code&gt;__init__.py&lt;/code&gt;文件，用于标识该文件夹是一个包。&lt;/p&gt;
&lt;h3 id=&#34;init-py&#34;&gt;&lt;strong&gt;init&lt;/strong&gt;.py&lt;/h3&gt;
&lt;p&gt;使用包：使用&lt;code&gt;import 包名.模块名&lt;/code&gt;导入。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;import mypackage.mymodule
print(mypackage.mymodule.myfunction())
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;使用包中的特定模块：使用&lt;code&gt;from 包名 import 模块名&lt;/code&gt;导入。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;from mypackage import mymodule
print(mymodule.myfunction())
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;使用包中的特定函数：使用&lt;code&gt;from 包名.模块名 import 函数名&lt;/code&gt;导入。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;from mypackage.mymodule import myfunction
print(myfunction())
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;使用包中的特定变量：使用&lt;code&gt;from 包名.模块名 import 变量名&lt;/code&gt;导入。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;from mypackage.mymodule import myvariable
print(myvariable)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;使用包中的所有函数：使用&lt;code&gt;from 包名.模块名 import *&lt;/code&gt;导入。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;from mypackage.mymodule import *
print(myfunction())
print(myvariable)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;使用包中的所有变量：使用&lt;code&gt;from 包名.模块名 import *&lt;/code&gt;导入。&lt;/p&gt;
&lt;p&gt;注意：导包会默认执行&lt;code&gt;__init__.py &lt;/code&gt;文件中的代码。&lt;/p&gt;
&lt;h3 id=&#34;all&#34;&gt;&lt;strong&gt;all&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;__all__&lt;/code&gt;是一个列表，用于指定包中可以被导入的模块。&lt;/p&gt;
&lt;p&gt;语法：&lt;code&gt;__all__ = [&amp;quot;模块名1&amp;quot;, &amp;quot;模块名2&amp;quot;, ...]&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;示例：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;# mypackage/__init__.py
__all__ = [&amp;quot;mymodule1&amp;quot;, &amp;quot;mymodule2&amp;quot;]
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;使用包中的特定模块：使用&lt;code&gt;from 包名 import 模块名&lt;/code&gt;导入。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;from mypackage import mymodule1
print(mymodule1.myfunction())
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;闭包-2&#34;&gt;闭包&lt;/h2&gt;
&lt;p&gt;闭包是指在一个函数内部定义的函数，它可以访问外部函数的局部变量。&lt;br&gt;
实现：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;函数嵌套（内部函数定义在外部函数内部）&lt;/li&gt;
&lt;li&gt;内部函数访问外部函数的局部变量&lt;/li&gt;
&lt;li&gt;外部函数返回内部函数&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;语法：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def 外部函数():
    变量 = 值
    def 内部函数():
        print(变量)
    return 内部函数
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;示例：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def outer_function():
    x = 10
    def inner_function():
        print(x)
    return inner_function # 返回内部函数的引用，即地址

my_function = outer_function()
my_function() # 输出10
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;注意：闭包可以访问外部函数的局部变量，但是不能修改外部函数的局部变量。&lt;/p&gt;
&lt;h3 id=&#34;函数引用&#34;&gt;函数引用&lt;/h3&gt;
&lt;p&gt;函数引用是指将函数赋值给一个变量，然后通过变量调用函数。&lt;/p&gt;
&lt;p&gt;语法：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;变量 = 函数名
变量()
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;示例：&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def my_function():
    print(&amp;quot;Hello, World!&amp;quot;)

my_function_ref = my_function
my_function_ref() # 输出Hello, World!
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;闭包变量&#34;&gt;闭包变量&lt;/h3&gt;
&lt;p&gt;闭包变量是指在闭包中使用的变量，闭包变量实际上只有一份，每次开启内函数都是在使用同一份闭包变量。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def outer_function(n):
    print(&amp;quot;outer_function:&amp;quot;, n)
    def inner_function(m):
        print(&amp;quot;inner_function:&amp;quot;,m)
        return n + m
    return inner_function

out = outer_function(10) # outer_function: 10
out(20) # inner_function: 20
print(out(20)) # inner_function: 20 30
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;装饰器&#34;&gt;装饰器&lt;/h2&gt;
&lt;p&gt;作用：在不修改原有函数代码的情况下，给函数增加新的功能。&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;标准装饰器&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;# 闭包三要素
# 1. 函数嵌套
# 2. 内部函数使用外部函数的变量
# 3. 外部函数返回内部函数的函数名

# 装饰器函数
def send():
    print(&amp;quot;发送邮件&amp;quot;)

def outer_function(func):
    def inner_function():
        print(&amp;quot;before&amp;quot;)
        func()
        print(&amp;quot;after&amp;quot;)
    return inner_function
out = outer_function(send)
out()
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;语法糖装饰器&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def outer_function(func):
    def inner_function():
        print(&amp;quot;before&amp;quot;)
        func()
        print(&amp;quot;after&amp;quot;)
    return inner_function

@outer_function
def send():
    print(&amp;quot;发送邮件&amp;quot;)

send()
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;被装饰的函数有参数&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;def outer_function(func):
    def inner_function(*args, **kwargs):
        print(&amp;quot;before&amp;quot;)
        func(*args, **kwargs)
        print(&amp;quot;after&amp;quot;)
    return inner_function

@outer_function
def send(name):
    print(&amp;quot;发送邮件给&amp;quot;, name)

send(&amp;quot;张三&amp;quot;)
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;多个装饰器&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code class=&#34;language-python&#34;&gt;# 第一个装饰器
def outer_function1(func):
    def inner_function1(*args, **kwargs):
        print(&amp;quot;before1&amp;quot;)
        func(*args, **kwargs)
        print(&amp;quot;after1&amp;quot;)
    return inner_function1
# 第二个装饰器
def outer_function2(func):
    def inner_function2(*args, **kwargs):
        print(&amp;quot;before2&amp;quot;)
        func(*args, **kwargs)
        print(&amp;quot;after2&amp;quot;)
    return inner_function2

@outer_function1
@outer_function2
# 被装饰的函数
def send(name):
    print(&amp;quot;发送邮件给&amp;quot;, name)
send(&amp;quot;张三&amp;quot;)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;注意：Python 的装饰器应用顺序是 ​&lt;code&gt;​自底向上​​&lt;/code&gt; 的，即靠近&lt;code&gt;函数定义&lt;/code&gt;的装饰器（&lt;code&gt;@outer_function2&lt;/code&gt;）先被应用，外层装饰器（&lt;code&gt;@outer_function1&lt;/code&gt;）后应用。&lt;br&gt;
以上可以看做： &lt;code&gt;send = outer_function1(outer_function2(send))&lt;/code&gt;&lt;/p&gt;
